// BUILD SVG BRAIN
// ═══════════════════════════════════════════════════════════════════
const svgEl      = document.getElementById('brainSvg');
const cnsLayer   = document.getElementById('cnsLayer');
const vascLayer  = document.getElementById('vascLayer');
const connLayer  = document.getElementById('connLayer');
const lightLayer = document.getElementById('lightLayer');
const ringLayer  = document.getElementById('ringLayer');
const nodeLayer  = document.getElementById('nodeLayer');
const thoughtLayer = document.getElementById('thoughtLayer');
const proteinLayer = document.getElementById('proteinLayer');

function makeSVG(tag) { return document.createElementNS('http://www.w3.org/2000/svg', tag); }

// Connections
CONNS.forEach(([a,b]) => {
  const na=nodeMap[a], nb=nodeMap[b];
  if (!na||!nb) return;
  const l=makeSVG('line');
  l.setAttribute('x1',na.x); l.setAttribute('y1',na.y);
  l.setAttribute('x2',nb.x); l.setAttribute('y2',nb.y);
  l.setAttribute('class','conn-line');
  l.setAttribute('id',`c-${a}-${b}`);
  connLayer.appendChild(l);
});

// Region nodes
REGIONS.forEach(r => {
  const g = makeSVG('g');
  g.setAttribute('class','brain-node');
  g.setAttribute('id',`n-${r.id}`);
  g.setAttribute('transform',`translate(${r.x},${r.y})`);

  const outer=makeSVG('circle');
  outer.setAttribute('r','18'); outer.setAttribute('fill',r.color);
  outer.setAttribute('opacity','0.11'); outer.setAttribute('class','n-outer');
  g.appendChild(outer);

  const core=makeSVG('circle');
  core.setAttribute('r','8'); core.setAttribute('fill',r.color);
  core.setAttribute('opacity','0.87'); core.setAttribute('class','n-core');
  g.appendChild(core);

  const dot=makeSVG('circle');
  dot.setAttribute('r','2.8'); dot.setAttribute('fill','white');
  dot.setAttribute('opacity','0.55');
  g.appendChild(dot);

  const name0 = r.name.split(' ').slice(0,2).join(' ');
  const lbl=makeSVG('text');
  lbl.setAttribute('class','node-label');
  lbl.setAttribute('y','22');
  lbl.textContent=name0;
  g.appendChild(lbl);

  nodeLayer.appendChild(g);
});

// Protein nodes (hidden until protein layer on)
PROTEIN_NODES.forEach(p => {
  const g=makeSVG('g');
  g.setAttribute('id',`p-${p.id}`);
  g.setAttribute('transform',`translate(${p.x},${p.y})`);
  g.setAttribute('opacity','0');
  g.style.cursor='pointer';
  g.style.transition='opacity .3s';

  const c=makeSVG('circle');
  c.setAttribute('r','5'); c.setAttribute('fill',p.color);
  c.setAttribute('opacity','0.7');
  g.appendChild(c);

  const t=makeSVG('text');
  t.setAttribute('class','node-label');
  t.setAttribute('y','15');
  t.style.fontSize='6px';
  t.textContent=p.name.split(' ')[0];
  g.appendChild(t);

  g.addEventListener('click', e => { e.stopPropagation(); openProteinPanel(p); });
  proteinLayer.appendChild(g);
});

