// CNS — SPINAL CORD + NERVE ROOTS + VASCULAR TREE
// ═══════════════════════════════════════════════════════════════════

// Pre-created SVG elements for CNS — built once, mutated every frame
const CNS = (() => {
  // ── spinal cord vertebrae ──
  const SPINE_X = 350, SPINE_Y0 = 458, SPINE_Y1 = 528;
  const SEG_COUNT = 8;
  const SEG_H = (SPINE_Y1 - SPINE_Y0) / SEG_COUNT;
  const spineSegs = []; // {ellipse, glow}
  const spineDot = makeSVG('ellipse'); // traveling pulse dot on spine

  // vertebrae
  for (let i = 0; i < SEG_COUNT; i++) {
    const cy = SPINE_Y0 + i * SEG_H + SEG_H * 0.5;
    const rx = 7 - i * 0.25; // taper slightly
    const ry = SEG_H * 0.38;

    const seg = makeSVG('ellipse');
    seg.setAttribute('cx', SPINE_X); seg.setAttribute('cy', cy);
    seg.setAttribute('rx', rx.toFixed(1)); seg.setAttribute('ry', ry.toFixed(1));
    seg.setAttribute('fill', 'none');
    seg.setAttribute('stroke', '#80deea');
    seg.setAttribute('stroke-width', '1.1');
    seg.setAttribute('stroke-opacity', '0.55');
    seg.setAttribute('class', 'spinal-seg');
    seg.style.animationDelay = (i * 0.18) + 's';

    const glow = makeSVG('ellipse');
    glow.setAttribute('cx', SPINE_X); glow.setAttribute('cy', cy);
    glow.setAttribute('rx', (rx + 2).toFixed(1)); glow.setAttribute('ry', (ry + 2).toFixed(1));
    glow.setAttribute('fill', 'rgba(128,222,234,0.035)');
    glow.setAttribute('stroke', 'none');

    cnsLayer.appendChild(glow);
    cnsLayer.appendChild(seg);
    spineSegs.push({ seg, glow, cy, baseRx: rx });
  }

  // spine traveling dot
  spineDot.setAttribute('cx', SPINE_X); spineDot.setAttribute('cy', SPINE_Y0);
  spineDot.setAttribute('rx', '4'); spineDot.setAttribute('ry', '2.5');
  spineDot.setAttribute('fill', '#80deea');
  spineDot.setAttribute('opacity', '0');
  spineDot.setAttribute('filter', 'url(#spineDotGlow)');
  cnsLayer.appendChild(spineDot);

  // spine dot glow filter — add to SVG defs
  const defs = svgEl.querySelector('defs') || svgEl.insertBefore(makeSVG('defs'), svgEl.firstChild);
  const flt = makeSVG('filter');
  flt.setAttribute('id', 'spineDotGlow');
  flt.setAttribute('x', '-100%'); flt.setAttribute('y', '-100%');
  flt.setAttribute('width', '300%'); flt.setAttribute('height', '300%');
  const feGauss = makeSVG('feGaussianBlur');
  feGauss.setAttribute('stdDeviation', '2.5'); feGauss.setAttribute('result', 'blur');
  const feMerge = makeSVG('feMerge');
  ['blur', 'SourceGraphic'].forEach(inp => {
    const n = makeSVG('feMergeNode'); n.setAttribute('in', inp); feMerge.appendChild(n);
  });
  flt.appendChild(feGauss); flt.appendChild(feMerge);
  defs.appendChild(flt);

  // ── nerve roots ──
  // 12 roots, 6 per side, branching from spine
  const NERVE_ROOTS = [];
  const rootPairs = 6;
  for (let i = 0; i < rootPairs; i++) {
    const t = (i + 0.5) / rootPairs;
    const spineY = SPINE_Y0 + t * (SPINE_Y1 - SPINE_Y0);
    const spread = 18 + i * 5; // fans out more lower down
    const len1 = 28 + i * 3;
    const len2 = 18 + i * 2;

    [-1, 1].forEach(side => {
      const endX = SPINE_X + side * (spread + len1);
      const endY = spineY + 4;
      const cp1X = SPINE_X + side * spread;
      const cp1Y = spineY - 2;

      const path = makeSVG('path');
      const d = `M ${SPINE_X} ${spineY} Q ${cp1X} ${cp1Y} ${endX} ${endY}`;
      path.setAttribute('d', d);
      path.setAttribute('fill', 'none');
      path.setAttribute('stroke', 'rgba(128,222,234,0.22)');
      path.setAttribute('stroke-width', '0.8');
      cnsLayer.appendChild(path);

      // secondary branch tip
      const bX = endX + side * len2 * 0.7;
      const bY = endY - 5;
      const branch = makeSVG('path');
      branch.setAttribute('d', `M ${endX} ${endY} L ${bX} ${bY}`);
      branch.setAttribute('fill', 'none');
      branch.setAttribute('stroke', 'rgba(128,222,234,0.12)');
      branch.setAttribute('stroke-width', '0.5');
      cnsLayer.appendChild(branch);

      // AP traveling dot on nerve root
      const dot = makeSVG('circle');
      dot.setAttribute('r', '1.8');
      dot.setAttribute('fill', '#80deea');
      dot.setAttribute('opacity', '0');
      cnsLayer.appendChild(dot);

      // Store full path geometry for animation
      const totalLen = Math.hypot(endX - SPINE_X, endY - spineY);
      NERVE_ROOTS.push({
        path, dot,
        startX: SPINE_X, startY: spineY,
        cp1X, cp1Y,
        endX, endY,
        totalLen,
        prog: Math.random(), // randomize start offset
        speed: 0.0004 + Math.random() * 0.0003,
        active: false,
        nextFire: Math.random() * 8000,
      });
    });
  }

  // ── Circle of Willis ──
  const COW_CX = 350, COW_CY = 418, COW_RX = 55, COW_RY = 22;
  const cow = makeSVG('ellipse');
  cow.setAttribute('cx', COW_CX); cow.setAttribute('cy', COW_CY);
  cow.setAttribute('rx', COW_RX); cow.setAttribute('ry', COW_RY);
  cow.setAttribute('fill', 'none');
  cow.setAttribute('stroke', 'rgba(239,83,80,0.18)');
  cow.setAttribute('stroke-width', '1.5');
  vascLayer.appendChild(cow);

  // ── 6 main arteries from Circle of Willis upward into brain ──
  const ARTERY_TARGETS = [
    { tx: 248, ty: 128 }, // PFC
    { tx: 208, ty: 183 }, // Motor
    { tx: 312, ty: 296 }, // Hippocampus
    { tx: 392, ty: 458 }, // Brainstem (downward — this connects to spine)
    { tx: 462, ty: 403 }, // Cerebellum
    { tx: 475, ty: 153 }, // Visual
  ];

  const arteries = [];
  const veins = [];
  ARTERY_TARGETS.forEach((tgt, idx) => {
    // Artery (red)
    const art = makeSVG('path');
    const cx = COW_CX + (tgt.tx - COW_CX) * 0.3;
    const cy = COW_CY + (tgt.ty - COW_CY) * 0.3;
    art.setAttribute('d', `M ${COW_CX} ${COW_CY} Q ${cx} ${cy} ${tgt.tx} ${tgt.ty}`);
    art.setAttribute('fill', 'none');
    art.setAttribute('stroke', 'rgba(239,83,80,0.16)');
    art.setAttribute('stroke-width', '1.5');
    vascLayer.appendChild(art);

    // Vein (blue, offset slightly)
    const vein = makeSVG('path');
    const vox = 4, voy = 3;
    vein.setAttribute('d', `M ${COW_CX + vox} ${COW_CY + voy} Q ${cx + vox} ${cy + voy} ${tgt.tx + vox} ${tgt.ty + voy}`);
    vein.setAttribute('fill', 'none');
    vein.setAttribute('stroke', 'rgba(100,120,200,0.10)');
    vein.setAttribute('stroke-width', '0.8');
    vascLayer.appendChild(vein);

    // Blood flow dots (2 per artery, flowing toward brain)
    const dots = [0, 1].map(j => {
      const d = makeSVG('ellipse');
      d.setAttribute('rx', '2.5'); d.setAttribute('ry', '1.5');
      d.setAttribute('fill', 'rgba(239,83,80,0.6)');
      d.setAttribute('opacity', '0');
      vascLayer.appendChild(d);
      return { el: d, t: j * 0.5 + Math.random() * 0.3, speed: 0.0006 + Math.random() * 0.0004 };
    });

    arteries.push({
      art, vein, dots,
      sx: COW_CX, sy: COW_CY,
      cpx: cx, cpy: cy,
      ex: tgt.tx, ey: tgt.ty,
      idx,
      flashOpacity: 0,
    });
  });

  // ── Heartbeat oscillation state ──
  const heartbeat = { phase: 0, bpm: 72 };
  // ── Spine pulse state ──
  const spinePulse = { active: false, prog: 0, speed: 0.0035 };
  // ── Last frame ts for nerve fire scheduling ──
  let _lastTs = 0;

  // ── Quad bezier point helper ──
  function quadBezier(t, sx, sy, cpx, cpy, ex, ey) {
    const mt = 1 - t;
    return {
      x: mt * mt * sx + 2 * mt * t * cpx + t * t * ex,
      y: mt * mt * sy + 2 * mt * t * cpy + t * t * ey,
    };
  }

  // ── Main drawCNS(t) called from loop() ──
  function draw(ts) {
    if (!layerState.cns) {
      cnsLayer.setAttribute('opacity', '0');
      vascLayer.setAttribute('opacity', '0');
      return;
    }
    cnsLayer.setAttribute('opacity', '1');
    vascLayer.setAttribute('opacity', '1');

    const dt = _lastTs === 0 ? 16 : Math.min(ts - _lastTs, 100); // cap at 100ms to avoid first-frame jump
    _lastTs = ts;
    const t = ts * 0.001;

    // ── Heartbeat: 72bpm = 833ms period ──
    heartbeat.phase += dt * (Math.PI * 2 / 833);
    const hbPulse = 0.5 + 0.5 * Math.sin(heartbeat.phase);
    const hbStrong = Math.max(0, Math.sin(heartbeat.phase) * 2 - 0.9); // sharp spike near peak

    // Circle of Willis heartbeat flicker
    const cowOpacity = 0.12 + hbStrong * 0.22;
    cow.setAttribute('stroke', `rgba(239,83,80,${(0.14 + hbStrong * 0.28).toFixed(3)})`);

    // Artery blood flow dots
    arteries.forEach(artery => {
      if (!layerState.bloodflow && artery.flashOpacity <= 0) {
        // Only show if bloodflow layer is on OR if we're flash-activating
        artery.dots.forEach(d => d.el.setAttribute('opacity', '0'));
        return;
      }
      artery.dots.forEach(d => {
        d.t = (d.t + d.speed * Math.max(1, dt)) % 1.0;
        const pt = quadBezier(d.t, artery.sx, artery.sy, artery.cpx, artery.cpy, artery.ex, artery.ey);
        // Compute rotation angle along path
        const pt2 = quadBezier(Math.min(d.t + 0.01, 1), artery.sx, artery.sy, artery.cpx, artery.cpy, artery.ex, artery.ey);
        const angle = Math.atan2(pt2.y - pt.y, pt2.x - pt.x);
        d.el.setAttribute('cx', pt.x.toFixed(1));
        d.el.setAttribute('cy', pt.y.toFixed(1));
        d.el.setAttribute('transform', `rotate(${(angle * 180 / Math.PI).toFixed(1)},${pt.x.toFixed(1)},${pt.y.toFixed(1)})`);
        const baseOp = layerState.bloodflow ? 0.5 : 0;
        const flashBoost = artery.flashOpacity * 0.7;
        d.el.setAttribute('opacity', Math.min(1, baseOp + flashBoost + hbStrong * 0.3).toFixed(3));
      });
      if (artery.flashOpacity > 0) artery.flashOpacity = Math.max(0, artery.flashOpacity - dt * 0.002);
    });

    // ── Spinal cord breathing rhythm (12 breaths/min = 5000ms) ──
    const breathPhase = t * (Math.PI * 2 / 5);
    const breathPulse = 0.5 + 0.5 * Math.sin(breathPhase);
    spineSegs.forEach((s, i) => {
      const phase = breathPhase + i * 0.22;
      const op = 0.38 + 0.35 * Math.sin(phase);
      s.seg.setAttribute('stroke-opacity', op.toFixed(3));
      const rx = (s.baseRx * (0.92 + 0.08 * Math.sin(phase))).toFixed(2);
      s.seg.setAttribute('rx', rx);
      s.glow.setAttribute('fill', `rgba(128,222,234,${(0.02 + 0.03 * Math.sin(phase)).toFixed(3)})`);
    });

    // ── Spine pulse dot ──
    if (spinePulse.active) {
      spinePulse.prog += spinePulse.speed * Math.max(1, dt);
      if (spinePulse.prog >= 1) {
        spinePulse.active = false;
        spineDot.setAttribute('opacity', '0');
      } else {
        const py = SPINE_Y0 + spinePulse.prog * (SPINE_Y1 - SPINE_Y0);
        spineDot.setAttribute('cy', py.toFixed(1));
        spineDot.setAttribute('opacity', (0.9 - spinePulse.prog * 0.7).toFixed(3));
      }
    }

    // ── Nerve root AP pulses ──
    NERVE_ROOTS.forEach(root => {
      if (root.active) {
        root.prog += root.speed * Math.max(1, dt);
        if (root.prog >= 1) {
          root.active = false;
          root.dot.setAttribute('opacity', '0');
          root.nextFire = ts + 4000 + Math.random() * 8000;
        } else {
          const pt = quadBezier(root.prog, root.startX, root.startY, root.cp1X, root.cp1Y, root.endX, root.endY);
          root.dot.setAttribute('cx', pt.x.toFixed(1));
          root.dot.setAttribute('cy', pt.y.toFixed(1));
          root.dot.setAttribute('opacity', (0.75 - root.prog * 0.55).toFixed(3));
        }
      } else if (ts >= root.nextFire) {
        root.active = true;
        root.prog = 0;
      }
    });
  }

  // ── Spine pulse trigger (called from activateNode) ──
  function triggerSpinePulse() {
    spinePulse.active = true;
    spinePulse.prog = 0;
    spineDot.setAttribute('cx', SPINE_X.toString());
    spineDot.setAttribute('cy', SPINE_Y0.toString());
    spineDot.setAttribute('opacity', '0.9');
  }

  // ── Artery flash trigger (called from activateNode) ──
  function flashArteries(major) {
    if (major) {
      arteries.forEach(a => { a.flashOpacity = 1.0; });
      // flash CoW stroke momentarily
      cow.setAttribute('stroke', 'rgba(239,83,80,0.60)');
    } else {
      // flash nearest 2 arteries
      const idx1 = Math.floor(Math.random() * arteries.length);
      const idx2 = (idx1 + 1) % arteries.length;
      arteries[idx1].flashOpacity = 0.8;
      arteries[idx2].flashOpacity = 0.5;
    }
  }

  return { draw, triggerSpinePulse, flashArteries };
})();

