// ═══ SKELETON ANIMATION SYSTEM ═══
const SKELETON = (() => {
  const skelLayer = document.getElementById('skeletonLayer');

  // Marrow signal paths — [startX,startY, endX,endY, color]
  const marrowPaths = [
    { dot: document.getElementById('marrow1'), pts:[350,345,350,900], prog:0, speed:0.0004, color:'rgba(160,185,255,0.8)' },
    { dot: document.getElementById('marrow2'), pts:[238,500,210,890], prog:0.3, speed:0.00035, color:'rgba(160,185,255,0.7)' },
    { dot: document.getElementById('marrow3'), pts:[295,908,285,1400], prog:0.1, speed:0.0003, color:'rgba(160,185,255,0.75)' },
    { dot: document.getElementById('marrow4'), pts:[405,908,415,1400], prog:0.5, speed:0.00032, color:'rgba(160,185,255,0.75)' },
  ];

  // Bone glow pulse — flash all bones briefly
  let glowIntensity = 0;
  let glowDecay = 0;

  function activateSkeleton() {
    glowIntensity = 1;
    glowDecay = 0.008;
    // Speed up marrow
    marrowPaths.forEach(m => m.speed = 0.0018);
    setTimeout(()=>{ marrowPaths.forEach(m => m.speed = m.speed > 0.0005 ? (m === marrowPaths[0] ? 0.0004 : m === marrowPaths[1] ? 0.00035 : 0.0003) : m.speed); }, 2000);
  }

  function draw(ts) {
    // Animate marrow dots along bone paths
    marrowPaths.forEach(m => {
      if (!m.dot) return;
      m.prog += m.speed;
      if (m.prog > 1) m.prog = 0;
      const t = m.prog;
      const x = m.pts[0] + (m.pts[2] - m.pts[0]) * t;
      const y = m.pts[1] + (m.pts[3] - m.pts[1]) * t;
      m.dot.setAttribute('cx', x.toFixed(1));
      m.dot.setAttribute('cy', y.toFixed(1));
      // Fade in/out at ends
      const fade = t < 0.05 ? t/0.05 : t > 0.95 ? (1-t)/0.05 : 1;
      m.dot.setAttribute('opacity', (fade * 0.75).toFixed(2));
    });

    // Glow pulse on skeleton layer
    if (glowDecay > 0) {
      glowIntensity = Math.max(0, glowIntensity - glowDecay);
      if (glowIntensity <= 0) { glowDecay = 0; skelLayer.setAttribute('opacity','0.55'); }
      else { skelLayer.setAttribute('opacity', (0.55 + glowIntensity * 0.45).toFixed(2)); }
    }

    // Ambient breath-pulse on skeleton
    const breathe = 0.5 + 0.05 * Math.sin(ts * 0.00035);
    if (glowDecay === 0) skelLayer.setAttribute('opacity', breathe.toFixed(3));
  }

  return { draw, activateSkeleton };
})();

