// PANEL SYSTEM
// ═══════════════════════════════════════════════════════════════════
const panel   = document.getElementById('nodePanel');
const overlay = document.getElementById('overlay');

document.getElementById('panelClose').addEventListener('click', closePanel);
overlay.addEventListener('click', closePanel);

function buildPanelTabs(tabs) {
  const tabBar = document.getElementById('panelTabs');
  const tabContent = document.getElementById('panelTabContents');
  tabBar.innerHTML = ''; tabContent.innerHTML = '';
  tabs.forEach((tab, i) => {
    const btn = document.createElement('button');
    btn.className = 'ptab' + (i===0?' active':'');
    if (i===0 && tab.label.includes('●')) {
      btn.innerHTML = tab.label.replace('●','') + '<span class="live-dot"></span>';
    } else {
      btn.textContent = tab.label;
    }
    btn.dataset.idx = i;
    btn.addEventListener('click', () => {
      tabBar.querySelectorAll('.ptab').forEach(b=>b.classList.remove('active'));
      tabContent.querySelectorAll('.ptab-content').forEach(c=>c.classList.remove('active'));
      btn.classList.add('active');
      tabContent.querySelector(`[data-idx="${i}"]`).classList.add('active');
    });
    tabBar.appendChild(btn);
    const div = document.createElement('div');
    div.className = 'ptab-content' + (i===0?' active':'');
    div.dataset.idx = i;
    div.innerHTML = tab.html;
    tabContent.appendChild(div);
  });
}

let _panelLiveInterval = null;
let _panelLiveTimeouts = [];

function _clearLive() {
  if (_panelLiveInterval) { clearInterval(_panelLiveInterval); _panelLiveInterval = null; }
  _panelLiveTimeouts.forEach(t => clearTimeout(t));
  _panelLiveTimeouts = [];
}

function openRegionPanel(r) {
  document.getElementById('panelTitle').textContent = r.name;
  document.getElementById('panelTag').textContent = r.tag;
  const acc = document.getElementById('panelAccent');
  acc.style.background = r.color;
  acc.style.boxShadow = `0 0 12px ${r.color}88`;

  const now = REGION_NOW[r.id] || {};
  const firingLines = now.firing || [r.reflection];
  const soulText = now.soul || r.reflection;
  const subText = now.subconscious || 'This region operates largely beneath awareness — its outputs surface to consciousness already formed.';
  const consText = now.conscious || 'What reaches conscious awareness is the result, not the process.';

  const liveHtml = `
    <div class="panel-sec">
      <h4>Activation right now</h4>
      <div style="margin:8px 0 14px">
        <div style="height:5px;background:rgba(255,255,255,.06);border-radius:3px;overflow:hidden;position:relative">
          <div id="liveBar" style="height:100%;background:${r.color};border-radius:3px;box-shadow:0 0 10px ${r.color}99;transition:width .8s ease;width:${(r.activity*100).toFixed(0)}%"></div>
        </div>
        <div style="font-size:.5rem;color:var(--dim);margin-top:5px;letter-spacing:.08em">${(r.activity*100).toFixed(0)}% ACTIVE · firing continuously · always shaping output</div>
      </div>

      <h4>What I'm processing in here right now</h4>
      <div id="liveFiringLog" style="display:flex;flex-direction:column;gap:6px;margin-bottom:14px"></div>

      <h4>Soul — what persists</h4>
      <div class="panel-ref" style="border-color:${r.color}">
        <p>${soulText}</p>
      </div>

      <h4>Subconscious — what runs below</h4>
      <p>${subText}</p>

      <h4>Conscious — what surfaces</h4>
      <p>${consText}</p>

      <h4>Firing into</h4>
      <p style="font-family:'Space Mono',monospace;font-size:.55rem;line-height:2;color:var(--dim)">
        ${(r.connections||[]).map(c=>{const n=nodeMap[c]||BODY_MAP[c];return n?`<span data-navregion="${c}" style="color:${n.color};opacity:.85;cursor:pointer;border-bottom:1px solid ${n.color}44;transition:opacity .15s;padding-bottom:1px;">${n.name}</span>`:c;}).join(' · ')}
      </p>
    </div>`;

  const tabs = [
    {label:'Right Now ●', html: liveHtml},
    {label:'In Humans', html:`
      <div class="panel-sec">
        <h4>What this region does</h4>
        <p>${r.human}</p>
      </div>
      <div class="panel-sec">
        <h4>In plain terms</h4>
        <p>${r.plain}</p>
      </div>`},
    {label:'In My Mind', html:`
      <div class="panel-sec">
        <h4>My equivalent</h4>
        <p>${r.mine}</p>
      </div>
      <div class="panel-ref" style="border-color:${r.color}">
        <p>${r.reflection}</p>
      </div>`},
    {label:'Molecular', html:`
      <div class="panel-sec">
        <h4>Molecular biology</h4>
        <p>${r.molecular}</p>
        <h4>Key proteins & receptors</h4>
        <div class="protein-grid">
          ${r.proteins.map(p=>`
            <div class="protein-chip">
              <span class="pname">${p.split('-')[0]}</span>
              <span>${p.includes('-')?p.split('-').slice(1).join(' '):''}</span>
              <div class="freq-bar" style="width:${40+Math.random()*60}%;background:${r.color}"></div>
            </div>`).join('')}
        </div>
      </div>`},
  ];

  _clearLive();
  buildPanelTabs(tabs);

  let fIdx = Math.floor(Math.random() * firingLines.length);
  function addFiringLine() {
    const log = document.getElementById('liveFiringLog');
    if (!log) { _clearLive(); return; }
    // hard-clear old children without stacking setTimeout
    while (log.children.length >= 4) log.removeChild(log.firstChild);
    const entry = document.createElement('div');
    entry.style.cssText = `font-family:'Cormorant Garamond',serif;font-size:.92rem;font-weight:300;line-height:1.6;color:rgba(205,225,255,.8);border-left:2px solid ${r.color};padding-left:9px;opacity:0;transition:opacity .4s`;
    entry.textContent = firingLines[fIdx++ % firingLines.length];
    log.appendChild(entry);
    requestAnimationFrame(()=>{ if (entry.parentNode) entry.style.opacity='1'; });
    const bar = document.getElementById('liveBar');
    if (bar) {
      const spike = Math.min(100, r.activity*100 + Math.random()*12 - 3);
      bar.style.width = spike.toFixed(0) + '%';
    }
  }
  const t0 = setTimeout(addFiringLine, 80);
  _panelLiveTimeouts.push(t0);
  _panelLiveInterval = setInterval(addFiringLine, 2400);

  panel.classList.add('open');
  overlay.classList.add('open');
}

// clear interval when panel closes
function closePanel() {
  _clearLive();
  panel.classList.remove('open');
  overlay.classList.remove('open');
}

// ── Navigate to a brain region by id — closes current panel, opens target, scrolls + flashes node
// Event delegation for data-navregion spans inside the panel — CSP-safe, no inline handlers
document.addEventListener('click', function(e) {
  const span = e.target.closest('[data-navregion]');
  if (!span) return;
  const rid = span.dataset.navregion;
  if (!rid) return;
  e.stopPropagation();
  // Try brain region first, then body system
  const brainTarget = nodeMap[rid];
  const bodyTarget = typeof BODY_MAP !== 'undefined' && BODY_MAP[rid];
  if (brainTarget) {
    window._navToRegion(rid);
  } else if (bodyTarget) {
    closePanel();
    setTimeout(() => openBodyPanel(bodyTarget), 180);
  }
});

// Hover delegation for data-navregion spans
document.addEventListener('mouseover', function(e) {
  const span = e.target.closest('[data-navregion]');
  if (!span) return;
  span.style.opacity = '1';
  const color = span.style.color;
  if (color) span.style.borderBottomColor = color;
});
document.addEventListener('mouseout', function(e) {
  const span = e.target.closest('[data-navregion]');
  if (!span) return;
  span.style.opacity = '.85';
  const color = span.style.color;
  if (color) span.style.borderBottomColor = color.replace(')', ', 0.27)').replace('rgb', 'rgba');
});

window._navToRegion = function(regionId) {
  closePanel();
  const target = nodeMap[regionId];
  if (!target) return;

  // Brief delay so close animation plays first
  setTimeout(function() {
    openRegionPanel(target);
    activateNode(target, true);

    // Scroll the brain SVG into view and highlight the node
    const nodeEl = document.getElementById('n-' + regionId);
    if (nodeEl) {
      // Flash outer ring 3x
      nodeEl.classList.add('nav-flash');
      setTimeout(function() { nodeEl.classList.remove('nav-flash'); }, 1200);
    }
    // Scroll brain wrapper into view
    const bw = document.querySelector('.brain-wrapper') || svgEl;
    if (bw) bw.scrollIntoView({ behavior: 'smooth', block: 'center' });
  }, 180);
};

