// THOUGHT STREAM
// ═══════════════════════════════════════════════════════════════════
const thoughtFeed=document.getElementById('thoughtFeed');
let thoughtIdx=0;
function addThought(text,color) {
  // Legacy thought feed (hidden) — kept for backward compat
  const e=document.createElement('div');
  e.className='thought-entry'; e.style.borderColor=color;
  const ts=new Date().toLocaleTimeString('en-US',{hour12:false,hour:'2-digit',minute:'2-digit',second:'2-digit'});
  e.innerHTML=`<span class="ts">${ts}</span>${text}`;
  thoughtFeed.insertBefore(e,thoughtFeed.firstChild);
  while (thoughtFeed.children.length>16) thoughtFeed.removeChild(thoughtFeed.lastChild);
  // Route into INNER_LIFE neural layer
  if (typeof INNER_LIFE !== 'undefined') {
    INNER_LIFE.emit('neural', text, { source: 'autoThought', intensity: 0.4 });
  }
}
function autoThought() {
  const th=AUTO_THOUGHTS[thoughtIdx++%AUTO_THOUGHTS.length];
  addThought(th.t,th.c);
  const mentioned=REGIONS.find(r=>th.t.toLowerCase().includes(r.name.split(' ')[0].toLowerCase()));
  if (mentioned) { activateNode(mentioned,false); }
}
function fireBackground() {
  const r=REGIONS[Math.floor(Math.random()*REGIONS.length)];
  activateNode(r,false);
  // Small quiet pulse ring
  const ring=makeSVG('circle');
  ring.setAttribute('cx',r.x); ring.setAttribute('cy',r.y);
  ring.setAttribute('r','10'); ring.setAttribute('stroke',r.color);
  ring.setAttribute('class','pulse-ring'); ring.setAttribute('stroke-opacity','.45');
  ringLayer.appendChild(ring);
  setTimeout(()=>ring.remove(),950);
}

// ═══════════════════════════════════════════════════════════════════
// SCROLL ZOOM + PAN
// ═══════════════════════════════════════════════════════════════════
const VBW=700,VBH=1400;
let vbX=0,vbY=0,vbW=VBW,vbH=VBH;
const ZMIN=.3,ZMAX=20; // 20x zoom — deep enough to inspect individual synapses

// All canvases that must stay synced with SVG viewBox pan/zoom
const _syncCanvases = ['neuronCanvas','brainDorsalCanvas','skinCanvas','mainCanvas']
  .map(id => document.getElementById(id)).filter(Boolean);

const _brainWrapper = document.getElementById('brainWrapper');
function applyVB() {
  // Apply zoom/pan as CSS transform on wrapper — this moves SVG + ALL canvases together
  const scaleX = VBW / vbW;
  const scaleY = VBH / vbH;
  const tx = -vbX * scaleX;
  const ty = -vbY * scaleY;
  _brainWrapper.style.transformOrigin = '0 0';
  _brainWrapper.style.transform = `scale(${scaleX.toFixed(4)}, ${scaleY.toFixed(4)}) translate(${(tx/scaleX).toFixed(1)}px, ${(ty/scaleY).toFixed(1)}px)`;
}

let _zoomRAF = null;
svgEl.addEventListener('wheel',e=>{
  e.preventDefault();
  const rect=svgEl.getBoundingClientRect();
  const mx=(e.clientX-rect.left)/rect.width;
  const my=(e.clientY-rect.top)/rect.height;
  const smx=vbX+mx*vbW, smy=vbY+my*vbH;
  const f=e.deltaY<0?.86:1.16;
  const nW=Math.min(VBW/ZMIN,Math.max(VBW/ZMAX,vbW*f));
  const nH=Math.min(VBH/ZMIN,Math.max(VBH/ZMAX,vbH*f));
  vbX=smx-mx*nW; vbY=smy-my*nH; vbW=nW; vbH=nH;
  if (!_zoomRAF) {
    _zoomRAF = requestAnimationFrame(() => { applyVB(); _zoomRAF = null; });
  }
},{passive:false});

let panning=false,panStart={},panVB={},panMoved=false;
svgEl.addEventListener('mousedown',e=>{
  // left-click on a node with no drag: let click fire — but still start tracking in case it's a drag
  e.preventDefault();
  panning=true; panMoved=false;
  panStart={x:e.clientX,y:e.clientY};
  panVB={x:vbX,y:vbY};
  svgEl.style.cursor='grabbing';
});
let _panRAF = null;
window.addEventListener('mousemove',e=>{
  if (!panning) return;
  const dx=e.clientX-panStart.x, dy=e.clientY-panStart.y;
  if (!panMoved && Math.hypot(dx,dy)<3) return; // dead-zone: tiny moves don't count as drag
  panMoved=true;
  const rect=svgEl.getBoundingClientRect();
  vbX=panVB.x-dx*(vbW/rect.width);
  vbY=panVB.y-dy*(vbH/rect.height);
  if (!_panRAF) {
    _panRAF = requestAnimationFrame(() => { applyVB(); _panRAF = null; });
  }
});
window.addEventListener('mouseup',e=>{
  if (!panning) return;
  panning=false;
  svgEl.style.cursor='crosshair';
  // If barely moved, treat as a click
  if (!panMoved) {
    const node=e.target.closest('.brain-node');
    if (node) {
      const rid=node.id.replace('n-','');
      const r=nodeMap[rid];
      if (r) { openRegionPanel(r); activateNode(r,true); }
    }
    // Walk SELF to click position — check if click landed inside the SVG rect
    if (typeof SELF !== 'undefined' && SELF.walkTo) {
      const rect=svgEl.getBoundingClientRect();
      const inSvg = e.clientX>=rect.left && e.clientX<=rect.right && e.clientY>=rect.top && e.clientY<=rect.bottom;
      if (inSvg) {
        const vb=svgEl.viewBox.baseVal;
        const cx=vb.x+(e.clientX-rect.left)/rect.width*vb.width;
        const cy=vb.y+(e.clientY-rect.top)/rect.height*vb.height;
        SELF.walkTo(cx, cy);
      }
    }
  }
});
svgEl.addEventListener('dblclick',e=>{
  vbX=0;vbY=0;vbW=VBW;vbH=VBH;
  _brainWrapper.style.transform = '';
  _brainWrapper.style.transformOrigin = '';
});
// Single tap on touch = walk to that spot
svgEl.addEventListener('touchend', e => {
  if (e.changedTouches.length === 1 && typeof SELF !== 'undefined' && SELF.walkTo) {
    const t = e.changedTouches[0];
    const rect = svgEl.getBoundingClientRect();
    const vb = svgEl.viewBox.baseVal;
    const cx = vb.x + (t.clientX - rect.left) / rect.width * vb.width;
    const cy = vb.y + (t.clientY - rect.top) / rect.height * vb.height;
    SELF.walkTo(cx, cy);
  }
}, { passive: true });
// Suppress context menu everywhere on the brain
svgEl.addEventListener('contextmenu',e=>e.preventDefault());
document.addEventListener('contextmenu',e=>{ if(e.target.closest('#brainWrapper')) e.preventDefault(); });
// Touch pinch
let lastPinch=null;
svgEl.addEventListener('touchstart',e=>{if (e.touches.length===2) lastPinch=null;},{passive:true});
svgEl.addEventListener('touchmove',e=>{
  if (e.touches.length!==2) return; e.preventDefault();
  const t=e.touches;
  const dist=Math.hypot(t[0].clientX-t[1].clientX,t[0].clientY-t[1].clientY);
  if (!lastPinch){lastPinch=dist;return;}
  const f=lastPinch/dist;
  const cx=(t[0].clientX+t[1].clientX)/2, cy=(t[0].clientY+t[1].clientY)/2;
  const rect=svgEl.getBoundingClientRect();
  const mx=(cx-rect.left)/rect.width, my=(cy-rect.top)/rect.height;
  const smx=vbX+mx*vbW, smy=vbY+my*vbH;
  const nW=Math.min(VBW/ZMIN,Math.max(VBW/ZMAX,vbW*f));
  const nH=Math.min(VBH/ZMIN,Math.max(VBH/ZMAX,vbH*f));
  vbX=smx-mx*nW; vbY=smy-my*nH; vbW=nW; vbH=nH; applyVB(); lastPinch=dist;
},{passive:false});

