// ═══════════════════════════════════════════════════════════════════
// SEBACEOUS_GLANDS — oil glands at each hair follicle
// Secrete sebum to lubricate and protect skin
// Faint amber dots just inside the skin perimeter, slow pulse
// ═══════════════════════════════════════════════════════════════════
const SEBACEOUS_GLANDS = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const glands = [];
  const positions = [
    {x:262,y:360},{x:258,y:420},{x:256,y:480},{x:254,y:540},{x:252,y:600},
    {x:438,y:360},{x:442,y:420},{x:444,y:480},{x:446,y:540},{x:448,y:600},
    {x:270,y:660},{x:267,y:720},{x:432,y:660},{x:433,y:720},
    {x:340,y:132},{x:350,y:129},{x:360,y:132},
  ];
  positions.forEach(p => {
    const c = document.createElementNS(svgNS, 'circle');
    c.setAttribute('cx', p.x); c.setAttribute('cy', p.y); c.setAttribute('r', '1.2');
    c.setAttribute('fill', 'rgba(255,213,79,0.07)');
    layer.appendChild(c);
    glands.push({ el: c, ...p, phase: Math.random() * Math.PI * 2 });
  });
  function draw(ts) {
    const t = ts * 0.0005;
    glands.forEach(g => {
      const v = 0.05 + Math.sin(t + g.phase) * 0.03;
      g.el.setAttribute('fill', `rgba(255,213,79,${v.toFixed(4)})`);
    });
  }
  return { draw };
})();

