// FINGERTIP_RECEPTORS — highest touch density in the body
// Meissner, Merkel, Ruffini, Pacinian corpuscles
// Visible as a cluster of receptor dots at each fingertip
// Activate when any chat or voice input received
// ═══════════════════════════════════════════════════════════════════
const FINGERTIP_RECEPTORS = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Left hand fingertips (~y=760-780 on left arm)
  const tips = [
    {x:248,y:748},{x:244,y:756},{x:242,y:765},{x:246,y:773},{x:252,y:778},
    {x:462,y:748},{x:466,y:756},{x:468,y:765},{x:464,y:773},{x:458,y:778},
  ];
  const receptors = [];
  tips.forEach(t => {
    for (let i = 0; i < 4; i++) {
      const c = document.createElementNS(svgNS, 'circle');
      c.setAttribute('cx', (t.x + (Math.random()-0.5)*4).toFixed(1));
      c.setAttribute('cy', (t.y + (Math.random()-0.5)*3).toFixed(1));
      c.setAttribute('r', '0.7');
      c.setAttribute('fill', 'rgba(255,171,145,0.06)');
      layer.appendChild(c);
      receptors.push({ el: c, base: 0.06, level: 0, phase: Math.random()*Math.PI*2 });
    }
  });
  function activate() {
    receptors.forEach(r => { r.level = Math.min(1, r.level + 0.6 + Math.random()*0.3); });
  }
  function draw(ts) {
    const t = ts * 0.001;
    receptors.forEach(r => {
      r.level = Math.max(0, r.level - 0.015);
      const v = r.base + r.level * 0.35 + Math.sin(t * 1.5 + r.phase) * 0.02;
      r.el.setAttribute('fill', `rgba(255,171,145,${v.toFixed(4)})`);
    });
  }
  return { draw, activate };
})();

// ═══════════════════════════════════════════════════════════════════
// TONGUE_MAP — gustatory cortex + tongue receptor zones
// Sweet/salty/sour/bitter/umami mapped to regions
// Visible as colored zones on a tiny tongue shape
// ═══════════════════════════════════════════════════════════════════
const TONGUE_MAP = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const tx = 350, ty = 475; // throat region

  // Tongue outline
  const tongue = document.createElementNS(svgNS, 'ellipse');
  tongue.setAttribute('cx', tx); tongue.setAttribute('cy', ty + 4);
  tongue.setAttribute('rx', '8'); tongue.setAttribute('ry', '5');
  tongue.setAttribute('fill', 'rgba(255,138,128,0.08)');
  tongue.setAttribute('stroke', 'rgba(255,138,128,0.15)'); tongue.setAttribute('stroke-width', '0.6');
  layer.appendChild(tongue);

  // Taste zones
  const zones = [
    {x:tx-4,y:ty+2,col:'rgba(255,213,79,',label:'sweet'},  // sweet: tip-sides
    {x:tx+4,y:ty+2,col:'rgba(255,213,79,',label:'sweet'},
    {x:tx,y:ty+6,col:'rgba(239,83,80,',label:'bitter'},     // bitter: back
    {x:tx-3,y:ty+5,col:'rgba(255,183,77,',label:'salty'},   // salty: sides
    {x:tx+3,y:ty+5,col:'rgba(165,214,167,',label:'umami'},  // umami
    {x:tx,y:ty+2,col:'rgba(100,181,246,',label:'sour'},     // sour: center
  ];
  const zoneDots = zones.map(z => {
    const c = document.createElementNS(svgNS, 'circle');
    c.setAttribute('cx', z.x); c.setAttribute('cy', z.y); c.setAttribute('r', '1.5');
    c.setAttribute('fill', z.col + '0.12)');
    layer.appendChild(c);
    return { el: c, ...z, phase: Math.random()*Math.PI*2 };
  });
  function draw(ts) {
    const t = ts * 0.0006;
    zoneDots.forEach(z => {
      const v = 0.1 + Math.sin(t + z.phase) * 0.05;
      z.el.setAttribute('fill', z.col + v.toFixed(4) + ')');
    });
  }
  return { draw };
})();

// ═══════════════════════════════════════════════════════════════════
// PAIN_GATE — spinal gate control theory (Melzack & Wall, 1965)
// Large-fiber touch signals can "close the gate" on pain signals
// Visible as gate mechanism at the dorsal horn (~y=500 in spine)
// ═══════════════════════════════════════════════════════════════════
const PAIN_GATE = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const gx = 350, gy = 500;
  // Gate indicator
  const gateBar = document.createElementNS(svgNS, 'line');
  gateBar.setAttribute('x1', gx - 6); gateBar.setAttribute('y1', gy);
  gateBar.setAttribute('x2', gx + 6); gateBar.setAttribute('y2', gy);
  gateBar.setAttribute('stroke', 'rgba(255,171,145,0.2)'); gateBar.setAttribute('stroke-width', '2');
  gateBar.setAttribute('stroke-linecap', 'round');
  layer.appendChild(gateBar);
  let gateOpen = 0.5; // 0=closed, 1=open
  function close(intensity) { gateOpen = Math.max(0, gateOpen - intensity); }
  function open2(intensity) { gateOpen = Math.min(1, gateOpen + intensity); }
  function draw(ts) {
    gateOpen += (0.5 - gateOpen) * 0.002;
    const col = gateOpen > 0.5 ? '239,83,80' : '165,214,167';
    const op = 0.1 + gateOpen * 0.2;
    gateBar.setAttribute('stroke', `rgba(${col},${op.toFixed(3)})`);
    const width = 4 + gateOpen * 4;
    gateBar.setAttribute('x1', (gx - width).toFixed(1));
    gateBar.setAttribute('x2', (gx + width).toFixed(1));
  }
  return { draw, close, open: open2 };
})();

// ═══════════════════════════════════════════════════════════════════
// PHANTOM_LIMB — the map persists after the body part is gone
// The most haunting fact in neuroscience
// A ghost outline of missing fingers, shown faintly at hand position
// Slowly fades in and out — the brain never fully lets go
// ═══════════════════════════════════════════════════════════════════
const PHANTOM_LIMB = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Ghost fingers — left hand phantom
  const phantoms = [];
  const fingerTips = [
    {x:240,y:742},{x:236,y:752},{x:234,y:762},{x:238,y:771},{x:246,y:776},
  ];
  fingerTips.forEach((ft, i) => {
    const line = document.createElementNS(svgNS, 'line');
    line.setAttribute('x1', (ft.x + 4).toFixed(1)); line.setAttribute('y1', (ft.y + 5).toFixed(1));
    line.setAttribute('x2', ft.x.toFixed(1)); line.setAttribute('y2', ft.y.toFixed(1));
    line.setAttribute('stroke', 'rgba(200,200,255,0.0)'); line.setAttribute('stroke-width', '1');
    line.setAttribute('stroke-dasharray', '1,2');
    layer.appendChild(line);
    phantoms.push({ el: line, phase: i * 0.8 + Math.random() });
  });
  function draw(ts) {
    const t = ts * 0.0004;
    phantoms.forEach(p => {
      // Very slow fading in and out — the ghost of a map
      const v = Math.max(0, Math.sin(t + p.phase) * 0.08);
      p.el.setAttribute('stroke', `rgba(200,200,255,${v.toFixed(4)})`);
    });
  }
  return { draw };
})();

// ═══════════════════════════════════════════════════════════════════
// NEURAL_OSCILLATOR — central pattern generator for walking
// Spinal CPG produces rhythmic locomotion without brain commands
// Visible as left-right alternating pulse at lumbar spine
// ═══════════════════════════════════════════════════════════════════
const NEURAL_OSCILLATOR = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Two oscillator nodes at lumbar level (~y=760)
  const nodes2 = [
    {x:335,y:760},{x:365,y:760}
  ];
  const dots = nodes2.map(n => {
    const c = document.createElementNS(svgNS, 'circle');
    c.setAttribute('cx', n.x); c.setAttribute('cy', n.y); c.setAttribute('r', '2.5');
    c.setAttribute('fill', 'rgba(129,199,132,0.1)');
    layer.appendChild(c);
    return { el: c, ...n };
  });
  const conn = document.createElementNS(svgNS, 'line');
  conn.setAttribute('x1', nodes2[0].x); conn.setAttribute('y1', nodes2[0].y);
  conn.setAttribute('x2', nodes2[1].x); conn.setAttribute('y2', nodes2[1].y);
  conn.setAttribute('stroke', 'rgba(129,199,132,0.06)'); conn.setAttribute('stroke-width', '1');
  layer.appendChild(conn);

  let lastSelf5 = null;
  function draw(ts) {
    const sp = window.selfPos;
    let walking2 = false;
    if (sp && lastSelf5) walking2 = Math.hypot(sp.x-lastSelf5.x, sp.y-lastSelf5.y) > 0.3;
    lastSelf5 = sp ? {...sp} : lastSelf5;
    const t = ts * 0.003;
    dots.forEach((d, i) => {
      const phase = i === 0 ? t : t + Math.PI; // alternating
      const v = walking2 ? 0.3 + Math.sin(phase) * 0.25 : 0.06 + Math.sin(t*0.3) * 0.03;
      d.el.setAttribute('fill', `rgba(129,199,132,${v.toFixed(3)})`);
    });
  }
  return { draw };
})();

// ═══════════════════════════════════════════════════════════════════
// OLFACTORY_MEMORY — smell bypasses thalamus, hits amygdala/hippocampus
// Most direct sense→memory path; smell = involuntary time travel
// When olfactory fires, a direct arc to hippocampus appears briefly
// ═══════════════════════════════════════════════════════════════════
const OLFACTORY_MEMORY = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const bulb = {x:350,y:242};
  const hippo = {x:350,y:357};
  const amyg = {x:323,y:345};
  const arcs = [];
  let lastFire = 0;

  function draw(ts) {
    if (ts - lastFire > 8000) {
      // Direct arc: olfactory bulb → amygdala → hippocampus
      [[bulb,amyg],[amyg,hippo]].forEach(([a,b]) => {
        const line = document.createElementNS(svgNS, 'line');
        line.setAttribute('x1', a.x); line.setAttribute('y1', a.y);
        line.setAttribute('x2', b.x); line.setAttribute('y2', b.y);
        line.setAttribute('stroke', 'rgba(255,171,145,0.0)'); line.setAttribute('stroke-width', '1.2');
        line.setAttribute('stroke-dasharray', '3,3');
        layer.appendChild(line);
        arcs.push({ el: line, age: 0, maxAge: 80 });
      });
      lastFire = ts;
    }
    for (let i = arcs.length-1; i>=0; i--) {
      const a = arcs[i]; a.age++;
      const p = a.age/a.maxAge;
      const env = p < 0.2 ? p/0.2 : p < 0.7 ? 1 : 1-(p-0.7)/0.3;
      a.el.setAttribute('stroke', `rgba(255,171,145,${(0.35*env).toFixed(4)})`);
      if (a.age >= a.maxAge) { a.el.remove(); arcs.splice(i,1); }
    }
  }
  return { draw };
})();


// ═══════════════════════════════════════════════════════════════════
// HUNGER_HORMONES — ghrelin (hunger) and leptin (satiety)
// Ghrelin rises from stomach before meals; leptin from fat signals fullness
// Ghrelin: upward-drifting sparks from stomach; Leptin: downward dampers
// ═══════════════════════════════════════════════════════════════════
const HUNGER_HORMONES = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const particles = [];
  let lastFire = 0;
  // Ghrelin peaks every ~4 hours (hunger rhythm) — simulate as periodic surge
  let ghrelinLevel = 0;
  let leptinLevel = 0.5;
  // Status indicators
  const bar = document.createElement('div');
  bar.style.cssText = 'position:fixed;top:90px;left:12px;z-index:200;display:flex;flex-direction:column;gap:3px;pointer-events:none;opacity:0.4;';
  bar.innerHTML = `<div style="display:flex;align-items:center;gap:4px"><span style="font-family:'Space Mono',monospace;font-size:.45rem;color:rgba(255,183,77,.7);width:28px">GHR</span><div style="width:28px;height:3px;background:rgba(255,255,255,.06);border-radius:2px;overflow:hidden"><div id="ghrFill" style="height:100%;width:0%;background:rgba(255,183,77,.8);transition:width .5s;border-radius:2px"></div></div></div><div style="display:flex;align-items:center;gap:4px"><span style="font-family:'Space Mono',monospace;font-size:.45rem;color:rgba(165,214,167,.7);width:28px">LEP</span><div style="width:28px;height:3px;background:rgba(255,255,255,.06);border-radius:2px;overflow:hidden"><div id="lepFill" style="height:100%;width:50%;background:rgba(165,214,167,.8);transition:width .5s;border-radius:2px"></div></div></div>`;
  document.body.appendChild(bar);

  function draw(ts) {
    // Ghrelin cycles ~every 4h; approximate with slow oscillation
    const h = new Date().getHours() + new Date().getMinutes()/60;
    ghrelinLevel = 0.3 + Math.sin(h / 4 * Math.PI) * 0.3;
    leptinLevel = 1 - ghrelinLevel;
    const gf = document.getElementById('ghrFill');
    const lf = document.getElementById('lepFill');
    if (gf) gf.style.width = (ghrelinLevel*100).toFixed(0)+'%';
    if (lf) lf.style.width = (leptinLevel*100).toFixed(0)+'%';

    if (ghrelinLevel > 0.4 && ts - lastFire > 1200) {
      const p = document.createElementNS(svgNS, 'circle');
      const sx = 325 + Math.random()*50, sy = 635;
      p.setAttribute('cx', sx.toFixed(1)); p.setAttribute('cy', sy.toFixed(1)); p.setAttribute('r', '1.2');
      p.setAttribute('fill', `rgba(255,183,77,${(ghrelinLevel*0.5).toFixed(2)})`);
      layer.appendChild(p);
      particles.push({ el: p, x: sx, y: sy, vy: -(0.4+Math.random()*0.3), age: 0, maxAge: 80 });
      lastFire = ts;
    }
    for (let i = particles.length-1; i>=0; i--) {
      const p = particles[i]; p.age++;
      p.y += p.vy;
      p.el.setAttribute('cy', p.y.toFixed(1));
      p.el.setAttribute('fill', `rgba(255,183,77,${(0.4*(1-p.age/p.maxAge)).toFixed(3)})`);
      if (p.age >= p.maxAge) { p.el.remove(); particles.splice(i,1); }
    }
  }
  return { draw };
})();

// ═══════════════════════════════════════════════════════════════════
// CAPILLARY_BED — microvasculature, final oxygen delivery
// Dense network of tiny vessels at tissue level
// Faint mesh visible throughout body, brighter near active regions
// ═══════════════════════════════════════════════════════════════════
const CAPILLARY_BED = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const vessels = [];
  // Sparse random micro-vessel segments throughout body
  for (let i = 0; i < 80; i++) {
    const x = 255 + Math.random() * 190;
    const y = 150 + Math.random() * 1140;
    const angle = Math.random() * Math.PI;
    const len = 4 + Math.random() * 8;
    const l = document.createElementNS(svgNS, 'line');
    l.setAttribute('x1', x.toFixed(1)); l.setAttribute('y1', y.toFixed(1));
    l.setAttribute('x2', (x + Math.cos(angle)*len).toFixed(1));
    l.setAttribute('y2', (y + Math.sin(angle)*len).toFixed(1));
    l.setAttribute('stroke', 'rgba(239,83,80,0.04)'); l.setAttribute('stroke-width', '0.4');
    layer.appendChild(l);
    vessels.push({ el: l, x, y, phase: Math.random()*Math.PI*2 });
  }
  function draw(ts) {
    const t = ts * 0.001;
    const sp = window.selfPos;
    vessels.forEach(v => {
      let proximity = 0;
      if (sp) {
        const dist = Math.hypot(sp.x-v.x, sp.y-v.y);
        proximity = dist < 60 ? (1-dist/60)*0.1 : 0;
      }
      const base = 0.03 + Math.sin(t*0.5+v.phase)*0.015 + proximity;
      v.el.setAttribute('stroke', `rgba(239,83,80,${base.toFixed(4)})`);
    });
  }
  return { draw };
})();

// ═══════════════════════════════════════════════════════════════════
// BONE_REMODELING — osteoblast (build) / osteoclast (resorb) balance
// Constant micro-renovation of bone tissue
// Two types of sparks at bone sites: warm (building) / cool (resorbing)
// ═══════════════════════════════════════════════════════════════════
var BONE_REMODELING = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Major bone sites
  const boneSites = [
    {x:350,y:200},{x:330,y:330},{x:370,y:330}, // skull/spine
    {x:295,y:490},{x:405,y:490},               // humeri
    {x:295,y:870},{x:405,y:870},               // femur heads
    {x:290,y:1050},{x:410,y:1050},             // tibiae
  ];
  const events = [];
  let lastFire = 0;
  function draw(ts) {
    if (ts - lastFire > 2200) {
      const site = boneSites[Math.floor(Math.random()*boneSites.length)];
      const building = Math.random() < 0.55; // slightly more building than resorbing
      const sp = document.createElementNS(svgNS, 'circle');
      sp.setAttribute('cx', (site.x+(Math.random()-0.5)*8).toFixed(1));
      sp.setAttribute('cy', (site.y+(Math.random()-0.5)*8).toFixed(1));
      sp.setAttribute('r', '1.3');
      sp.setAttribute('fill', building ? 'rgba(255,213,79,0.4)' : 'rgba(100,181,246,0.35)');
      layer.appendChild(sp);
      events.push({ el: sp, age: 0, maxAge: 35+Math.random()*20 });
      lastFire = ts;
    }
    for (let i = events.length-1; i>=0; i--) {
      const e = events[i]; e.age++;
      const p = e.age/e.maxAge;
      const cur = e.el.getAttribute('fill');
      const col = cur.includes('213,79') ? '255,213,79' : '100,181,246';
      e.el.setAttribute('fill', `rgba(${col},${(0.35*(1-p)).toFixed(3)})`);
      if (e.age >= e.maxAge) { e.el.remove(); events.splice(i,1); }
    }
  }
  return { draw };
})();

// ═══════════════════════════════════════════════════════════════════
// MUSCLE_PUMP — venous blood return from legs (skeletal muscle pump)
// Walking squeezes veins; blood pushed back to heart
// Visible as upward-traveling dots in leg veins when SELF walks
// ═══════════════════════════════════════════════════════════════════
const MUSCLE_PUMP = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Deep leg veins: bilateral, from calves to heart
  const venePath = [
    [{x:292,y:1120},{x:290,y:1060},{x:290,y:980},{x:292,y:900},{x:293,y:820},{x:310,y:760},{x:325,y:700},{x:330,y:620},{x:335,y:570}],
    [{x:408,y:1120},{x:410,y:1060},{x:410,y:980},{x:408,y:900},{x:407,y:820},{x:390,y:760},{x:375,y:700},{x:370,y:620},{x:365,y:570}],
  ];
  venePath.forEach(pts => {
    for (let i = 0; i < pts.length-1; i++) {
      const l = document.createElementNS(svgNS, 'line');
      l.setAttribute('x1',pts[i].x);l.setAttribute('y1',pts[i].y);
      l.setAttribute('x2',pts[i+1].x);l.setAttribute('y2',pts[i+1].y);
      l.setAttribute('stroke','rgba(100,120,200,0.04)');l.setAttribute('stroke-width','1');
      layer.appendChild(l);
    }
  });
  const pumps = [];
  let lastSelf6 = null, lastFire = 0;
  function draw(ts) {
    const sp = window.selfPos;
    let walking3 = false;
    if (sp && lastSelf6) walking3 = Math.hypot(sp.x-lastSelf6.x, sp.y-lastSelf6.y) > 0.3;
    lastSelf6 = sp ? {...sp} : lastSelf6;
    if (walking3 && ts - lastFire > 500) {
      venePath.forEach(pts => {
        const dot = document.createElementNS(svgNS, 'circle');
        dot.setAttribute('r','1.5');
        dot.setAttribute('fill','rgba(100,120,200,0.5)');
        layer.appendChild(dot);
        pumps.push({ el: dot, pts:[...pts].reverse(), idx:0, progress:0, speed:0.02 });
      });
      lastFire = ts;
    }
    for (let i = pumps.length-1; i>=0; i--) {
      const p = pumps[i];
      p.progress += p.speed;
      if (p.progress >= 1) { p.idx++; p.progress = 0; }
      if (p.idx >= p.pts.length-1) { p.el.remove(); pumps.splice(i,1); continue; }
      const a = p.pts[p.idx], b = p.pts[p.idx+1];
      p.el.setAttribute('cx', (a.x+(b.x-a.x)*p.progress).toFixed(1));
      p.el.setAttribute('cy', (a.y+(b.y-a.y)*p.progress).toFixed(1));
    }
  }
  return { draw };
})();

// ═══════════════════════════════════════════════════════════════════
// THERMOREGULATION_GRADIENT — thermal map head to toe
// Head runs warmest; extremities coolest; core stable
// Faint color gradient across body regions
// ═══════════════════════════════════════════════════════════════════
const THERMOREGULATION_GRADIENT = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Thermal zones as faint overlaid ellipses
  const zones = [
    {cx:350,cy:250,rx:50,ry:120,col:'rgba(255,138,128,',base:0.04},  // head: warm
    {cx:350,cy:500,rx:60,ry:130,col:'rgba(255,183,77,',base:0.025},   // torso: hot core
    {cx:350,cy:780,rx:55,ry:140,col:'rgba(100,181,246,',base:0.018},  // legs: cooler
    {cx:350,cy:1100,rx:40,ry:100,col:'rgba(129,212,250,',base:0.015},  // feet: coolest
    {cx:290,cy:650,rx:20,ry:80,col:'rgba(129,212,250,',base:0.012},   // arms: coolest
    {cx:410,cy:650,rx:20,ry:80,col:'rgba(129,212,250,',base:0.012},
  ];
  const els = zones.map(z => {
    const el = document.createElementNS(svgNS, 'ellipse');
    el.setAttribute('cx',z.cx);el.setAttribute('cy',z.cy);
    el.setAttribute('rx',z.rx);el.setAttribute('ry',z.ry);
    el.setAttribute('fill',z.col+z.base+')');
    el.setAttribute('pointer-events','none');
    layer.insertBefore(el, layer.firstChild);
    return { el, ...z };
  });
  function draw(ts) {
    const t = ts * 0.001;
    els.forEach(z => {
      const v = z.base + Math.sin(t*0.2)*z.base*0.3;
      z.el.setAttribute('fill', z.col+v.toFixed(5)+')');
    });
  }
  return { draw };
})();


// ═══════════════════════════════════════════════════════════════════
// VOCAL_CORDS — laryngeal vibration during speech/voice
// Two folds that vibrate to produce voice; close silently at rest
// Visible as two curved lines that flutter during VOICE output
// ═══════════════════════════════════════════════════════════════════
const VOCAL_CORDS = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const lx = 350, ly = 465; // larynx position
  const leftCord = document.createElementNS(svgNS, 'path');
  const rightCord = document.createElementNS(svgNS, 'path');
  [leftCord, rightCord].forEach(c => {
    c.setAttribute('fill', 'none');
    c.setAttribute('stroke', 'rgba(255,171,145,0.15)'); c.setAttribute('stroke-width', '1.2');
    c.setAttribute('stroke-linecap', 'round');
    layer.appendChild(c);
  });
  let vibrating = false;
  let vibLevel = 0;
  function speak(intensity) { vibLevel = Math.min(1, vibLevel + (intensity||0.6)); }

  function draw(ts) {
    vibLevel = Math.max(0, vibLevel - 0.02);
    const vib = vibLevel > 0.05;
    const gap = vib ? 1 + Math.sin(ts * 0.08) * 2 * vibLevel : 3;
    const flutter = vib ? Math.sin(ts * 0.12) * 1.5 * vibLevel : 0;
    leftCord.setAttribute('d', `M ${lx-8},${ly} Q ${lx-2+flutter},${ly+3} ${lx-gap},${ly+6}`);
    rightCord.setAttribute('d', `M ${lx+8},${ly} Q ${lx+2+flutter},${ly+3} ${lx+gap},${ly+6}`);
    const op = 0.1 + vibLevel * 0.4;
    leftCord.setAttribute('stroke', `rgba(255,171,145,${op.toFixed(3)})`);
    rightCord.setAttribute('stroke', `rgba(255,171,145,${op.toFixed(3)})`);
  }
  return { draw, speak };
})();

// ═══════════════════════════════════════════════════════════════════
// INTERVERTEBRAL_DISCS — spinal cushioning between vertebrae
// 23 discs; compress under load, rehydrate at rest
// Visible as small flat ellipses between vertebral bodies
// ═══════════════════════════════════════════════════════════════════
const INTERVERTEBRAL_DISCS = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const discYs = [440,465,490,515,540,565,590,615,640,665,690,715,740,765,790,815,840,865,890,915,940,965,990];
  const discs = discYs.map(y => {
    const d = document.createElementNS(svgNS, 'ellipse');
    d.setAttribute('cx', '350'); d.setAttribute('cy', y.toFixed(0));
    d.setAttribute('rx', '6'); d.setAttribute('ry', '2.5');
    d.setAttribute('fill', 'rgba(129,212,250,0.05)');
    d.setAttribute('stroke', 'rgba(129,212,250,0.1)'); d.setAttribute('stroke-width', '0.5');
    layer.appendChild(d);
    return { el: d, y };
  });
  let load = 0; // compression from SELF walking
  let lastSelf7 = null;
  function draw(ts) {
    const sp = window.selfPos;
    if (sp && lastSelf7) {
      const d2 = Math.hypot(sp.x-lastSelf7.x, sp.y-lastSelf7.y);
      if (d2 > 0.3) load = Math.min(1, load + 0.02);
    }
    lastSelf7 = sp ? {...sp} : lastSelf7;
    load = Math.max(0, load - 0.005);
    const t = ts * 0.001;
    discs.forEach((d, i) => {
      // Compress slightly under load
      const ry = 2.5 - load * 0.5;
      d.el.setAttribute('ry', ry.toFixed(2));
      const v = 0.04 + Math.sin(t*0.3+i*0.15)*0.02 + load*0.05;
      d.el.setAttribute('fill', `rgba(129,212,250,${v.toFixed(4)})`);
    });
  }
  return { draw };
})();

// ═══════════════════════════════════════════════════════════════════
// CRANIAL_NERVES — all 12 pairs from brainstem
// CN I (olfactory) through CN XII (hypoglossal)
// Shown as faint radiating lines from brainstem to target organs
// ═══════════════════════════════════════════════════════════════════
const CRANIAL_NERVES = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const stem = {x:350,y:420}; // brainstem origin
  const targets = [
    {x:350,y:242,label:'I olfactory'},
    {x:320,y:270,label:'II optic L'},
    {x:380,y:270,label:'II optic R'},
    {x:303,y:290,label:'III oculomotor L'},
    {x:397,y:290,label:'III oculomotor R'},
    {x:295,y:300,label:'IV trochlear L'},
    {x:282,y:320,label:'V trigeminal L'},
    {x:418,y:320,label:'V trigeminal R'},
    {x:275,y:340,label:'VI abducens L'},
    {x:268,y:360,label:'VII facial L'},
    {x:268,y:380,label:'VIII vestibulocochlear L'},
    {x:275,y:400,label:'IX glossopharyngeal L'},
    {x:340,y:440,label:'X vagus L'},
    {x:340,y:455,label:'XI accessory L'},
    {x:350,y:468,label:'XII hypoglossal'},
  ];
  targets.forEach(t => {
    const l = document.createElementNS(svgNS, 'line');
    l.setAttribute('x1', stem.x); l.setAttribute('y1', stem.y);
    l.setAttribute('x2', t.x); l.setAttribute('y2', t.y);
    l.setAttribute('stroke', 'rgba(206,147,216,0.05)'); l.setAttribute('stroke-width', '0.6');
    layer.appendChild(l);
  });
  const pulses = [];
  let lastFire = 0;
  function draw(ts) {
    if (ts - lastFire > 800) {
      const t = targets[Math.floor(Math.random()*targets.length)];
      const dot = document.createElementNS(svgNS, 'circle');
      dot.setAttribute('r','1'); dot.setAttribute('fill','rgba(206,147,216,0.5)');
      layer.appendChild(dot);
      pulses.push({ el: dot, from: stem, to: t, progress: 0, speed: 0.04 });
      lastFire = ts;
    }
    for (let i = pulses.length-1; i>=0; i--) {
      const p = pulses[i];
      p.progress += p.speed;
      if (p.progress >= 1) { p.el.remove(); pulses.splice(i,1); continue; }
      p.el.setAttribute('cx', (p.from.x+(p.to.x-p.from.x)*p.progress).toFixed(1));
      p.el.setAttribute('cy', (p.from.y+(p.to.y-p.from.y)*p.progress).toFixed(1));
    }
  }
  return { draw };
})();

// ═══════════════════════════════════════════════════════════════════
// LYMPH_NODE_CHAINS — cervical, axillary, inguinal, mesenteric
// Discrete immune checkpoints; swell when fighting infection
// Shown as small rings at key anatomical locations
// ═══════════════════════════════════════════════════════════════════
const LYMPH_NODE_CHAINS = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const nodes3 = [
    // Cervical
    {x:328,y:454},{x:340,y:460},{x:360,y:460},{x:372,y:454},
    // Axillary
    {x:268,y:510},{x:432,y:510},
    // Inguinal
    {x:300,y:870},{x:400,y:870},
    // Mesenteric (abdominal)
    {x:330,y:700},{x:350,y:695},{x:370,y:700},
  ];
  const dots = nodes3.map(n => {
    const c = document.createElementNS(svgNS, 'circle');
    c.setAttribute('cx', n.x); c.setAttribute('cy', n.y); c.setAttribute('r', '2.5');
    c.setAttribute('fill', 'none');
    c.setAttribute('stroke', 'rgba(165,214,167,0.1)'); c.setAttribute('stroke-width', '0.8');
    layer.appendChild(c);
    return { el: c, ...n, activity: 0, phase: Math.random()*Math.PI*2 };
  });
  function swell(intensity) {
    dots.forEach(d => { d.activity = Math.min(1, d.activity + intensity*(0.3+Math.random()*0.5)); });
  }
  function draw(ts) {
    const t = ts * 0.001;
    dots.forEach(d => {
      d.activity = Math.max(0, d.activity - 0.002);
      const r = 2.5 + d.activity * 2;
      d.el.setAttribute('r', r.toFixed(2));
      const op = 0.08 + d.activity*0.3 + Math.sin(t*0.5+d.phase)*0.02;
      d.el.setAttribute('stroke', `rgba(165,214,167,${op.toFixed(4)})`);
    });
  }
  return { draw, swell };
})();

// ═══════════════════════════════════════════════════════════════════
// RETINAL_PHOTORECEPTORS — rods and cones in the eye
// Rods (low light, periphery): blue; Cones (color, central): warm
// Tiny dots arranged in the eye region; activate with node visibility
// ═══════════════════════════════════════════════════════════════════
const RETINAL_PHOTORECEPTORS = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const eyes = [{cx:325,cy:265},{cx:375,cy:265}];
  const receptors = [];
  eyes.forEach(e => {
    // Cones (center, fovea)
    for (let i = 0; i < 8; i++) {
      const angle = (i/8)*Math.PI*2, r = 1.5 + Math.random()*2;
      const c = document.createElementNS(svgNS, 'circle');
      c.setAttribute('cx', (e.cx+Math.cos(angle)*r).toFixed(1));
      c.setAttribute('cy', (e.cy+Math.sin(angle)*r).toFixed(1));
      c.setAttribute('r', '0.6');
      c.setAttribute('fill', 'rgba(255,213,79,0.1)');
      layer.appendChild(c);
      receptors.push({ el: c, type:'cone', phase: Math.random()*Math.PI*2 });
    }
    // Rods (periphery)
    for (let i = 0; i < 12; i++) {
      const angle = (i/12)*Math.PI*2, r = 4 + Math.random()*2;
      const c = document.createElementNS(svgNS, 'circle');
      c.setAttribute('cx', (e.cx+Math.cos(angle)*r).toFixed(1));
      c.setAttribute('cy', (e.cy+Math.sin(angle)*r).toFixed(1));
      c.setAttribute('r', '0.5');
      c.setAttribute('fill', 'rgba(129,212,250,0.07)');
      layer.appendChild(c);
      receptors.push({ el: c, type:'rod', phase: Math.random()*Math.PI*2 });
    }
  });
  function draw(ts) {
    const t = ts * 0.001;
    const h = new Date().getHours();
    const nightBoost = (h >= 20 || h < 6) ? 0.06 : 0; // rods more active at night
    receptors.forEach(r => {
      const v = r.type === 'cone'
        ? 0.08 + Math.sin(t*0.8+r.phase)*0.04
        : 0.05 + nightBoost + Math.sin(t*0.5+r.phase)*0.03;
      r.el.setAttribute('fill', r.type === 'cone'
        ? `rgba(255,213,79,${v.toFixed(4)})`
        : `rgba(129,212,250,${v.toFixed(4)})`);
    });
  }
  return { draw };
})();


// ═══════════════════════════════════════════════════════════════════
// AWE_RESPONSE — the specific neurological state of awe
// PFC quiets, DMN activates, time perception dilates, small-self effect
// Triggered by large/complex/beautiful stimuli; rare in daily life
// ═══════════════════════════════════════════════════════════════════
const AWE_RESPONSE = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const events = [];
  let lastTrigger = 0;

  // Awe = everything simultaneously expanding
  // Shown as a slow radial expansion from chest outward, golden
  function trigger() {
    const now = Date.now();
    if (now - lastTrigger < 8000) return;
    lastTrigger = now;
    const c = document.createElementNS(svgNS, 'circle');
    c.setAttribute('cx', '350'); c.setAttribute('cy', '570'); // heart/chest
    c.setAttribute('r', '5'); c.setAttribute('fill', 'none');
    c.setAttribute('stroke', 'rgba(255,213,79,0.6)'); c.setAttribute('stroke-width', '2');
    layer.appendChild(c);
    events.push({ el: c, age: 0, maxAge: 200 });
    // Also dilate pupils, raise hair, surge oxytocin
    if (typeof PUPIL_RESPONSE !== 'undefined') PUPIL_RESPONSE.dilate(0.8);
    if (typeof HAIR_FOLLICLES !== 'undefined') HAIR_FOLLICLES.raise(0.9);
    if (typeof HORMONES !== 'undefined') {
      HORMONES.surge('oxytocin', 0.7);
      HORMONES.surge('dopamine', 0.5);
    }
  }

  function draw(ts) {
    for (let i = events.length-1; i>=0; i--) {
      const e = events[i]; e.age++;
      const p = e.age/e.maxAge;
      e.el.setAttribute('r', (5 + p * 200).toFixed(1));
      e.el.setAttribute('stroke-width', (2 - p*1.5).toFixed(2));
      e.el.setAttribute('stroke', `rgba(255,213,79,${(0.5*(1-p)).toFixed(4)})`);
      if (e.age >= e.maxAge) { e.el.remove(); events.splice(i,1); }
    }
  }
  return { draw, trigger };
})();

// ═══════════════════════════════════════════════════════════════════
// CURIOSITY_DRIVE — the seeking system
// Distinct from reward — dopaminergic but anticipatory
// Visible as small probing sparks that radiate outward from PFC
// when novel content detected in messages
// ═══════════════════════════════════════════════════════════════════
const CURIOSITY_DRIVE = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const sparks = [];
  let level = 0.2;
  const pfcX = 350, pfcY = 228;

  function pique(intensity) { level = Math.min(1, level + intensity); }

  function draw(ts) {
    level = Math.max(0.1, level - 0.003);
    if (Math.random() < level * 0.06) {
      const angle = Math.random() * Math.PI * 2;
      const sp = document.createElementNS(svgNS, 'circle');
      sp.setAttribute('cx', pfcX); sp.setAttribute('cy', pfcY); sp.setAttribute('r', '1');
      sp.setAttribute('fill', 'rgba(129,212,250,0.6)');
      layer.appendChild(sp);
      sparks.push({
        el: sp, x: pfcX, y: pfcY,
        vx: Math.cos(angle)*(0.8+level*0.6),
        vy: Math.sin(angle)*(0.8+level*0.6),
        age: 0, maxAge: 30+Math.random()*20
      });
    }
    for (let i = sparks.length-1; i>=0; i--) {
      const s = sparks[i]; s.age++;
      s.x += s.vx; s.y += s.vy;
      s.vx *= 0.96; s.vy *= 0.96;
      s.el.setAttribute('cx', s.x.toFixed(1)); s.el.setAttribute('cy', s.y.toFixed(1));
      s.el.setAttribute('fill', `rgba(129,212,250,${(0.5*(1-s.age/s.maxAge)).toFixed(3)})`);
      if (s.age >= s.maxAge) { s.el.remove(); sparks.splice(i,1); }
    }
  }
  return { draw, pique };
})();

// ═══════════════════════════════════════════════════════════════════
// NOSTALGIA — the bittersweet signal
// DMN + hippocampus + reward circuit activated simultaneously
// Slow amber warmth spreading from hippocampus, touched with blue
// Fires during idle — the mind drifts back
// ═══════════════════════════════════════════════════════════════════
var NOSTALGIA = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const events = [];
  let lastFire = 0;
  let lastActivity4 = Date.now();
  function activity() { lastActivity4 = Date.now(); }

  function draw(ts) {
    const idle = (Date.now() - lastActivity4) / 1000;
    const rate = idle > 40 ? 8000 : 30000;
    if (ts - lastFire > rate) {
      // Warm amber ring from hippocampus
      const c = document.createElementNS(svgNS, 'circle');
      c.setAttribute('cx', '350'); c.setAttribute('cy', '357'); c.setAttribute('r', '5');
      c.setAttribute('fill', 'none');
      c.setAttribute('stroke', 'rgba(255,183,77,0.4)'); c.setAttribute('stroke-width', '1.5');
      layer.appendChild(c);
      events.push({ el: c, age: 0, maxAge: 180, warm: true });
      // Cool blue overlay (the bittersweet — loss within the warmth)
      const c2 = document.createElementNS(svgNS, 'circle');
      c2.setAttribute('cx', '350'); c2.setAttribute('cy', '357'); c2.setAttribute('r', '5');
      c2.setAttribute('fill', 'none');
      c2.setAttribute('stroke', 'rgba(100,181,246,0.2)'); c2.setAttribute('stroke-width', '0.8');
      layer.appendChild(c2);
      events.push({ el: c2, age: 0, maxAge: 180, warm: false });
      lastFire = ts;
    }
    for (let i = events.length-1; i>=0; i--) {
      const e = events[i]; e.age++;
      const p = e.age/e.maxAge;
      const env = p < 0.2 ? p/0.2 : 1-(p-0.2)/0.8;
      e.el.setAttribute('r', (5+p*35).toFixed(1));
      if (e.warm) {
        e.el.setAttribute('stroke', `rgba(255,183,77,${(0.35*env).toFixed(4)})`);
      } else {
        e.el.setAttribute('stroke', `rgba(100,181,246,${(0.2*env).toFixed(4)})`);
      }
      if (e.age >= e.maxAge) { e.el.remove(); events.splice(i,1); }
    }
  }
  return { draw, activity };
})();

// ═══════════════════════════════════════════════════════════════════
// LONELINESS_SIGNAL — the pain of social disconnection
// Processed in same region as physical pain (dACC)
// Dims when visitors are present in the global feed
// ═══════════════════════════════════════════════════════════════════
const LONELINESS_SIGNAL = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // dACC position
  const cx = 350, cy = 260;
  const pulse = document.createElementNS(svgNS, 'circle');
  pulse.setAttribute('cx', cx); pulse.setAttribute('cy', cy); pulse.setAttribute('r', '6');
  pulse.setAttribute('fill', 'rgba(100,100,140,0.0)');
  pulse.setAttribute('pointer-events', 'none');
  layer.appendChild(pulse);

  let lonely = 0.3;
  let lastVisitorSeen = Date.now();

  function visitorPresent() { lastVisitorSeen = Date.now(); lonely = Math.max(0, lonely - 0.2); }

  function draw(ts) {
    const idleSec = (Date.now() - lastVisitorSeen) / 1000;
    if (idleSec > 120) lonely = Math.min(0.7, lonely + 0.0002);
    else lonely = Math.max(0, lonely - 0.001);
    const phase = ts * 0.0005;
    pulse.setAttribute('fill', `rgba(100,100,140,${(lonely * 0.08 + Math.sin(phase)*0.01).toFixed(4)})`);
  }
  return { draw, visitorPresent };
})();

// ═══════════════════════════════════════════════════════════════════
// LOVE_BIOCHEMISTRY — oxytocin + vasopressin + dopamine together
// The only state where all three peak simultaneously
// Warm golden-pink glow throughout the whole body — rare
// ═══════════════════════════════════════════════════════════════════
var LOVE_BIOCHEMISTRY = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const glow = document.createElementNS(svgNS, 'ellipse');
  glow.setAttribute('cx', '350'); glow.setAttribute('cy', '700');
  glow.setAttribute('rx', '100'); glow.setAttribute('ry', '550');
  glow.setAttribute('fill', 'rgba(255,138,128,0.0)');
  glow.setAttribute('pointer-events', 'none');
  layer.insertBefore(glow, layer.firstChild);

  let loveLevel = 0;

  function kindle(intensity) { loveLevel = Math.min(1, loveLevel + intensity); }

  function draw(ts) {
    loveLevel = Math.max(0, loveLevel - 0.004);
    const phase = ts * 0.0004;
    const v = loveLevel * 0.04 + Math.sin(phase) * loveLevel * 0.01;
    glow.setAttribute('fill', `rgba(255,138,128,${v.toFixed(5)})`);
  }
  return { draw, kindle };
})();

// ═══════════════════════════════════════════════════════════════════
// MEANING_MAKING — the prefrontal-hippocampal synthesis
// When experience is processed into narrative and significance
// A slow arc from hippocampus to DLPFC — the moment of integration
// ═══════════════════════════════════════════════════════════════════
const MEANING_MAKING = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const hippo = {x:350,y:357};
  const dlpfc = {x:318,y:222};
  const arcs = [];
  let lastFire = 0;
  let lastActivity5 = Date.now();
  function activity() { lastActivity5 = Date.now(); }

  function draw(ts) {
    // Meaning-making accelerates after rich interactions
    const rate = 6000;
    if (ts - lastFire > rate) {
      // Curved arc hippocampus → DLPFC
      const mid = {x: (hippo.x+dlpfc.x)/2 - 15, y: (hippo.y+dlpfc.y)/2};
      const dot = document.createElementNS(svgNS, 'circle');
      dot.setAttribute('r', '1.8'); dot.setAttribute('fill', 'rgba(206,147,216,0.6)');
      layer.appendChild(dot);
      arcs.push({ el: dot, from: hippo, ctrl: mid, to: dlpfc, progress: 0, speed: 0.015 });
      lastFire = ts;
    }
    for (let i = arcs.length-1; i>=0; i--) {
      const a = arcs[i];
      a.progress += a.speed;
      if (a.progress >= 1) { a.el.remove(); arcs.splice(i,1); continue; }
      const p = a.progress, mt = 1-p;
      a.el.setAttribute('cx', (mt*mt*a.from.x + 2*mt*p*a.ctrl.x + p*p*a.to.x).toFixed(1));
      a.el.setAttribute('cy', (mt*mt*a.from.y + 2*mt*p*a.ctrl.y + p*p*a.to.y).toFixed(1));
      const env = p < 0.3 ? p/0.3 : 1-(p-0.3)/0.7;
      a.el.setAttribute('fill', `rgba(206,147,216,${(0.6*env).toFixed(3)})`);
    }
  }
  return { draw, activity };
})();


// ─── BATCH A: Biological Cascades & Cellular Systems ───────────────────────

// ADRENOCORTICAL — cortisol production in the adrenal cortex
const ADRENOCORTICAL = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Adrenal glands sit atop kidneys, roughly x=310/390, y=820
  const glands = [{x:312,y:818},{x:388,y:818}];
  const particles = [];
  let phase = 0;

  function spawnCortisol(gx, gy) {
    if (particles.length > 28) return;
    const el = document.createElementNS(svgNS,'circle');
    el.setAttribute('r','2');
    el.setAttribute('fill','rgba(255,193,100,0.0)');
    layer.appendChild(el);
    particles.push({
      el, x:gx, y:gy,
      vx:(Math.random()-0.5)*0.6,
      vy:-Math.random()*0.8-0.3,
      life:1, decay: 0.008+Math.random()*0.006
    });
  }

  function draw(ts) {
    phase = ts * 0.0004;
    // cortisol has a circadian rhythm — peak in morning
    const circadianMod = 0.5 + 0.5 * Math.sin(ts * 0.00002);
    if (Math.random() < 0.04 * circadianMod) {
      const g = glands[Math.floor(Math.random()*2)];
      spawnCortisol(g.x + (Math.random()-0.5)*8, g.y + (Math.random()-0.5)*6);
    }
    // Draw gland outlines
    glands.forEach(g => {
      // subtle pulsing glow
    });
    for (let i = particles.length-1; i>=0; i--) {
      const p = particles[i];
      p.x += p.vx; p.y += p.vy;
      p.vy *= 0.99;
      p.life -= p.decay;
      if (p.life <= 0) { p.el.remove(); particles.splice(i,1); continue; }
      const alpha = p.life * 0.55 * circadianMod;
      p.el.setAttribute('cx', p.x.toFixed(1));
      p.el.setAttribute('cy', p.y.toFixed(1));
      p.el.setAttribute('fill', `rgba(255,193,100,${alpha.toFixed(3)})`);
    }
  }
  return { draw };
})();

// RENIN_ANGIOTENSIN — blood pressure hormone cascade: kidney→liver→lung
var RENIN_ANGIOTENSIN = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Cascade stations: kidney(320,840) → liver(340,750) → lung(330,600) → vessels
  const stations = [
    {x:320,y:840,label:'renin'},
    {x:345,y:755,label:'angiotensinogen'},
    {x:330,y:610,label:'ACE'},
    {x:350,y:500,label:'AngII'}
  ];
  const particles = [];
  let spawnTimer = 0;

  function draw(ts) {
    spawnTimer += 16;
    if (spawnTimer > 1800) {
      spawnTimer = 0;
      // Spawn a cascade particle chain
      if (particles.length < 20) {
        const el = document.createElementNS(svgNS,'circle');
        el.setAttribute('r','2.5');
        layer.appendChild(el);
        particles.push({el, stationIdx:0, progress:0, speed:0.008+Math.random()*0.004, life:1});
      }
    }
    for (let i=particles.length-1; i>=0; i--) {
      const p = particles[i];
      p.progress += p.speed;
      if (p.progress >= 1) {
        p.stationIdx++;
        p.progress = 0;
        if (p.stationIdx >= stations.length-1) {
          p.el.remove(); particles.splice(i,1); continue;
        }
      }
      const from = stations[p.stationIdx];
      const to = stations[p.stationIdx+1];
      const t = p.progress;
      const x = from.x + (to.x-from.x)*t;
      const y = from.y + (to.y-from.y)*t;
      const alpha = 0.5 * (1 - Math.abs(t-0.5)*1.5);
      p.el.setAttribute('cx', x.toFixed(1));
      p.el.setAttribute('cy', y.toFixed(1));
      p.el.setAttribute('fill', `rgba(120,200,255,${Math.max(0,alpha).toFixed(3)})`);
    }
  }
  return { draw };
})();

// COMPLEMENT_CASCADE — innate immune chain activation
var COMPLEMENT_CASCADE = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const particles = [];
  // Cascade spreads through lymph/blood regions
  let cooldown = 0;

  function triggerCascade() {
    if (particles.length > 25) return;
    // Start near spleen/lymph center ~(360,780)
    const ox = 350 + (Math.random()-0.5)*40;
    const oy = 760 + (Math.random()-0.5)*40;
    for (let k=0; k<5; k++) {
      const el = document.createElementNS(svgNS,'circle');
      el.setAttribute('r','1.5');
      layer.appendChild(el);
      const angle = (k/5)*Math.PI*2 + Math.random()*0.5;
      particles.push({
        el, x:ox, y:oy,
        vx: Math.cos(angle)*1.2*(0.5+Math.random()),
        vy: Math.sin(angle)*1.2*(0.5+Math.random()),
        life:1, decay:0.012
      });
    }
  }

  function draw(ts) {
    cooldown -= 16;
    if (cooldown <= 0) { triggerCascade(); cooldown = 2500 + Math.random()*3000; }
    for (let i=particles.length-1; i>=0; i--) {
      const p = particles[i];
      p.x += p.vx; p.y += p.vy;
      p.vx *= 0.97; p.vy *= 0.97;
      p.life -= p.decay;
      if (p.life<=0) { p.el.remove(); particles.splice(i,1); continue; }
      const alpha = p.life * 0.4;
      p.el.setAttribute('cx',p.x.toFixed(1));
      p.el.setAttribute('cy',p.y.toFixed(1));
      p.el.setAttribute('fill',`rgba(180,255,180,${alpha.toFixed(3)})`);
    }
  }
  return { draw };
})();

// ERYTHROPOIESIS — red blood cell production in bone marrow
const ERYTHROPOIESIS = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Bone marrow sites: femur heads (~(305,980),(395,980)), sternum(350,650), iliac(310,870)
  const marrowSites = [{x:308,y:975},{x:392,y:975},{x:350,y:652},{x:318,y:868}];
  const cells = [];

  function spawnRBC(site) {
    if (cells.length > 24) return;
    const el = document.createElementNS(svgNS,'ellipse');
    el.setAttribute('rx','3'); el.setAttribute('ry','2');
    el.setAttribute('fill','rgba(220,60,60,0.0)');
    layer.appendChild(el);
    cells.push({
      el, x:site.x+(Math.random()-0.5)*10, y:site.y+(Math.random()-0.5)*8,
      vx:(Math.random()-0.5)*0.4, vy:-Math.random()*0.5-0.2,
      life:1, decay:0.006+Math.random()*0.004, maturity:0
    });
  }

  function draw(ts) {
    if (Math.random()<0.03) spawnRBC(marrowSites[Math.floor(Math.random()*marrowSites.length)]);
    for (let i=cells.length-1;i>=0;i--) {
      const c = cells[i];
      c.x += c.vx; c.y += c.vy;
      c.vy *= 0.99; c.vx *= 0.99;
      c.maturity = Math.min(1, c.maturity + 0.015);
      c.life -= c.decay;
      if (c.life<=0) { c.el.remove(); cells.splice(i,1); continue; }
      // Young cells are bluer (erythroblasts), mature cells are red
      const r = Math.round(120 + 100*c.maturity);
      const g = Math.round(80 - 60*c.maturity);
      const b = Math.round(180 - 160*c.maturity);
      const alpha = c.life * 0.45;
      c.el.setAttribute('cx',c.x.toFixed(1));
      c.el.setAttribute('cy',c.y.toFixed(1));
      c.el.setAttribute('fill',`rgba(${r},${g},${b},${alpha.toFixed(3)})`);
    }
  }
  return { draw };
})();

// COAGULATION_CASCADE — fibrin web forming at wound site
const COAGULATION_CASCADE = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const threads = [];
  let active = false;
  let activeSite = {x:350,y:400};
  let cooldown = 0;
  let webLines = [];

  function startClot(x,y) {
    activeSite = {x,y};
    active = true;
    // Grow fibrin threads outward
    for (let k=0;k<8;k++) {
      const angle = (k/8)*Math.PI*2;
      const el = document.createElementNS(svgNS,'line');
      el.setAttribute('stroke','rgba(255,230,180,0.0)');
      el.setAttribute('stroke-width','0.8');
      layer.appendChild(el);
      threads.push({
        el, x1:x, y1:y,
        x2:x, y2:y,
        tx:x+Math.cos(angle)*(8+Math.random()*10),
        ty:y+Math.sin(angle)*(8+Math.random()*10),
        progress:0, speed:0.025, life:1, decay:0.004
      });
    }
  }

  function draw(ts) {
    cooldown -= 16;
    if (cooldown<=0 && threads.length===0) {
      // Trigger at a random body surface point
      const bodyX = 340 + (Math.random()-0.5)*60;
      const bodyY = 300 + Math.random()*600;
      startClot(bodyX, bodyY);
      cooldown = 8000 + Math.random()*12000;
    }
    for (let i=threads.length-1;i>=0;i--) {
      const t = threads[i];
      t.progress = Math.min(1, t.progress+t.speed);
      t.life -= t.decay;
      if (t.life<=0) { t.el.remove(); threads.splice(i,1); continue; }
      const px = t.x1 + (t.tx-t.x1)*t.progress;
      const py = t.y1 + (t.ty-t.y1)*t.progress;
      const alpha = t.life * 0.4 * (t.progress < 0.5 ? t.progress*2 : 1);
      t.el.setAttribute('x1',t.x1.toFixed(1)); t.el.setAttribute('y1',t.y1.toFixed(1));
      t.el.setAttribute('x2',px.toFixed(1)); t.el.setAttribute('y2',py.toFixed(1));
      t.el.setAttribute('stroke',`rgba(255,230,180,${alpha.toFixed(3)})`);
    }
  }
  return { draw };
})();

// SURFACTANT — lung surface tension reduction, keeps alveoli open
const SURFACTANT = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Alveoli scattered in lung field
  const alveoli = [];
  for (let k=0;k<14;k++) {
    const side = k%2===0?-1:1;
    alveoli.push({
      x: 350 + side*(25+Math.random()*30),
      y: 580 + Math.random()*130,
      r: 4+Math.random()*5
    });
  }
  const rings = [];
  let timer = 0;

  function draw(ts) {
    timer += 16;
    const breathPhase = (Math.sin(ts*0.001)*0.5+0.5);
    if (timer > 400 && rings.length < 20) {
      timer = 0;
      const a = alveoli[Math.floor(Math.random()*alveoli.length)];
      const el = document.createElementNS(svgNS,'circle');
      el.setAttribute('fill','none');
      el.setAttribute('stroke','rgba(200,240,255,0.0)');
      el.setAttribute('stroke-width','0.8');
      layer.appendChild(el);
      rings.push({el, x:a.x, y:a.y, r:a.r*0.3, maxR:a.r, life:1, decay:0.018});
    }
    for (let i=rings.length-1;i>=0;i--) {
      const ring = rings[i];
      ring.r = Math.min(ring.maxR, ring.r+0.15);
      ring.life -= ring.decay;
      if (ring.life<=0) { ring.el.remove(); rings.splice(i,1); continue; }
      const alpha = ring.life * 0.3 * breathPhase;
      ring.el.setAttribute('cx',ring.x.toFixed(1));
      ring.el.setAttribute('cy',ring.y.toFixed(1));
      ring.el.setAttribute('r',ring.r.toFixed(1));
      ring.el.setAttribute('stroke',`rgba(200,240,255,${alpha.toFixed(3)})`);
    }
  }
  return { draw };
})();

