// CORONARY_CIRCULATION — blood supply to the heart muscle itself
const CORONARY_CIRCULATION = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Heart center ~(350,680). Coronary arteries wrap the heart surface
  const heartX = 350, heartY = 680;
  const particles = [];
  // Two main coronary paths (left/right) as bezier control points
  const leftPath = [{x:350,y:670},{x:335,y:665},{x:325,y:680},{x:330,y:700},{x:345,y:710}];
  const rightPath = [{x:350,y:670},{x:365,y:665},{x:375,y:680},{x:370,y:700},{x:355,y:710}];

  function spawnCoronary(path) {
    if (particles.length > 22) return;
    const el = document.createElementNS(svgNS,'circle');
    el.setAttribute('r','1.8');
    layer.appendChild(el);
    particles.push({el, path, idx:0, t:0, speed:0.025+Math.random()*0.015, life:1});
  }

  function getPathPos(path, idx, t) {
    if (idx >= path.length-1) return path[path.length-1];
    const a = path[idx], b = path[idx+1];
    return {x:a.x+(b.x-a.x)*t, y:a.y+(b.y-a.y)*t};
  }

  function draw(ts) {
    if (Math.random()<0.04) {
      if (Math.random()<0.5) spawnCoronary(leftPath); else spawnCoronary(rightPath);
    }
    for (let i=particles.length-1;i>=0;i--) {
      const p = particles[i];
      p.t += p.speed;
      if (p.t >= 1) { p.t = 0; p.idx++; }
      if (p.idx >= p.path.length-1) { p.el.remove(); particles.splice(i,1); continue; }
      const pos = getPathPos(p.path, p.idx, p.t);
      const alpha = 0.55 * (p.idx < p.path.length-2 ? 1 : 1-p.t);
      p.el.setAttribute('cx',pos.x.toFixed(1));
      p.el.setAttribute('cy',pos.y.toFixed(1));
      p.el.setAttribute('fill',`rgba(255,80,80,${alpha.toFixed(3)})`);
    }
  }
  return { draw };
})();

// PULMONARY_CIRCULATION — right heart→lungs→left heart oxygen exchange
const PULMONARY_CIRCULATION = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Right heart(345,690)→right lung(310,620)→left lung(390,620)→left heart(355,690)
  const rightLoop = [{x:345,y:688},{x:315,y:660},{x:305,y:630},{x:318,y:615}];
  const leftLoop  = [{x:355,y:688},{x:385,y:660},{x:395,y:630},{x:382,y:615}];
  const particles = [];
  let timer = 0;

  function spawn(path, oxygenated) {
    if (particles.length > 20) return;
    const el = document.createElementNS(svgNS,'circle');
    el.setAttribute('r','2');
    layer.appendChild(el);
    particles.push({el, path, idx:0, t:0, speed:0.02+Math.random()*0.01, oxygenated, life:1});
  }

  function draw(ts) {
    timer += 16;
    if (timer > 800) {
      timer = 0;
      spawn(rightLoop, false);
      spawn(leftLoop, false);
    }
    for (let i=particles.length-1;i>=0;i--) {
      const p = particles[i];
      p.t += p.speed;
      if (p.t >= 1) { p.t=0; p.idx++; if (p.idx===Math.floor(p.path.length/2)) p.oxygenated=true; }
      if (p.idx >= p.path.length-1) { p.el.remove(); particles.splice(i,1); continue; }
      const a=p.path[p.idx], b=p.path[p.idx+1];
      const x=a.x+(b.x-a.x)*p.t, y=a.y+(b.y-a.y)*p.t;
      const alpha = 0.5 * Math.sin(p.t*Math.PI);
      const col = p.oxygenated ? `rgba(255,80,80,${alpha.toFixed(3)})` : `rgba(80,100,200,${alpha.toFixed(3)})`;
      p.el.setAttribute('cx',x.toFixed(1));
      p.el.setAttribute('cy',y.toFixed(1));
      p.el.setAttribute('fill',col);
    }
  }
  return { draw };
})();

