// PEAK_END_RULE — memories formed by peak intensity and final moment
const PEAK_END_RULE = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Hippocampus encodes peak and end — both in medial temporal lobe (345,228)
  let peakIntensity = 0;
  let endMark = 0;
  let sequence = [];
  let seqTimer = 0;
  const glows = [];

  function draw(ts) {
    seqTimer += 16;
    // Simulate an experience unfolding
    if (seqTimer > 200) {
      seqTimer = 0;
      const val = 0.3+0.7*Math.abs(Math.sin(ts*0.0003+Math.cos(ts*0.00007)));
      sequence.push(val);
      if (sequence.length > 30) sequence.shift();
      peakIntensity = Math.max(...sequence);
      endMark = sequence[sequence.length-1];
    }
    // Glow at peak and end moments
    const memScore = (peakIntensity + endMark) / 2;
    if (Math.random() < memScore*0.03 && glows.length < 12) {
      const el = document.createElementNS(svgNS,'circle');
      el.setAttribute('r','3');
      layer.appendChild(el);
      glows.push({
        el,
        x: 345+(Math.random()-0.5)*15,
        y: 228+(Math.random()-0.5)*10,
        life:1, decay:0.012, score:memScore
      });
    }
    for (let i=glows.length-1;i>=0;i--) {
      const g = glows[i];
      g.life -= g.decay;
      if (g.life<=0) { g.el.remove(); glows.splice(i,1); continue; }
      const alpha = g.life * 0.45 * g.score;
      g.el.setAttribute('cx',g.x.toFixed(1));
      g.el.setAttribute('cy',g.y.toFixed(1));
      g.el.setAttribute('fill',`rgba(255,240,160,${alpha.toFixed(3)})`);
    }
  }
  return { draw };
})();

