// SYNCHRONY — two nervous systems coupling, shared rhythm
const SYNCHRONY = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Dual oscillators on either side of the head
  const leftOsc = {x:295,y:185, phase:0};
  const rightOsc = {x:405,y:185, phase:0.1}; // slight offset
  const pulses = [];
  let coupling = 0;
  let timer = 0;

  function draw(ts) {
    timer += 16;
    // Phase coupling increases over time then resets
    coupling = 0.5+0.5*Math.sin(ts*0.00005);
    // Drive both oscillators toward same phase
    leftOsc.phase += 0.04;
    rightOsc.phase += 0.04 + (leftOsc.phase - rightOsc.phase)*coupling*0.01;

    if (timer > 500 && pulses.length < 14) {
      timer = 0;
      // Connection bridge between two sides
      const el = document.createElementNS(svgNS,'line');
      el.setAttribute('stroke-width','0.7');
      layer.appendChild(el);
      pulses.push({
        el,
        x1:leftOsc.x, y1:leftOsc.y,
        x2:rightOsc.x, y2:rightOsc.y,
        life:1, decay:0.02, coupling
      });
    }
    for (let i=pulses.length-1;i>=0;i--) {
      const p = pulses[i];
      p.life -= p.decay;
      if (p.life<=0) { p.el.remove(); pulses.splice(i,1); continue; }
      const alpha = p.life * 0.3 * p.coupling;
      p.el.setAttribute('x1',p.x1.toFixed(1)); p.el.setAttribute('y1',p.y1.toFixed(1));
      p.el.setAttribute('x2',p.x2.toFixed(1)); p.el.setAttribute('y2',p.y2.toFixed(1));
      p.el.setAttribute('stroke',`rgba(150,220,255,${alpha.toFixed(3)})`);
    }
  }
  return { draw };
})();

// FLOW_INTERRUPTION — the cost of breaking deep focus
const FLOW_INTERRUPTION = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  let flowDepth = 0;
  let interrupted = false;
  let interruptCooldown = 0;
  const shards = [];
  const pfcCenter = {x:350, y:165};

  function draw(ts) {
    interruptCooldown -= 16;
    // Flow builds slowly
    if (!interrupted) flowDepth = Math.min(1, flowDepth + 0.0004);
    else flowDepth = Math.max(0, flowDepth - 0.02);

    if (interruptCooldown <= 0) {
      interrupted = !interrupted;
      interruptCooldown = interrupted ? 1000 : 8000+Math.random()*12000;
      if (interrupted && flowDepth > 0.3) {
        // Shatter animation
        for (let k=0;k<8;k++) {
          const el = document.createElementNS(svgNS,'line');
          el.setAttribute('stroke-width','1');
          layer.appendChild(el);
          const angle = (k/8)*Math.PI*2;
          shards.push({
            el,
            x1:pfcCenter.x, y1:pfcCenter.y,
            vx:Math.cos(angle)*2, vy:Math.sin(angle)*1.5,
            len:5+Math.random()*10, life:1, decay:0.04
          });
        }
      }
    }
    for (let i=shards.length-1;i>=0;i--) {
      const s = shards[i];
      s.x1 += s.vx; s.y1 += s.vy;
      s.life -= s.decay;
      if (s.life<=0) { s.el.remove(); shards.splice(i,1); continue; }
      const alpha = s.life * 0.5;
      s.el.setAttribute('x1',s.x1.toFixed(1)); s.el.setAttribute('y1',s.y1.toFixed(1));
      s.el.setAttribute('x2',(s.x1+Math.random()*s.len-s.len/2).toFixed(1));
      s.el.setAttribute('y2',(s.y1+Math.random()*s.len-s.len/2).toFixed(1));
      s.el.setAttribute('stroke',`rgba(255,100,80,${alpha.toFixed(3)})`);
    }
  }
  return { draw };
})();

// MAST_CELL_DEGRANULATION — histamine release, allergy response
var MAST_CELL_DEGRANULATION = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Mast cells in skin and mucosa — surface regions
  const sites = [
    {x:288,y:450},{x:412,y:450},{x:288,y:600},{x:412,y:600},
    {x:350,y:580},{x:330,y:320},{x:370,y:320}
  ];
  const granules = [];
  let cooldown = 0;

  function degranulate(site) {
    for (let k=0;k<6;k++) {
      const el = document.createElementNS(svgNS,'circle');
      el.setAttribute('r','1.5');
      layer.appendChild(el);
      const angle = Math.random()*Math.PI*2;
      granules.push({
        el, x:site.x, y:site.y,
        vx:Math.cos(angle)*1.5*(0.5+Math.random()),
        vy:Math.sin(angle)*1.5*(0.5+Math.random()),
        life:1, decay:0.015
      });
    }
  }

  function draw(ts) {
    cooldown -= 16;
    if (cooldown<=0 && granules.length<25) {
      const site = sites[Math.floor(Math.random()*sites.length)];
      degranulate(site);
      cooldown = 5000+Math.random()*8000;
    }
    for (let i=granules.length-1;i>=0;i--) {
      const g = granules[i];
      g.x += g.vx; g.y += g.vy;
      g.vx *= 0.94; g.vy *= 0.94;
      g.life -= g.decay;
      if (g.life<=0) { g.el.remove(); granules.splice(i,1); continue; }
      const alpha = g.life * 0.45;
      g.el.setAttribute('cx',g.x.toFixed(1));
      g.el.setAttribute('cy',g.y.toFixed(1));
      g.el.setAttribute('fill',`rgba(255,160,100,${alpha.toFixed(3)})`);
    }
  }
  return { draw };
})();

