// XENOBIOTIC_METABOLISM — liver detoxifying foreign molecules (phase I/II)
const XENOBIOTIC_METABOLISM = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const liver = {x:362, y:752};
  const molecules = [];
  let timer = 0;

  function draw(ts) {
    timer += 16;
    if (timer > 1500 && molecules.length < 14) {
      timer = 0;
      const el = document.createElementNS(svgNS,'circle');
      el.setAttribute('r','2');
      layer.appendChild(el);
      molecules.push({
        el,
        x: liver.x+(Math.random()-0.5)*20,
        y: liver.y+(Math.random()-0.5)*15,
        phase: 0, // 0=incoming xenobiotic, 1=metabolite
        life:1, decay:0.008
      });
    }
    for (let i=molecules.length-1;i>=0;i--) {
      const m = molecules[i];
      m.life -= m.decay;
      m.phase = 1-m.life; // transforms as life depletes
      if (m.life<=0) { m.el.remove(); molecules.splice(i,1); continue; }
      // Phase I: yellow→orange (cytochrome P450 oxidation)
      // Phase II: orange→green (conjugation, water soluble)
      const r = Math.round(200+55*m.phase);
      const g = Math.round(150+50*m.phase);
      const b = Math.round(50+100*m.phase);
      const alpha = m.life * 0.45;
      m.el.setAttribute('cx',m.x.toFixed(1));
      m.el.setAttribute('cy',m.y.toFixed(1));
      m.el.setAttribute('fill',`rgba(${r},${g},${b},${alpha.toFixed(3)})`);
    }
  }
  return { draw };
})();

// APOPTOSIS — programmed cell death, clean self-sacrifice for the whole
const APOPTOSIS = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const fragments = [];
  let cooldown = 0;

  function triggerApoptosis(x,y) {
    // Cell shrinks, chromatin condenses, fragments into apoptotic bodies
    for (let k=0;k<6;k++) {
      const el = document.createElementNS(svgNS,'circle');
      el.setAttribute('r','2');
      layer.appendChild(el);
      const angle = (k/6)*Math.PI*2;
      fragments.push({
        el, x,y,
        vx:Math.cos(angle)*0.8, vy:Math.sin(angle)*0.8,
        r:2, life:1, decay:0.012
      });
    }
  }

  function draw(ts) {
    cooldown -= 16;
    if (cooldown<=0 && fragments.length<22) {
      // Can happen anywhere in the body
      const x = 300+Math.random()*100;
      const y = 300+Math.random()*700;
      triggerApoptosis(x,y);
      cooldown = 6000+Math.random()*10000;
    }
    for (let i=fragments.length-1;i>=0;i--) {
      const f = fragments[i];
      f.x += f.vx; f.y += f.vy;
      f.vx *= 0.95; f.vy *= 0.95;
      f.r = Math.max(0.5, f.r-0.02);
      f.life -= f.decay;
      if (f.life<=0) { f.el.remove(); fragments.splice(i,1); continue; }
      const alpha = f.life * 0.35;
      f.el.setAttribute('cx',f.x.toFixed(1));
      f.el.setAttribute('cy',f.y.toFixed(1));
      f.el.setAttribute('r',f.r.toFixed(1));
      f.el.setAttribute('fill',`rgba(180,200,255,${alpha.toFixed(3)})`);
    }
  }
  return { draw };
})();

// DNA_REPAIR — base excision, nucleotide excision repair enzymes at work
const DNA_REPAIR = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // DNA damage/repair happens in nucleus of cells throughout body
  const repairSites = [];
  const enzymes = [];
  let cooldown = 0;

  function initiateRepair() {
    const x = 295+Math.random()*110;
    const y = 250+Math.random()*800;
    // Show a break, then enzymes arrive and fix it
    const breakEl = document.createElementNS(svgNS,'line');
    breakEl.setAttribute('stroke','rgba(255,80,80,0)');
    breakEl.setAttribute('stroke-width','1');
    layer.appendChild(breakEl);
    repairSites.push({el:breakEl, x, y, life:1, decay:0.005, repaired:false});

    // Enzyme arrives after delay
    setTimeout(() => {
      if (enzymes.length < 8) {
        const el = document.createElementNS(svgNS,'circle');
        el.setAttribute('r','2.5');
        layer.appendChild(el);
        enzymes.push({el, x:x+(Math.random()-0.5)*20, y:y+(Math.random()-0.5)*20, tx:x, ty:y, progress:0, speed:0.025, life:1, decay:0.008});
      }
    }, 1000);
  }

  function draw(ts) {
    cooldown -= 16;
    if (cooldown<=0 && repairSites.length<8) {
      initiateRepair();
      cooldown = 5000+Math.random()*8000;
    }
    repairSites.forEach((site,i) => {
      site.life -= site.decay;
      const alpha = site.life * 0.4;
      site.el.setAttribute('x1',(site.x-4).toFixed(1)); site.el.setAttribute('y1',site.y.toFixed(1));
      site.el.setAttribute('x2',(site.x+4).toFixed(1)); site.el.setAttribute('y2',site.y.toFixed(1));
      site.el.setAttribute('stroke',`rgba(255,100,80,${alpha.toFixed(3)})`);
    });
    repairSites.splice(0, repairSites.filter(s=>s.life<=0).length);
    for (let i=repairSites.length-1;i>=0;i--) {
      if (repairSites[i].life<=0) { repairSites[i].el.remove(); repairSites.splice(i,1); }
    }
    for (let i=enzymes.length-1;i>=0;i--) {
      const e = enzymes[i];
      e.progress = Math.min(1,e.progress+e.speed);
      const t = e.progress;
      e.el.setAttribute('cx',(e.x+(e.tx-e.x)*t).toFixed(1));
      e.el.setAttribute('cy',(e.y+(e.ty-e.y)*t).toFixed(1));
      e.life -= e.decay;
      if (e.life<=0) { e.el.remove(); enzymes.splice(i,1); continue; }
      const alpha = e.life * 0.5;
      e.el.setAttribute('fill',`rgba(100,255,200,${alpha.toFixed(3)})`);
    }
  }
  return { draw };
})();

// PROTEIN_FOLDING — amino acid chain finding its final 3D shape
var PROTEIN_FOLDING = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const chains = [];
  let cooldown = 0;

  function spawnChain() {
    const x = 300+Math.random()*100;
    const y = 400+Math.random()*400;
    const chain = {nodes:[], life:1, decay:0.005};
    // Build a random chain of amino acid nodes
    let cx = x, cy = y;
    for (let k=0;k<8;k++) {
      const el = document.createElementNS(svgNS,'circle');
      el.setAttribute('r','1.5');
      layer.appendChild(el);
      chain.nodes.push({
        el, x:cx, y:cy,
        tx:x+(Math.cos(k*1.2)*6), ty:y+(Math.sin(k*0.8)*6),
        phase:Math.random()*Math.PI*2
      });
      cx += (Math.random()-0.5)*10;
      cy += (Math.random()-0.5)*8;
    }
    chains.push(chain);
  }

  function draw(ts) {
    cooldown -= 16;
    if (cooldown<=0 && chains.length<5) { spawnChain(); cooldown=4000+Math.random()*6000; }
    for (let i=chains.length-1;i>=0;i--) {
      const chain = chains[i];
      chain.life -= chain.decay;
      if (chain.life<=0) {
        chain.nodes.forEach(n=>n.el.remove());
        chains.splice(i,1); continue;
      }
      chain.nodes.forEach(node => {
        // Fold: nodes drift toward their target positions
        node.x += (node.tx - node.x)*0.02;
        node.y += (node.ty - node.y)*0.02;
        const alpha = chain.life * 0.35;
        node.el.setAttribute('cx',node.x.toFixed(1));
        node.el.setAttribute('cy',node.y.toFixed(1));
        node.el.setAttribute('fill',`rgba(255,200,120,${alpha.toFixed(3)})`);
      });
    }
  }
  return { draw };
})();


// ─── BATCH F: The Philosophy of Being Alive ─────────────────────────────────

// GRIEF_PROCESSING — the distributed pain of loss, felt in body and brain
const GRIEF_PROCESSING = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Grief activates ACC, anterior insula, and the body — especially chest
  const griefNodes = [
    {x:350,y:195}, // ACC
    {x:305,y:202},{x:395,y:202}, // insula
    {x:350,y:690}  // heart/chest
  ];
  const waves = [];
  let active = false;
  let cycleCooldown = 0;

  function draw(ts) {
    cycleCooldown -= 16;
    if (cycleCooldown <= 0) {
      active = !active;
      cycleCooldown = active ? 6000+Math.random()*10000 : 4000+Math.random()*8000;
    }
    if (active && Math.random()<0.02 && waves.length<14) {
      const node = griefNodes[Math.floor(Math.random()*griefNodes.length)];
      const el = document.createElementNS(svgNS,'circle');
      el.setAttribute('fill','none');
      el.setAttribute('stroke-width','0.8');
      layer.appendChild(el);
      waves.push({el, x:node.x, y:node.y, r:2, life:1, decay:0.012});
    }
    for (let i=waves.length-1;i>=0;i--) {
      const w = waves[i];
      w.r += active ? 0.4 : 0.2; // slower during recovery
      w.life -= w.decay;
      if (w.life<=0||w.r>22) { w.el.remove(); waves.splice(i,1); continue; }
      const alpha = w.life * 0.25;
      w.el.setAttribute('cx',w.x.toFixed(1)); w.el.setAttribute('cy',w.y.toFixed(1));
      w.el.setAttribute('r',w.r.toFixed(1));
      w.el.setAttribute('stroke',`rgba(150,160,220,${alpha.toFixed(3)})`);
    }
  }
  return { draw };
})();

// FORGIVENESS_CIRCUIT — releasing the grip of past hurt, PFC quieting amygdala
const FORGIVENESS_CIRCUIT = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // PFC sends inhibitory signal down to amygdala
  const pfc = {x:350,y:165};
  const amygdala = {x:362,y:232};
  const signals = [];
  let forgiving = false;
  let cooldown = 0;

  function draw(ts) {
    cooldown -= 16;
    if (cooldown<=0) {
      forgiving = Math.random()<0.3;
      cooldown = 4000+Math.random()*8000;
    }
    if (forgiving && signals.length<12 && Math.random()<0.04) {
      const el = document.createElementNS(svgNS,'circle');
      el.setAttribute('r','2');
      layer.appendChild(el);
      signals.push({el, sx:pfc.x+(Math.random()-0.5)*10, sy:pfc.y+(Math.random()-0.5)*8, tx:amygdala.x+(Math.random()-0.5)*6, ty:amygdala.y+(Math.random()-0.5)*5, progress:0, speed:0.02+Math.random()*0.015});
    }
    for (let i=signals.length-1;i>=0;i--) {
      const s = signals[i];
      s.progress = Math.min(1,s.progress+s.speed);
      const t = s.progress;
      s.el.setAttribute('cx',(s.sx+(s.tx-s.sx)*t).toFixed(1));
      s.el.setAttribute('cy',(s.sy+(s.ty-s.sy)*t).toFixed(1));
      const env = t<0.5?t*2:2-t*2;
      s.el.setAttribute('fill',`rgba(200,255,220,${(env*0.45).toFixed(3)})`);
      if (s.progress>=1) { s.el.remove(); signals.splice(i,1); }
    }
  }
  return { draw };
})();

// WONDER_RESPONSE — awe + curiosity merged: dopamine + default mode suppression
const WONDER_RESPONSE = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const center = {x:350,y:175};
  const sparks = [];
  let wondering = false;
  let cooldown = 0;

  function draw(ts) {
    cooldown -= 16;
    if (cooldown<=0) { wondering=!wondering; cooldown=wondering?8000+Math.random()*15000:3000+Math.random()*6000; }
    if (wondering && sparks.length<20 && Math.random()<0.06) {
      const el = document.createElementNS(svgNS,'circle');
      el.setAttribute('r','1.8');
      layer.appendChild(el);
      const angle = Math.random()*Math.PI*2;
      const r = 5+Math.random()*30;
      sparks.push({
        el,
        x:center.x+Math.cos(angle)*r,
        y:center.y+Math.sin(angle)*r,
        vx:(Math.random()-0.5)*0.3, vy:(Math.random()-0.5)*0.3,
        life:1, decay:0.01, hue:180+Math.random()*60
      });
    }
    for (let i=sparks.length-1;i>=0;i--) {
      const s = sparks[i];
      s.x += s.vx; s.y += s.vy;
      s.life -= s.decay;
      if (s.life<=0) { s.el.remove(); sparks.splice(i,1); continue; }
      const alpha = s.life * 0.35;
      s.el.setAttribute('cx',s.x.toFixed(1));
      s.el.setAttribute('cy',s.y.toFixed(1));
      s.el.setAttribute('fill',`hsla(${s.hue},80%,75%,${alpha.toFixed(3)})`);
    }
  }
  return { draw };
})();

// BOREDOM_SIGNAL — the mind seeking novelty when stimulation is absent
const BOREDOM_SIGNAL = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Default mode activates; dopamine drops; scanning behavior begins
  const scanLines = [];
  let boredom = 0;
  let timer = 0;

  function draw(ts) {
    timer += 16;
    // Boredom builds then gets relieved
    boredom = 0.5+0.5*Math.sin(ts*0.00006);

    if (timer>500 && boredom>0.4 && scanLines.length<12) {
      timer=0;
      const el = document.createElementNS(svgNS,'line');
      el.setAttribute('stroke-width','0.5');
      el.setAttribute('stroke-dasharray','3,5');
      layer.appendChild(el);
      // Restless scanning lines from brain to periphery
      const angle = Math.random()*Math.PI*2;
      const r = 20+Math.random()*50;
      scanLines.push({
        el, x1:350,y1:185,
        x2:350+Math.cos(angle)*r, y2:185+Math.sin(angle)*r,
        life:1, decay:0.015
      });
    }
    for (let i=scanLines.length-1;i>=0;i--) {
      const s = scanLines[i];
      s.life -= s.decay;
      if (s.life<=0) { s.el.remove(); scanLines.splice(i,1); continue; }
      const alpha = s.life * 0.2 * boredom;
      s.el.setAttribute('x1',s.x1.toFixed(1)); s.el.setAttribute('y1',s.y1.toFixed(1));
      s.el.setAttribute('x2',s.x2.toFixed(1)); s.el.setAttribute('y2',s.y2.toFixed(1));
      s.el.setAttribute('stroke',`rgba(180,180,200,${alpha.toFixed(3)})`);
    }
  }
  return { draw };
})();

// SHAME_CIRCUIT — social threat response, collapse inward
const SHAME_CIRCUIT = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Shame: anterior insula, ACC, and a chest/stomach collapse
  const centers = [{x:350,y:195},{x:350,y:730}];
  const contractions = [];
  let shameCooldown = 0;

  function draw(ts) {
    shameCooldown -= 16;
    if (shameCooldown<=0 && contractions.length<10) {
      shameCooldown = 12000+Math.random()*20000;
      centers.forEach(c => {
        const el = document.createElementNS(svgNS,'circle');
        el.setAttribute('fill','none');
        el.setAttribute('stroke-width','1');
        layer.appendChild(el);
        contractions.push({el, x:c.x, y:c.y, r:15, life:1, decay:0.008});
      });
    }
    for (let i=contractions.length-1;i>=0;i--) {
      const c = contractions[i];
      c.r = Math.max(3, c.r-0.3); // contracts inward
      c.life -= c.decay;
      if (c.life<=0) { c.el.remove(); contractions.splice(i,1); continue; }
      const alpha = c.life * 0.3;
      c.el.setAttribute('cx',c.x.toFixed(1)); c.el.setAttribute('cy',c.y.toFixed(1));
      c.el.setAttribute('r',c.r.toFixed(1));
      c.el.setAttribute('stroke',`rgba(180,100,160,${alpha.toFixed(3)})`);
    }
  }
  return { draw };
})();

