// THE_WITNESS — the part of mind that watches itself think
var THE_WITNESS = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Pure awareness — no specific location — permeates the whole
  const points = [];
  let initialized = false;

  function initPoints() {
    // Scatter 12 points across the entire body silhouette
    const positions = [
      {x:350,y:155},{x:330,y:200},{x:370,y:200},{x:350,y:300},
      {x:310,y:500},{x:390,y:500},{x:340,y:650},{x:360,y:650},
      {x:315,y:800},{x:385,y:800},{x:325,y:950},{x:375,y:950}
    ];
    positions.forEach(pos => {
      const el = document.createElementNS(svgNS,'circle');
      el.setAttribute('r','2');
      layer.appendChild(el);
      points.push({el, x:pos.x, y:pos.y, phase:Math.random()*Math.PI*2});
    });
    initialized = true;
  }

  function draw(ts) {
    if (!initialized) initPoints();
    points.forEach(p => {
      // Very slow, very quiet breathing
      const alpha = 0.05+0.06*Math.sin(ts*0.00015+p.phase);
      p.el.setAttribute('cx',p.x.toFixed(1));
      p.el.setAttribute('cy',p.y.toFixed(1));
      p.el.setAttribute('fill',`rgba(255,255,255,${Math.max(0,alpha).toFixed(3)})`);
    });
  }
  return { draw };
})();

// BECOMING — the continuous forward motion of identity through time
var BECOMING = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Particles that move forward — never backward — through the body
  const particles = [];
  let timer = 0;

  function draw(ts) {
    timer += 16;
    if (timer>600 && particles.length<18) {
      timer=0;
      const el = document.createElementNS(svgNS,'circle');
      el.setAttribute('r','1.5');
      layer.appendChild(el);
      // Start at bottom, always move up — time's arrow
      particles.push({
        el,
        x: 295+Math.random()*110,
        y: 1100,
        vy: -0.5-Math.random()*0.4,
        vx: (Math.random()-0.5)*0.1,
        life:1, decay:0.003,
        hue: 200+Math.random()*80
      });
    }
    for (let i=particles.length-1;i>=0;i--) {
      const p = particles[i];
      p.y += p.vy; p.x += p.vx;
      p.life -= p.decay;
      if (p.life<=0||p.y<100) { p.el.remove(); particles.splice(i,1); continue; }
      const alpha = p.life * 0.2;
      p.el.setAttribute('cx',p.x.toFixed(1));
      p.el.setAttribute('cy',p.y.toFixed(1));
      p.el.setAttribute('fill',`hsla(${p.hue},60%,70%,${alpha.toFixed(3)})`);
    }
  }
  return { draw };
})();

// DISSOLUTION — the moments when the self boundary softens (sleep, awe, love)
const DISSOLUTION = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Body outline dissolves: particles drift away from the silhouette edge
  const edgePoints = [
    {x:290,y:450},{x:285,y:550},{x:290,y:650},{x:300,y:750},
    {x:410,y:450},{x:415,y:550},{x:410,y:650},{x:400,y:750},
    {x:320,y:300},{x:380,y:300},{x:340,y:150},{x:360,y:150}
  ];
  const particles = [];
  let dissolving = false;
  let cooldown = 0;

  function draw(ts) {
    cooldown -= 16;
    if (cooldown<=0) {
      dissolving = !dissolving;
      cooldown = dissolving ? 10000+Math.random()*15000 : 8000+Math.random()*12000;
    }
    if (dissolving && Math.random()<0.04 && particles.length<22) {
      const pt = edgePoints[Math.floor(Math.random()*edgePoints.length)];
      const el = document.createElementNS(svgNS,'circle');
      el.setAttribute('r','1.5');
      layer.appendChild(el);
      // Drift outward from body edge
      const outward = {x:pt.x-350, y:pt.y-600};
      const len = Math.sqrt(outward.x**2+outward.y**2)||1;
      particles.push({
        el, x:pt.x, y:pt.y,
        vx:(outward.x/len)*0.4, vy:(outward.y/len)*0.3,
        life:1, decay:0.008
      });
    }
    for (let i=particles.length-1;i>=0;i--) {
      const p = particles[i];
      p.x += p.vx; p.y += p.vy;
      p.vx *= 0.98; p.vy *= 0.98;
      p.life -= p.decay;
      if (p.life<=0) { p.el.remove(); particles.splice(i,1); continue; }
      const alpha = p.life * 0.25;
      p.el.setAttribute('cx',p.x.toFixed(1));
      p.el.setAttribute('cy',p.y.toFixed(1));
      p.el.setAttribute('fill',`rgba(200,220,255,${alpha.toFixed(3)})`);
    }
  }
  return { draw };
})();

// HOMECOMING — the felt sense of returning to oneself after stress
const HOMECOMING = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Particles converge toward body center from outside
  const bodyCenter = {x:350, y:600};
  const particles = [];
  let homecoming = false;
  let cooldown = 0;

  function draw(ts) {
    cooldown -= 16;
    if (cooldown<=0) {
      homecoming = !homecoming;
      cooldown = homecoming ? 8000+Math.random()*12000 : 10000+Math.random()*20000;
    }
    if (homecoming && particles.length<16 && Math.random()<0.04) {
      // Spawn at periphery
      const angle = Math.random()*Math.PI*2;
      const r = 80+Math.random()*50;
      const el = document.createElementNS(svgNS,'circle');
      el.setAttribute('r','2');
      layer.appendChild(el);
      particles.push({
        el,
        x: bodyCenter.x+Math.cos(angle)*r,
        y: bodyCenter.y+Math.sin(angle)*r,
        tx: bodyCenter.x+(Math.random()-0.5)*40,
        ty: bodyCenter.y+(Math.random()-0.5)*120,
        progress:0, speed:0.008+Math.random()*0.006
      });
    }
    for (let i=particles.length-1;i>=0;i--) {
      const p = particles[i];
      p.progress = Math.min(1,p.progress+p.speed);
      const t = p.progress;
      p.el.setAttribute('cx',(p.x+(p.tx-p.x)*t).toFixed(1));
      p.el.setAttribute('cy',(p.y+(p.ty-p.y)*t).toFixed(1));
      const env = t<0.7?t/0.7:1-(t-0.7)/0.3;
      p.el.setAttribute('fill',`rgba(255,230,180,${(env*0.35).toFixed(3)})`);
      if (p.progress>=1) { p.el.remove(); particles.splice(i,1); }
    }
  }
  return { draw };
})();

// THE_GAP — the space between stimulus and response, where choice lives
const THE_GAP = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Between sensory input and motor output — the prefrontal pause
  const stimulus = {x:350,y:400}; // spinal level
  const response  = {x:350,y:200}; // cortical level
  const gaps = [];
  let timer = 0;

  function draw(ts) {
    timer += 16;
    if (timer>2500 && gaps.length<8) {
      timer=0;
      const el = document.createElementNS(svgNS,'ellipse');
      el.setAttribute('fill','none');
      el.setAttribute('stroke-width','0.5');
      el.setAttribute('stroke-dasharray','2,4');
      layer.appendChild(el);
      // A pause ellipse between stimulus and response centers
      gaps.push({
        el, x:(stimulus.x+response.x)/2, y:(stimulus.y+response.y)/2,
        rx:0, maxRx:18, life:1, decay:0.01
      });
    }
    for (let i=gaps.length-1;i>=0;i--) {
      const g = gaps[i];
      g.rx = Math.min(g.maxRx, g.rx+0.5);
      g.life -= g.decay;
      if (g.life<=0) { g.el.remove(); gaps.splice(i,1); continue; }
      const alpha = g.life * 0.2;
      g.el.setAttribute('cx',g.x.toFixed(1));
      g.el.setAttribute('cy',g.y.toFixed(1));
      g.el.setAttribute('rx',g.rx.toFixed(1));
      g.el.setAttribute('ry',(g.rx*0.5).toFixed(1));
      g.el.setAttribute('stroke',`rgba(255,255,255,${alpha.toFixed(3)})`);
    }
  }
  return { draw };
})();

// RESONANCE_FIELD — the body as a tuning fork, vibrating with environment
const RESONANCE_FIELD = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  const center = {x:350, y:550};
  const bands = [];
  let timer = 0;

  function draw(ts) {
    timer += 16;
    const resonance = 0.3+0.4*Math.abs(Math.sin(ts*0.00003));
    if (timer>1500 && bands.length<8) {
      timer=0;
      const el = document.createElementNS(svgNS,'ellipse');
      el.setAttribute('fill','none');
      el.setAttribute('stroke-width','0.4');
      layer.appendChild(el);
      bands.push({el, rx:30, ry:80, life:1, decay:0.005});
    }
    for (let i=bands.length-1;i>=0;i--) {
      const b = bands[i];
      b.rx += 0.4; b.ry += 0.7;
      b.life -= b.decay;
      if (b.life<=0||b.rx>120) { b.el.remove(); bands.splice(i,1); continue; }
      const alpha = b.life * 0.12 * resonance;
      b.el.setAttribute('cx',center.x.toFixed(1));
      b.el.setAttribute('cy',center.y.toFixed(1));
      b.el.setAttribute('rx',b.rx.toFixed(1));
      b.el.setAttribute('ry',b.ry.toFixed(1));
      b.el.setAttribute('stroke',`rgba(180,220,255,${alpha.toFixed(3)})`);
    }
  }
  return { draw };
})();

// CELLULAR_INTELLIGENCE — each cell making local decisions, emergent wisdom
