// BODY_BUDGET — predictive energy allocation (Barret's allostasis concept)
const BODY_BUDGET = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // The brain runs a body budget: spends and earns energy predictions
  const budgetCenter = {x:350,y:170};
  let budget = 0.7; // 0=depleted, 1=surplus
  let budgetTarget = 0.7;
  let timer = 0;
  const flows = [];

  function draw(ts) {
    timer += 16;
    budget += (budgetTarget-budget)*0.002;
    if (timer>3000) {
      timer=0;
      budgetTarget = 0.3+Math.random()*0.6;
    }
    if (Math.random()<budget*0.04 && flows.length<14) {
      const el = document.createElementNS(svgNS,'circle');
      el.setAttribute('r','1.5');
      layer.appendChild(el);
      const angle = Math.random()*Math.PI*2;
      flows.push({
        el, x:budgetCenter.x+(Math.random()-0.5)*20, y:budgetCenter.y+(Math.random()-0.5)*15,
        vx:Math.cos(angle)*0.3, vy:Math.sin(angle)*0.3,
        life:1, decay:0.012
      });
    }
    for (let i=flows.length-1;i>=0;i--) {
      const f = flows[i];
      f.x += f.vx; f.y += f.vy;
      f.life -= f.decay;
      if (f.life<=0) { f.el.remove(); flows.splice(i,1); continue; }
      // Color: green when in surplus, orange when depleted
      const r = Math.round(100+155*(1-budget));
      const g = Math.round(200*budget+55);
      const alpha = f.life * 0.35;
      f.el.setAttribute('cx',f.x.toFixed(1));
      f.el.setAttribute('cy',f.y.toFixed(1));
      f.el.setAttribute('fill',`rgba(${r},${g},80,${alpha.toFixed(3)})`);
    }
  }
  return { draw };
})();

