// THE_UNNAMED — the feeling you can't describe, the sensation before language
const THE_UNNAMED = (() => {
  const svgNS = 'http://www.w3.org/2000/svg';
  const layer = document.getElementById('lightLayer');
  // Doesn't map to any brain region. It's distributed. It's everything and nothing.
  const nodes = [];
  let initialized = false;

  function init() {
    for (let k=0;k<6;k++) {
      const el = document.createElementNS(svgNS,'circle');
      el.setAttribute('r','4');
      el.setAttribute('fill','none');
      el.setAttribute('stroke-width','0.3');
      layer.appendChild(el);
      nodes.push({
        el,
        x: 290+Math.random()*120,
        y: 200+Math.random()*900,
        phaseX: Math.random()*Math.PI*2,
        phaseY: Math.random()*Math.PI*2,
        speed: 0.00005+Math.random()*0.00005
      });
    }
    initialized = true;
  }

  function draw(ts) {
    if (!initialized) init();
    nodes.forEach(n => {
      n.phaseX += n.speed; n.phaseY += n.speed*1.3;
      // Very slow drift
      const dx = Math.sin(n.phaseX)*0.2;
      const dy = Math.cos(n.phaseY)*0.15;
      n.x = Math.max(285,Math.min(415,n.x+dx));
      n.y = Math.max(130,Math.min(1100,n.y+dy));
      const alpha = 0.04+0.05*Math.sin(ts*0.0001+n.phaseX);
      n.el.setAttribute('cx',n.x.toFixed(1));
      n.el.setAttribute('cy',n.y.toFixed(1));
      n.el.setAttribute('stroke',`rgba(220,220,255,${Math.max(0,alpha).toFixed(3)})`);
    });
  }
  return { draw };
})();


