// Register Batch G via secondary RAF loop
(function(){
  const batchG=['PROPRIOCEPTION','SOMATOSENSORY_CORTEX','VISUAL_CORTEX','THALAMIC_RELAY',
    'PREFRONTAL_EXECUTIVE','ANTERIOR_CINGULATE','INSULA_AWARENESS','CLAUSTRUM_CONSCIOUSNESS',
    'DEFAULT_MODE_NETWORK','MIRROR_NEURONS','MYELIN_SHEATH','ASTROCYTE_NETWORK',
    'MICROGLIA_SURVEILLANCE','NEURAL_PLASTICITY','MITOCHONDRIAL_MEMBRANE',
    'ENDOPLASMIC_RETICULUM','GOLGI_APPARATUS','EXISTENTIAL_VERTIGO',
    'COURAGE_CIRCUIT','HOPE_SIGNAL','PLAYFULNESS','SURPRISE_CIRCUIT'];
  let _lastTs=0;
  function loop(ts){
    if(ts-_lastTs>14){_lastTs=ts;batchG.forEach(name=>{const sys=window[name];if(sys&&typeof sys.draw==='function')sys.draw(ts);});}
    requestAnimationFrame(loop);
  }
  requestAnimationFrame(loop);
})();


// ── GUT_BRAIN_AXIS — vagus nerve bidirectional signals gut↔brain
const GUT_BRAIN_AXIS = (() => {
  const L = document.getElementById('lightLayer');
  const signals=[]; let t=0;
  const gut={x:350,y:760}, brain={x:350,y:290};
  function fire(fromGut){
    const s=document.createElementNS('http://www.w3.org/2000/svg','circle');
    s.setAttribute('cx',fromGut?gut.x:brain.x); s.setAttribute('cy',fromGut?gut.y:brain.y);
    s.setAttribute('r','2'); s.setAttribute('fill',fromGut?'#a5d6a7':'#80cbc4'); s.setAttribute('opacity','0.7');
    L.appendChild(s); signals.push({el:s,y:fromGut?gut.y:brain.y,dir:fromGut?-1:1,target:fromGut?brain.y:gut.y});
  }
  function draw(ts){
    t+=0.015; if(Math.random()<0.025)fire(Math.random()<0.6);
    for(let i=signals.length-1;i>=0;i--){const s=signals[i];s.y+=s.dir*1.2;s.el.setAttribute('cy',s.y.toFixed(1));if((s.dir<0&&s.y<s.target)||(s.dir>0&&s.y>s.target)){s.el.remove();signals.splice(i,1);}}
  }
  return { draw };
})();

// ── FASCIA_TENSION — connective tissue stress web
const FASCIA_TENSION = (() => {
  const L = document.getElementById('lightLayer');
  let t=0, mesh=null;
  const pts=[];
  for(let y=200;y<=1200;y+=80){ const x=350+Math.sin(y*0.02)*15; pts.push({x,y}); }
  function draw(ts){
    t+=0.006;
    if(!mesh){
      const d=pts.map((p,i)=>`${i===0?'M':'L'}${p.x.toFixed(1)},${p.y}`).join(' ');
      mesh=document.createElementNS('http://www.w3.org/2000/svg','path');
      mesh.setAttribute('d',d); mesh.setAttribute('fill','none');
      mesh.setAttribute('stroke','#e8d5a3'); mesh.setAttribute('stroke-width','0.6');
      mesh.setAttribute('opacity','0.12'); L.appendChild(mesh);
    }
    const d=pts.map((p,i)=>{const x=p.x+Math.sin(t+i*0.3)*3;return `${i===0?'M':'L'}${x.toFixed(1)},${p.y}`;}).join(' ');
    mesh.setAttribute('d',d);
  }
  return { draw };
})();

