// ── MEMBRANE_FLUIDITY — lipid bilayer phase state shimmer
const MEMBRANE_FLUIDITY = (() => {
  const L = document.getElementById('lightLayer');
  const segments=[]; let t=0, inited=false;
  function init(){
    for(let i=0;i<12;i++){
      const s=document.createElementNS('http://www.w3.org/2000/svg','line');
      const x=270+i*13,y=350+Math.sin(i)*8;
      s.setAttribute('x1',x);s.setAttribute('y1',y);s.setAttribute('x2',x);s.setAttribute('y2',y+400);
      s.setAttribute('stroke','rgba(200,220,255,0.08)');s.setAttribute('stroke-width','0.5');
      L.appendChild(s); segments.push({el:s,x,baseY:y,phase:i*0.5});
    }
    inited=true;
  }
  function draw(ts){
    if(!inited)init(); t+=0.008;
    segments.forEach(s=>{const y=s.baseY+Math.sin(t+s.phase)*4;s.el.setAttribute('y1',y.toFixed(1));const a=0.03+0.05*Math.abs(Math.sin(t*0.5+s.phase));s.el.setAttribute('stroke',`rgba(200,220,255,${a.toFixed(2)})`);});
  }
  return { draw };
})();

