// ── PHYLOGENETIC_TREE — branching ancestry at cellular level, 3.8 billion years in a spine
const PHYLOGENETIC_TREE = (() => {
  const L = document.getElementById('lightLayer');
  const NS = 'http://www.w3.org/2000/svg';
  let t = 0; const branches = [];
  const roots = [[350,1350],[350,1350],[350,1350]];
  function addBranch(x, y, angle, depth, gen) {
    if (depth <= 0) return;
    const len = 18 - gen * 2.2;
    const ex = x + Math.cos(angle) * len;
    const ey = y - Math.sin(Math.abs(angle)) * len;
    const el = document.createElementNS(NS, 'line');
    el.setAttribute('x1', x.toFixed(1)); el.setAttribute('y1', y.toFixed(1));
    el.setAttribute('x2', ex.toFixed(1)); el.setAttribute('y2', ey.toFixed(1));
    el.setAttribute('stroke', '#ce93d8');
    el.setAttribute('stroke-width', (depth * 0.25).toFixed(2));
    el.setAttribute('opacity', '0');
    L.appendChild(el);
    branches.push({ el, phase: Math.random() * Math.PI * 2 });
    addBranch(ex, ey, angle - 0.45, depth - 1, gen + 1);
    addBranch(ex, ey, angle + 0.45, depth - 1, gen + 1);
  }
  addBranch(350, 1350, Math.PI / 2, 5, 0);
  function draw(ts) {
    t = ts * 0.0003;
    branches.forEach(b => {
      const a = 0.04 + 0.18 * Math.abs(Math.sin(t * 0.12 + b.phase));
      b.el.setAttribute('opacity', a.toFixed(2));
    });
  }
  return { draw };
})();

