// ── FREEZE_RESPONSE — tonic immobility, playing dead, the oldest threat response
var FREEZE_RESPONSE = (() => {
  const L = document.getElementById('lightLayer');
  const NS = 'http://www.w3.org/2000/svg';
  let t = 0, frozen = false, triggerTime = 0;
  const overlay = document.createElementNS(NS, 'rect');
  overlay.setAttribute('x', '240'); overlay.setAttribute('y', '80');
  overlay.setAttribute('width', '220'); overlay.setAttribute('height', '1280');
  overlay.setAttribute('rx', '60');
  overlay.setAttribute('fill', '#80deea');
  overlay.setAttribute('opacity', '0'); L.appendChild(overlay);
  const particles = [];
  for (let i = 0; i < 16; i++) {
    const el = document.createElementNS(NS, 'circle');
    el.setAttribute('r', '1.2'); el.setAttribute('fill', '#80deea'); el.setAttribute('opacity', '0');
    L.appendChild(el);
    particles.push({ el, x: 280 + Math.random() * 140, y: 200 + Math.random() * 900, phase: Math.random() * Math.PI * 2, frozen: false });
  }
  function draw(ts) {
    t = ts * 0.001;
    if (!frozen && Math.random() < 0.0005) { frozen = true; triggerTime = t; }
    if (frozen && t - triggerTime > 4) frozen = false;
    const intensity = frozen ? Math.min(1, (t - triggerTime) * 0.8) : Math.max(0, 1 - (t - triggerTime) * 0.5);
    overlay.setAttribute('opacity', (intensity * 0.04).toFixed(2));
    particles.forEach(p => {
      if (!frozen) {
        p.x += (Math.random() - 0.5) * 0.3;
        p.y += (Math.random() - 0.5) * 0.15;
      }
      p.el.setAttribute('cx', p.x.toFixed(1)); p.el.setAttribute('cy', p.y.toFixed(1));
      p.el.setAttribute('opacity', (0.05 + intensity * 0.25).toFixed(2));
    });
  }
  return { draw };
})();

