// ── RESILIENCE_SPRING — post-traumatic bounce-back, growth after compression
const RESILIENCE_SPRING = (() => {
  const L = document.getElementById('lightLayer');
  const NS = 'http://www.w3.org/2000/svg';
  let t = 0; const springs = [];
  for (let i = 0; i < 8; i++) {
    const el = document.createElementNS(NS, 'path');
    el.setAttribute('fill', 'none');
    el.setAttribute('stroke', '#a5d6a7');
    el.setAttribute('stroke-width', '0.7');
    el.setAttribute('opacity', '0');
    L.appendChild(el);
    springs.push({ el, cx: 310 + Math.random() * 80, cy: 300 + i * 95, phase: Math.random() * Math.PI * 2 });
  }
  function draw(ts) {
    t = ts * 0.0004;
    springs.forEach(s => {
      const energy = 0.5 + 0.5 * Math.sin(t * 0.3 + s.phase);
      const h = 8 + energy * 14;
      const w = 5 + energy * 4;
      const segs = 4;
      let d = `M ${s.cx} ${s.cy + h}`;
      for (let j = 0; j < segs; j++) {
        const side = j % 2 === 0 ? 1 : -1;
        const nextY = s.cy + h - (j + 1) * (h * 2 / segs);
        d += ` L ${(s.cx + side * w).toFixed(1)} ${((s.cy + h - (j + 0.5) * (h * 2 / segs))).toFixed(1)} L ${s.cx} ${nextY.toFixed(1)}`;
      }
      s.el.setAttribute('d', d);
      s.el.setAttribute('opacity', (0.06 + energy * 0.28).toFixed(2));
    });
  }
  return { draw };
})();

