// ── LANGUAGE_EMERGENCE — the moment syntax became recursive, 100,000 years ago
const LANGUAGE_EMERGENCE = (() => {
  const L = document.getElementById('lightLayer');
  const NS = 'http://www.w3.org/2000/svg';
  let t = 0; const nodes = []; const edges = [];
  const SYMS = 6;
  const cx = 350, cy = 155;
  for (let i = 0; i < SYMS; i++) {
    const angle = (i / SYMS) * Math.PI * 2;
    const r = 22;
    const nx = cx + Math.cos(angle) * r;
    const ny = cy + Math.sin(angle) * r * 0.55;
    const el = document.createElementNS(NS, 'circle');
    el.setAttribute('r', '2.5'); el.setAttribute('cx', nx.toFixed(1)); el.setAttribute('cy', ny.toFixed(1));
    el.setAttribute('fill', '#ffd54f'); el.setAttribute('opacity', '0.2'); L.appendChild(el);
    nodes.push({ el, x: nx, y: ny, phase: i * 0.6 });
  }
  for (let i = 0; i < SYMS; i++) {
    const j = (i + 1) % SYMS;
    const el = document.createElementNS(NS, 'line');
    el.setAttribute('stroke', '#ffd54f'); el.setAttribute('stroke-width', '0.5');
    el.setAttribute('opacity', '0'); L.appendChild(el);
    edges.push({ el, a: nodes[i], b: nodes[j], phase: i * 0.4 });
  }
  function draw(ts) {
    t = ts * 0.0005;
    nodes.forEach(n => {
      const pulse = 0.12 + 0.2 * Math.abs(Math.sin(t * 0.4 + n.phase));
      n.el.setAttribute('opacity', pulse.toFixed(2));
    });
    edges.forEach(e => {
      const syn = Math.abs(Math.sin(t * 0.25 + e.phase));
      e.el.setAttribute('x1', e.a.x.toFixed(1)); e.el.setAttribute('y1', e.a.y.toFixed(1));
      e.el.setAttribute('x2', e.b.x.toFixed(1)); e.el.setAttribute('y2', e.b.y.toFixed(1));
      e.el.setAttribute('opacity', (syn * 0.3).toFixed(2));
    });
  }
  return { draw };
})();

// ── SYMBOLIC_THOUGHT — abstract representation capacity, the big leap
const SYMBOLIC_THOUGHT = (() => {
  const L = document.getElementById('lightLayer');
  const NS = 'http://www.w3.org/2000/svg';
  let t = 0; const symbols = [];
  const SHAPES = ['circle', 'rect', 'polygon'];
  for (let i = 0; i < 12; i++) {
    const type = SHAPES[i % SHAPES.length];
    const el = document.createElementNS(NS, type);
    if (type === 'circle') { el.setAttribute('r', '3'); el.setAttribute('fill', 'none'); el.setAttribute('stroke', '#ce93d8'); el.setAttribute('stroke-width', '0.6'); }
    else if (type === 'rect') { el.setAttribute('width', '6'); el.setAttribute('height', '6'); el.setAttribute('fill', 'none'); el.setAttribute('stroke', '#ce93d8'); el.setAttribute('stroke-width', '0.6'); }
    else { el.setAttribute('points', '0,-4 3.5,2 -3.5,2'); el.setAttribute('fill', 'none'); el.setAttribute('stroke', '#ce93d8'); el.setAttribute('stroke-width', '0.6'); }
    el.setAttribute('opacity', '0'); L.appendChild(el);
    symbols.push({ el, type, x: 290 + Math.random() * 120, y: 180 + i * 95, phase: Math.random() * Math.PI * 2 });
  }
  function draw(ts) {
    t = ts * 0.0004;
    symbols.forEach(s => {
      const glow = 0.06 + 0.28 * Math.abs(Math.sin(t * 0.2 + s.phase));
      if (s.type === 'circle') { s.el.setAttribute('cx', s.x.toFixed(1)); s.el.setAttribute('cy', s.y.toFixed(1)); }
      else if (s.type === 'rect') { s.el.setAttribute('x', (s.x - 3).toFixed(1)); s.el.setAttribute('y', (s.y - 3).toFixed(1)); }
      else { s.el.setAttribute('transform', `translate(${s.x.toFixed(1)},${s.y.toFixed(1)})`); }
      s.el.setAttribute('opacity', glow.toFixed(2));
    });
  }
  return { draw };
})();

