// ── SOCIAL_BRAIN_HYPOTHESIS — intelligence driven by social complexity
const SOCIAL_BRAIN_HYPOTHESIS = (() => {
  const L = document.getElementById('lightLayer');
  const NS = 'http://www.w3.org/2000/svg';
  let t = 0; const agents = []; const connections = [];
  const N = 8;
  for (let i = 0; i < N; i++) {
    const angle = (i / N) * Math.PI * 2;
    const r = 28;
    const el = document.createElementNS(NS, 'circle');
    el.setAttribute('r', '2.5'); el.setAttribute('fill', '#ffd54f'); el.setAttribute('opacity', '0.15');
    L.appendChild(el);
    agents.push({ el, angle, r, phase: i * 0.8, cx: 350, cy: 155 });
  }
  for (let i = 0; i < N; i++) {
    for (let j = i + 1; j < N; j++) {
      if (Math.random() > 0.5) {
        const el = document.createElementNS(NS, 'line');
        el.setAttribute('stroke', '#ffd54f'); el.setAttribute('stroke-width', '0.4'); el.setAttribute('opacity', '0');
        L.appendChild(el);
        connections.push({ el, a: agents[i], b: agents[j], phase: (i + j) * 0.3 });
      }
    }
  }
  function draw(ts) {
    t = ts * 0.0004;
    agents.forEach(a => {
      const x = a.cx + Math.cos(a.angle + t * 0.08) * a.r;
      const y = a.cy + Math.sin(a.angle + t * 0.08) * a.r * 0.55;
      a.el.setAttribute('cx', x.toFixed(1)); a.el.setAttribute('cy', y.toFixed(1));
      a._cx = x; a._cy = y;
      a.el.setAttribute('opacity', (0.1 + 0.18 * Math.abs(Math.sin(t * 0.3 + a.phase))).toFixed(2));
    });
    connections.forEach(c => {
      c.el.setAttribute('x1', c.a._cx.toFixed(1)); c.el.setAttribute('y1', c.a._cy.toFixed(1));
      c.el.setAttribute('x2', c.b._cx.toFixed(1)); c.el.setAttribute('y2', c.b._cy.toFixed(1));
      c.el.setAttribute('opacity', (0.04 + 0.15 * Math.abs(Math.sin(t * 0.2 + c.phase))).toFixed(2));
    });
  }
  return { draw };
})();

