const QUANTUM_TUNNELING = (() => {
  let _last = 0, particles = [];
  for(let i=0;i<18;i++) particles.push({x:Math.random(),y:Math.random(),phase:Math.random()*Math.PI*2,speed:0.3+Math.random()*0.4});
  function draw(ts) {
    if(ts-_last<60) return; _last=ts;
    const el=document.getElementById('lightLayer'); if(!el) return;
    const W=window.innerWidth,H=window.innerHeight,cx=W/2;
    let h='';
    particles.forEach(p=>{
      p.phase+=p.speed*0.04;
      const jitter=(Math.random()-0.5)*60;
      const x=cx-80+p.x*160+jitter*(Math.sin(p.phase*3)>0.95?1:0);
      const y=H*0.1+p.y*H*0.8;
      const a=0.1+0.25*Math.abs(Math.sin(p.phase));
      h+=`<circle cx="${x}" cy="${y}" r="2" fill="#4af" opacity="${a.toFixed(2)}"/>`;
    });
    let d=el.querySelector('.qt-layer'); if(!d){d=document.createElementNS('http://www.w3.org/2000/svg','g');d.classList.add('qt-layer');el.appendChild(d);}
    d.innerHTML=h;
  }
  return {draw};
})();

