      h+=`<circle cx="${p.x.toFixed(1)}" cy="${p.y.toFixed(1)}" r="6" fill="none" stroke="#4af" stroke-width="0.6" opacity="${(p.life*0.2).toFixed(2)}"/>`;
      return true;
