const COLLECTIVE_EFFERVESCENCE = (() => {
  let _last=0, t=0, bubbles=[];
  for(let i=0;i<20;i++) bubbles.push({x:0.3+Math.random()*0.4,y:0.5+Math.random()*0.4,vy:-0.001-Math.random()*0.002,size:3+Math.random()*5,life:Math.random()});
  function draw(ts) {
    if(ts-_last<45) return; _last=ts; t+=0.025;
    const el=document.getElementById('lightLayer'); if(!el) return;
    const W=window.innerWidth,H=window.innerHeight,cx=W/2;
    let h='';
    bubbles.forEach(b=>{
      b.y+=b.vy; b.life+=0.006;
      if(b.y<0.1||b.life>1){b.y=0.7+Math.random()*0.2;b.life=0;b.x=0.3+Math.random()*0.4;}
      const x=cx+(b.x-0.5)*160+5*Math.sin(t+b.size);
      const y=H*b.y;
      const a=b.life<0.5?b.life*0.25:(1-b.life)*0.25;
      h+=`<circle cx="${x.toFixed(1)}" cy="${y.toFixed(1)}" r="${b.size}" fill="none" stroke="#4f8" stroke-width="0.6" opacity="${a.toFixed(2)}"/>`;
    });
    let d=el.querySelector('.ce-layer'); if(!d){d=document.createElementNS('http://www.w3.org/2000/svg','g');d.classList.add('ce-layer');el.appendChild(d);}
    d.innerHTML=h;
  }
  return {draw};
})();

const SOCIAL_PAIN_NETWORK = (() => {
  let _last=0, t=0;
  function draw(ts) {
    if(ts-_last<70) return; _last=ts; t+=0.018;
    const el=document.getElementById('lightLayer'); if(!el) return;
    const W=window.innerWidth,H=window.innerHeight,cx=W/2;
    const pain=0.3+0.7*Math.pow(Math.max(0,Math.sin(t*0.2)),2);
    let h='';
    const sites=[[cx,H*0.15],[cx-20,H*0.4],[cx+20,H*0.4],[cx,H*0.55]];
    sites.forEach(s=>{
      const r=5+8*pain;
      h+=`<circle cx="${s[0].toFixed(1)}" cy="${s[1].toFixed(1)}" r="${r.toFixed(1)}" fill="none" stroke="#f44" stroke-width="1" opacity="${(pain*0.2).toFixed(2)}"/>`;
    });
    for(let i=0;i<sites.length;i++) for(let j=i+1;j<sites.length;j++){
      h+=`<line x1="${sites[i][0].toFixed(1)}" y1="${sites[i][1].toFixed(1)}" x2="${sites[j][0].toFixed(1)}" y2="${sites[j][1].toFixed(1)}" stroke="#f44" stroke-width="0.5" opacity="${(pain*0.08).toFixed(3)}"/>`;
    }
    let d=el.querySelector('.spn-layer'); if(!d){d=document.createElementNS('http://www.w3.org/2000/svg','g');d.classList.add('spn-layer');el.appendChild(d);}
    d.innerHTML=h;
  }
  return {draw};
})();

const RECIPROCITY_ENGINE = (() => {
  let _last=0, t=0, exchanges=[];
  for(let i=0;i<6;i++) exchanges.push({from:{x:0.3+Math.random()*0.15,y:0.3+Math.random()*0.4},to:{x:0.55+Math.random()*0.15,y:0.3+Math.random()*0.4},prog:Math.random(),speed:0.008+Math.random()*0.008,dir:1});
  function draw(ts) {
    if(ts-_last<55) return; _last=ts; t+=0.02;
    const el=document.getElementById('lightLayer'); if(!el) return;
    const W=window.innerWidth,H=window.innerHeight,cx=W/2;
    let h='';
    exchanges.forEach(e=>{
      e.prog+=e.speed*e.dir;
      if(e.prog>=1){e.prog=1;e.dir=-1;} else if(e.prog<=0){e.prog=0;e.dir=1;}
      const x=cx+((e.from.x+(e.to.x-e.from.x)*e.prog)-0.5)*200;
      const y=H*(e.from.y+(e.to.y-e.from.y)*e.prog);
      const a=0.1+0.15*Math.sin(e.prog*Math.PI);
      h+=`<circle cx="${x.toFixed(1)}" cy="${y.toFixed(1)}" r="2.5" fill="#4af" opacity="${a.toFixed(2)}"/>`;
    });
    let d=el.querySelector('.re-layer'); if(!d){d=document.createElementNS('http://www.w3.org/2000/svg','g');d.classList.add('re-layer');el.appendChild(d);}
    d.innerHTML=h;
  }
  return {draw};
})();

const DNA_REPAIR_MECHANISM = (() => {
  let _last=0, t=0, repairs=[];
  function draw(ts) {
    if(ts-_last<55) return; _last=ts; t+=0.025;
    const el=document.getElementById('lightLayer'); if(!el) return;
    const W=window.innerWidth,H=window.innerHeight,cx=W/2;
    if(Math.random()<0.03) repairs.push({x:cx+(Math.random()-0.5)*100,y:H*(0.15+Math.random()*0.7),life:1});
    let h='';
    repairs=repairs.filter(r=>{
      r.life-=0.02;
      if(r.life<=0) return false;
      const s=8*(1-r.life*0.5);
      h+=`<line x1="${(r.x-s).toFixed(1)}" y1="${r.y.toFixed(1)}" x2="${(r.x+s).toFixed(1)}" y2="${r.y.toFixed(1)}" stroke="#4f8" stroke-width="1.5" opacity="${(r.life*0.3).toFixed(2)}"/>`;
      return true;
    });
    let d=el.querySelector('.drm-layer'); if(!d){d=document.createElementNS('http://www.w3.org/2000/svg','g');d.classList.add('drm-layer');el.appendChild(d);}
    d.innerHTML=h;
  }
  return {draw};
})();

