const CYTOKINE_STORM = (() => {
  let _last = 0, particles = [], active = false, stormT = 0;
  function draw(ts) {
    if (ts - _last < 35) return; _last = ts;
    const svg = document.getElementById('lightLayer');
    if (!svg) return;
    const cx = window.innerWidth / 2, cy = window.innerHeight * 0.43;
    let el = document.getElementById('cytokine_s');
    if (!el) { el = document.createElementNS('http://www.w3.org/2000/svg','g'); el.id='cytokine_s'; svg.appendChild(el); }
    el.innerHTML = '';
    if (Math.random() < 0.002) { active = true; stormT = 0; particles = []; }
    if (active) {
      stormT += 0.03;
      if (stormT < 1) { for (let i = 0; i < 3; i++) particles.push({x:cx,y:cy,vx:(Math.random()-0.5)*3,vy:(Math.random()-0.5)*3,life:1}); }
      if (stormT > 3) { active = false; particles = []; }
    }
    particles = particles.filter(p => { p.x+=p.vx; p.y+=p.vy; p.life-=0.02; return p.life > 0; });
    particles.forEach(p => {
      const c = document.createElementNS('http://www.w3.org/2000/svg','circle');
      c.setAttribute('cx', p.x); c.setAttribute('cy', p.y); c.setAttribute('r', 2);
      c.setAttribute('fill', `rgba(255,80,100,${p.life * 0.3})`);
      el.appendChild(c);
    });
  }
  return { draw };
})();

