const KUNDALINI_RISE = (() => {
  let _last = 0;
  return { draw(ts) {
    if (ts - _last < 40) return; _last = ts;
    const svg = document.getElementById('lightLayer'); if (!svg) return;
    const cx = window.innerWidth / 2, baseY = window.innerHeight * 0.92;
    const topY = window.innerHeight * 0.12;
    const id = '_kund';
    const el = document.getElementById(id) || (() => { const e = document.createElementNS('http://www.w3.org/2000/svg','path'); e.id=id; svg.appendChild(e); return e; })();
    let d = `M ${cx} ${baseY}`;
    const segs = 16;
    for (let i = 1; i <= segs; i++) {
      const t = i / segs;
      const y = baseY - t * (baseY - topY);
      const amp = (1 - t) * 18 * Math.sin(t * Math.PI);
      const x = cx + Math.sin(ts * 0.003 + t * 12) * amp;
      d += ` L ${x} ${y}`;
    }
    el.setAttribute('d', d); el.setAttribute('fill','none');
    el.setAttribute('stroke','#f44'); el.setAttribute('stroke-width','1.5'); el.setAttribute('opacity', 0.3);
  }};
})();

