(function(){
  const _batch17 = [
    'BROCA_PULSE','WERNICKE_DECODE','PHONEME_CASCADE','SYNTAX_WEAVE','METAPHOR_BRIDGE',
    'NARRATIVE_THREAD','INNER_SPEECH','SUBVOCALIZATION','SEMANTIC_FIELD','PRAGMATIC_CONTEXT',
    'BASAL_GANGLIA_LOOP','CEREBELLUM_TIMING','MOTOR_SEQUENCE','GAIT_RHYTHM','GESTURE_FIELD',
    'POSTURAL_SWAY','FINE_MOTOR_SPARK','GRIP_FORCE','BALLISTIC_MOVEMENT','MOTOR_LEARNING_ARC',
    'EMBRYONIC_FOLD','FETAL_HEARTBEAT','BIRTH_SURGE','INFANT_BOND','CHILDHOOD_WONDER',
    'ADOLESCENT_FLUX','ADULT_CONSOLIDATION','ELDER_WISDOM','DEATH_APPROACH','REBIRTH_POTENTIAL',
    'GLYCOLYSIS_WAVE','KREBS_CYCLE','OXIDATIVE_PHOSPHORYLATION','GLUCOSE_TIDE','KETONE_SHIFT',
    'INSULIN_SURGE','GLUCAGON_CALL','FAT_MOBILIZATION','THERMOGENESIS','BASAL_METABOLIC_FIELD',
    'KUNDALINI_RISE','CHAKRA_RESONANCE','MERKABA_SPIN','AURA_FIELD','THIRD_EYE_PULSE',
    'CROWN_OPENING','HEART_CHAKRA_BLOOM','SACRED_GEOMETRY','FIBONACCI_SPIRAL','GOLDEN_RATIO_PULSE'
  ];
  let _lt = 0;
  function loop(ts) {
    if (ts - _lt > 14) {
      _lt = ts;
      _batch17.forEach(n => { const s = window[n]; if (s && typeof s.draw === 'function') s.draw(ts); });
    }
    requestAnimationFrame(loop);
  }
  requestAnimationFrame(loop);
})();



