    const cx=window.innerWidth/2,cy=window.innerHeight*0.55;
    const t=ts*0.0003,r=60+Math.sin(t)*20;
    const el=document.createElementNS('http://www.w3.org/2000/svg','ellipse');
    el.setAttribute('cx',cx+Math.cos(t*0.7)*30);el.setAttribute('cy',cy);
    el.setAttribute('rx',r);el.setAttribute('ry',18+Math.cos(t)*6);
    el.setAttribute('fill','none');el.setAttribute('stroke','#a4f');
    el.setAttribute('stroke-width','1');el.setAttribute('opacity',0.12+Math.abs(Math.sin(t*2))*0.15);
