// CORONARY_FLOW — pulsing coronary artery rings around heart
const CORONARY_FLOW = (() => {
  let _last = 0;
  function draw(ts) {
    if (ts - _last < 60) return; _last = ts;
    const svg = document.getElementById('lightLayer'); if (!svg) return;
    const cx = window.innerWidth / 2, cy = window.innerHeight * 0.38;
    const p = (Math.sin(ts * 0.0025) + 1) / 2;
    let el = document.getElementById('_coronary_flow');
    if (!el) { el = document.createElementNS('http://www.w3.org/2000/svg','ellipse'); el.id='_coronary_flow'; svg.appendChild(el); }
    el.setAttribute('cx', cx); el.setAttribute('cy', cy);
    el.setAttribute('rx', 22 + p * 6); el.setAttribute('ry', 18 + p * 4);
    el.setAttribute('fill','none'); el.setAttribute('stroke','#f44');
    el.setAttribute('stroke-width', 1.2 + p * 1.8); el.setAttribute('opacity', 0.12 + p * 0.18);
  }
  return { draw };
})();

// CARDIAC_OUTPUT — radial burst from heart each beat
const CARDIAC_OUTPUT = (() => {
  let _last = 0, _beat = 0;
  function draw(ts) {
    if (ts - _last < 30) return; _last = ts;
    const svg = document.getElementById('lightLayer'); if (!svg) return;
    const cx = window.innerWidth / 2, cy = window.innerHeight * 0.38;
    const beat = Math.floor(ts / 857) % 2;
    if (beat !== _beat) { _beat = beat;
      for (let i = 0; i < 6; i++) {
        const a = (i / 6) * Math.PI * 2;
        let ln = document.createElementNS('http://www.w3.org/2000/svg','line');
        ln.setAttribute('x1', cx); ln.setAttribute('y1', cy);
        ln.setAttribute('x2', cx + Math.cos(a) * 32); ln.setAttribute('y2', cy + Math.sin(a) * 32);
        ln.setAttribute('stroke','#fa4'); ln.setAttribute('stroke-width','1.5'); ln.setAttribute('opacity','0.22');
        ln.style.transition = 'opacity 0.6s'; svg.appendChild(ln);
        setTimeout(() => { if (ln.parentNode) ln.parentNode.removeChild(ln); }, 700);
      }
    }
  }
  return { draw };
})();

// STROKE_VOLUME — expanding ring per heartbeat
const STROKE_VOLUME = (() => {
  let _last = 0, _rings = [];
  function draw(ts) {
    if (ts - _last < 20) return; _last = ts;
    const svg = document.getElementById('lightLayer'); if (!svg) return;
    const cx = window.innerWidth / 2, cy = window.innerHeight * 0.38;
    if (Math.floor(ts / 860) !== Math.floor((ts - 20) / 860)) {
      let c = document.createElementNS('http://www.w3.org/2000/svg','circle');
      c._born = ts; c.setAttribute('cx', cx); c.setAttribute('cy', cy);
      c.setAttribute('fill','none'); c.setAttribute('stroke','#4af'); c.setAttribute('stroke-width','1');
      svg.appendChild(c); _rings.push(c);
    }
    _rings = _rings.filter(c => {
      const age = ts - c._born, r = age * 0.05;
      if (age > 1200) { if (c.parentNode) c.parentNode.removeChild(c); return false; }
      c.setAttribute('r', r); c.setAttribute('opacity', Math.max(0, 0.25 - age * 0.0002));
      return true;
    });
  }
  return { draw };
})();

// EJECTION_FRACTION — arc meter near heart
const EJECTION_FRACTION = (() => {
  let _last = 0;
  function draw(ts) {
    if (ts - _last < 80) return; _last = ts;
    const svg = document.getElementById('lightLayer'); if (!svg) return;
    const cx = window.innerWidth / 2 + 50, cy = window.innerHeight * 0.36;
    const ef = 0.55 + Math.sin(ts * 0.0004) * 0.1;
    const angle = ef * Math.PI; const r = 18;
    const x2 = cx + r * Math.cos(Math.PI - angle), y2 = cy - r * Math.sin(Math.PI - angle);
    let p = document.getElementById('_ejection_arc');
    if (!p) { p = document.createElementNS('http://www.w3.org/2000/svg','path'); p.id='_ejection_arc'; svg.appendChild(p); }
    p.setAttribute('d', `M ${cx - r} ${cy} A ${r} ${r} 0 0 1 ${x2} ${y2}`);
    p.setAttribute('fill','none'); p.setAttribute('stroke','#4f8'); p.setAttribute('stroke-width','2'); p.setAttribute('opacity','0.2');
  }
  return { draw };
})();

// PRELOAD_SIGNAL — diastolic fill dots drifting toward heart
const PRELOAD_SIGNAL = (() => {
  let _last = 0, _dots = [];
  function draw(ts) {
    if (ts - _last < 40) return; _last = ts;
    const svg = document.getElementById('lightLayer'); if (!svg) return;
    const cx = window.innerWidth / 2, cy = window.innerHeight * 0.38;
    if (_dots.length < 6 && Math.random() < 0.15) {
      const angle = Math.random() * Math.PI * 2;
      const dist = 60 + Math.random() * 40;
      const d = { x: cx + Math.cos(angle) * dist, y: cy + Math.sin(angle) * dist, born: ts };
      const el = document.createElementNS('http://www.w3.org/2000/svg','circle');
      el.setAttribute('r','2'); el.setAttribute('fill','#a4f'); el.setAttribute('opacity','0.3');
      svg.appendChild(el); d.el = el; _dots.push(d);
    }
    _dots = _dots.filter(d => {
      const age = ts - d.born, t = Math.min(age / 800, 1);
      d.el.setAttribute('cx', d.x + (cx - d.x) * t); d.el.setAttribute('cy', d.y + (cy - d.y) * t);
      d.el.setAttribute('opacity', 0.3 * (1 - t));
      if (t >= 1) { if (d.el.parentNode) d.el.parentNode.removeChild(d.el); return false; }
      return true;
    });
  }
  return { draw };
})();

