    const svg = document.getElementById('lightLayer'); if (!svg) return;
    const cx = window.innerWidth / 2, cy = window.innerHeight * 0.42;
    const breath = (Math.sin(ts * 0.0008) + 1) / 2;
    for (let side = -1; side <= 1; side += 2) {
      const id = '_tidal_lung' + (side < 0 ? 'L' : 'R');
      let el = document.getElementById(id);
      if (!el) { el = document.createElementNS('http://www.w3.org/2000/svg','ellipse'); el.id=id; svg.appendChild(el); }
      el.setAttribute('cx', cx + side * (28 + breath * 4)); el.setAttribute('cy', cy);
      el.setAttribute('rx', 14 + breath * 5); el.setAttribute('ry', 24 + breath * 8);
      el.setAttribute('fill','#4af'); el.setAttribute('opacity', 0.06 + breath * 0.1);
    }
