const BACKPROPAGATION_WAVE = (() => {
  let _last = 0;
  function draw(ts) {
    if (ts - _last < 55) return; _last = ts;
    const svg = document.getElementById('lightLayer');
    const ox = window.innerWidth * 0.08, oy = window.innerHeight * 0.42;
    const layers = [4, 6, 4];
    let prevX = [];
    layers.forEach((count, li) => {
      const x = ox + li * 25;
      const currX = [];
      for (let n = 0; n < count; n++) {
        const y = oy + (n - count / 2) * 10;
        currX.push({ x, y });
        if (li > 0) {
          prevX.forEach(p => {
            const active = Math.sin(ts * 0.001 + p.y * 0.05 + y * 0.05) > 0.2;
            if (!active) return;
            const line = document.createElementNS('http://www.w3.org/2000/svg','line');
            line.setAttribute('x1', p.x); line.setAttribute('y1', p.y);
            line.setAttribute('x2', x); line.setAttribute('y2', y);
            line.setAttribute('stroke', '#a4f'); line.setAttribute('stroke-width', '0.5');
            line.setAttribute('opacity', '0.1');
            svg.appendChild(line);
            setTimeout(() => line.remove(), 400);
          });
        }
        const dot = document.createElementNS('http://www.w3.org/2000/svg','circle');
        dot.setAttribute('cx', x); dot.setAttribute('cy', y); dot.setAttribute('r', '2');
        dot.setAttribute('fill', '#a4f'); dot.setAttribute('opacity', '0.18');
        svg.appendChild(dot);
        setTimeout(() => dot.remove(), 400);
      }
      prevX = currX;
    });
  }
  return { draw };
})();

