// ── AUDITORY MEMORY ECHO ──────────────────────────────────────────────────────
const AUDITORY_MEMORY_ECHO = (() => {
  let _last = 0, phase = 0;
  function draw(ts) {
    if (ts - _last < 60) return; _last = ts;
    const svg = document.getElementById('lightLayer');
    if (!svg) return;
    const cx = window.innerWidth * 0.38, cy = window.innerHeight * 0.18;
    phase += 0.04;
    let el = document.getElementById('aud_echo');
    if (!el) { el = document.createElementNS('http://www.w3.org/2000/svg','g'); el.id='aud_echo'; svg.appendChild(el); }
    let h = '';
    for (let i = 0; i < 5; i++) {
      const r = 14 + i * 9 + Math.sin(phase - i * 0.6) * 4;
      const op = (0.22 - i * 0.03) * Math.abs(Math.sin(phase - i * 0.5));
      h += `<circle cx="${cx}" cy="${cy}" r="${r}" fill="none" stroke="#4af" stroke-width="1.2" opacity="${op.toFixed(3)}"/>`;
    }
    el.innerHTML = h;
  }
  return { draw };
})();

