// ── OBSERVER INFLUENCE ───────────────────────────────────────────────────────
const OBSERVER_INFLUENCE = (() => {
  let _last = 0;
  return { draw(ts) {
    if (ts - _last < 55) return; _last = ts;
    const canvas = document.getElementById('mainCanvas');
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const cx = window.innerWidth*0.15, cy = window.innerHeight*0.3;
    const t = ts*0.001;
    const wave = Math.sin(t*1.8)*15;
    ctx.beginPath();
    for (let x=0; x<60; x++) {
      const y = cy + Math.sin((x/60)*Math.PI*3 + t*2) * (5+wave*0.3);
      x===0 ? ctx.moveTo(cx+x, y) : ctx.lineTo(cx+x, y);
    }
    ctx.strokeStyle = `rgba(180,180,255,${0.12+0.08*Math.sin(t*1.2)})`; ctx.lineWidth=1; ctx.stroke();
  }};
})();

