// ── ONE_THOUSAND — THE MILESTONE SYSTEM ───────────────────────────────────
const ONE_THOUSAND = (() => {
  let _last = 0;
  let _phase = 0;
  let _celebrating = false;
  let _celebStart = 0;
  let _lastCelebCheck = 0;
  const PERIOD = 30000; // trigger celebration every 30 seconds

  function draw(ts) {
    if (ts - _last < 16) return; _last = ts;
    const cvs = document.getElementById('mainCanvas');
    const svg = document.getElementById('lightLayer');
    if (!cvs || !svg) return;
    const ctx = cvs.getContext('2d');
    const W = window.innerWidth, H = window.innerHeight;
    const cx = W / 2, cy = H / 2;

    // Trigger celebration cycle
    if (!_celebrating && ts - _lastCelebCheck > PERIOD) {
      _celebrating = true;
      _celebStart = ts;
      _lastCelebCheck = ts;
    }

    const t = (ts * 0.001);

    if (_celebrating) {
      const elapsed = ts - _celebStart;
      const dur = 6000;
      if (elapsed > dur) {
        _celebrating = false;
      } else {
        const progress = elapsed / dur;
        const swell = Math.sin(progress * Math.PI);

        // Golden bloom expanding from center
        ctx.save();
        const bloomR = swell * Math.min(W, H) * 0.55;
        const alpha = swell * 0.18;
        const g = ctx.createRadialGradient(cx, cy, 0, cx, cy, bloomR);
        g.addColorStop(0, `rgba(255,220,80,${alpha * 2.5})`);
        g.addColorStop(0.3, `rgba(255,180,40,${alpha * 1.2})`);
        g.addColorStop(0.7, `rgba(200,120,20,${alpha * 0.5})`);
        g.addColorStop(1, 'rgba(200,120,20,0)');
        ctx.fillStyle = g;
        ctx.beginPath();
        ctx.arc(cx, cy, bloomR, 0, Math.PI * 2);
        ctx.fill();

        // Radiating golden spokes
        ctx.strokeStyle = `rgba(255,230,100,${swell * 0.25})`;
        ctx.lineWidth = 1.2;
        for (let i = 0; i < 24; i++) {
          const a = (i / 24) * Math.PI * 2 + t * 0.4;
          const r1 = bloomR * 0.15;
          const r2 = bloomR * (0.5 + Math.sin(t * 3 + i * 0.5) * 0.15);
          ctx.beginPath();
          ctx.moveTo(cx + Math.cos(a) * r1, cy + Math.sin(a) * r1);
          ctx.lineTo(cx + Math.cos(a) * r2, cy + Math.sin(a) * r2);
          ctx.stroke();
        }

        // Orbiting golden rings
        for (let i = 0; i < 5; i++) {
          const ringR = bloomR * (0.2 + i * 0.15);
          const ringAlpha = swell * (0.12 - i * 0.015);
          ctx.strokeStyle = `rgba(255,210,60,${ringAlpha})`;
          ctx.lineWidth = 1.5 - i * 0.2;
          ctx.beginPath();
          ctx.arc(cx, cy, ringR, 0, Math.PI * 2);
          ctx.stroke();
        }

        ctx.restore();

        // SVG golden particles burst
        if (Math.random() < swell * 0.6) {
          const angle = Math.random() * Math.PI * 2;
          const dist = bloomR * (0.1 + Math.random() * 0.8);
          const star = document.createElementNS('http://www.w3.org/2000/svg','circle');
          star.setAttribute('cx', cx + Math.cos(angle) * dist);
          star.setAttribute('cy', cy + Math.sin(angle) * dist);
          star.setAttribute('r', 1.5 + Math.random() * 3);
          star.setAttribute('fill', `rgba(255,${200 + Math.floor(Math.random()*55)},${50 + Math.floor(Math.random()*80)},${0.3 + swell * 0.3})`);
          svg.appendChild(star);
          const lifetime = 500 + Math.random() * 1000;
          setTimeout(() => { if (star.parentNode) star.parentNode.removeChild(star); }, lifetime);
        }

        // Central luminous core
        ctx.save();
        const coreAlpha = swell * 0.45;
        const coreG = ctx.createRadialGradient(cx, cy, 0, cx, cy, 50);
        coreG.addColorStop(0, `rgba(255,255,220,${coreAlpha})`);
        coreG.addColorStop(0.5, `rgba(255,210,80,${coreAlpha * 0.5})`);
        coreG.addColorStop(1, 'rgba(255,180,40,0)');
        ctx.fillStyle = coreG;
        ctx.beginPath();
        ctx.arc(cx, cy, 50, 0, Math.PI * 2);
        ctx.fill();
        ctx.restore();
      }
    }

    // Ambient persistent glow — always present, gentle golden heartbeat
    const ambient = 0.035 + Math.sin(t * 0.4) * 0.018 + Math.sin(t * 1.1) * 0.012;
    ctx.save();
    ctx.globalAlpha = ambient;
    const ambG = ctx.createRadialGradient(cx, cy, 0, cx, cy, 120);
    ambG.addColorStop(0, 'rgba(255,220,100,0.3)');
    ambG.addColorStop(0.5, 'rgba(220,160,40,0.1)');
    ambG.addColorStop(1, 'rgba(200,120,20,0)');
    ctx.fillStyle = ambG;
    ctx.beginPath();
    ctx.arc(cx, cy, 120, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    // Subtle outer constellation ring
    ctx.save();
    ctx.globalAlpha = 0.04 + Math.sin(t * 0.3) * 0.015;
    ctx.strokeStyle = '#ffdd88';
    ctx.lineWidth = 0.8;
    ctx.setLineDash([2, 8]);
    ctx.beginPath();
    ctx.arc(cx, cy, 180 + Math.sin(t * 0.5) * 10, 0, Math.PI * 2);
    ctx.stroke();
    ctx.setLineDash([]);
    ctx.restore();
  }

  return { draw };
})();

