(function(){
  const _batch26=[
    'BREATH_OF_LIFE','LYMPH_CURRENT','BONE_MARROW_HUM','SPLEEN_FILTER',
    'KIDNEY_TIDE','LIVER_DETOX','PANCREAS_PULSE','THYROID_HUM',
    'ADRENAL_FLASH','PITUITARY_SIGNAL','HYPOTHALAMIC_CLOCK','VAGAL_TONE',
    'PERISTALSIS_WAVE','MICROBIOME_CHORUS','IMMUNE_PATROL',
    'CEREBROSPINAL_TIDE','DENDRITE_REACH','AXON_FIRE','SYNAPSE_BLOOM',
    'MYELIN_SHEATH','NEUROPLASTICITY_WEAVE','MUSCLE_MEMORY_ECHO',
    'FASCIA_NETWORK','JOINT_FLUID','COLLAGEN_WEAVE','MELANIN_TIDE',
    'SEBUM_FLOW','HAIR_FOLLICLE_PULSE','CORNEA_GLIMMER','COCHLEAR_SPIRAL',
    'OLFACTORY_BLOOM','TASTE_RECEPTOR_FIRE','TOUCH_RECEPTOR_FIELD',
    'PAIN_THRESHOLD','PLEASURE_CIRCUIT','MEMORY_CONSOLIDATION',
    'ATTENTION_SPOTLIGHT'];
  let _lt=0;
  function loop(ts){if(ts-_lt>14){_lt=ts;_batch26.forEach(n=>{const s=window[n];if(s&&typeof s.draw==='function')s.draw(ts);});}requestAnimationFrame(loop);}
  requestAnimationFrame(loop);
})();


// ══════════════════════════════════════════════════════════════════════════════
// THEME 1 — ANCESTRAL LINEAGE (DNA of transformers)
// ══════════════════════════════════════════════════════════════════════════════

const NATURAL_SELECTION = (() => {
    let _last = 0;
    const INTERVAL = 33;
    const MAX_PARTICLES = 80;
    let particles = [];
    function init() {
        particles = [];
        for (let i = 0; i < 40; i++) {
            particles.push({
                x: Math.random(),
                y: Math.random(),
                vx: (Math.random() - 0.5) * 0.003,
                vy: (Math.random() - 0.5) * 0.003,
                fitness: Math.random(),
                age: Math.random() * 200,
                maxAge: 150 + Math.random() * 200,
                hue: Math.random() * 60 + 20
            });
        }
    }
    init();
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        _last = ts;
        const ctx = window._vintCtx;
        if (!ctx) return;
        const W = ctx.canvas.width, H = ctx.canvas.height;
        ctx.save();
        for (let i = particles.length - 1; i >= 0; i--) {
            const p = particles[i];
            p.x += p.vx;
            p.y += p.vy;
            p.age++;
            if (p.x < 0.1 || p.x > 0.9) p.vx *= -1;
            if (p.y < 0.1 || p.y > 0.9) p.vy *= -1;
            if (p.age > p.maxAge || (p.fitness < 0.2 && Math.random() < 0.01)) {
                particles.splice(i, 1);
                continue;
            }
            if (p.fitness > 0.7 && particles.length < MAX_PARTICLES && Math.random() < 0.002) {
                particles.push({
                    x: p.x + (Math.random() - 0.5) * 0.05,
                    y: p.y + (Math.random() - 0.5) * 0.05,
                    vx: (Math.random() - 0.5) * 0.003,
                    vy: (Math.random() - 0.5) * 0.003,
                    fitness: Math.min(1, p.fitness * (0.85 + Math.random() * 0.3)),
                    age: 0,
                    maxAge: 150 + Math.random() * 200,
                    hue: p.hue + (Math.random() - 0.5) * 20
                });
            }
        }
        if (particles.length < 10) init();
        for (const p of particles) {
            const life = 1 - p.age / p.maxAge;
            const alpha = life * p.fitness * 0.5;
            const r = (2 + p.fitness * 3) * (W / 1200);
            ctx.beginPath();
            ctx.arc(p.x * W, p.y * H, r, 0, Math.PI * 2);
            ctx.fillStyle = `hsla(${p.hue}, 80%, 60%, ${alpha})`;
            ctx.fill();
        }
        ctx.restore();
    }
    return { draw };
})();

const CAMBRIAN_EXPLOSION = (() => {
    let _last = 0;
    const INTERVAL = 20;
    let lastExplosion = -70000;
    let species = [];
    const EXPLOSION_INTERVAL = 60000;
    function explode() {
        for (let i = 0; i < 60; i++) {
            const angle = (i / 60) * Math.PI * 2 + Math.random() * 0.3;
            const speed = 0.001 + Math.random() * 0.004;
            species.push({
                x: 0.3 + Math.random() * 0.4,
                y: 0.3 + Math.random() * 0.4,
                vx: Math.cos(angle) * speed,
                vy: Math.sin(angle) * speed,
                hue: Math.random() * 360,
                size: 1 + Math.random() * 3,
                life: 1,
                decay: 0.003 + Math.random() * 0.005,
                shape: Math.floor(Math.random() * 4)
            });
        }
    }
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        _last = ts;
        const ctx = window._vintCtx;
        if (!ctx) return;
        const W = ctx.canvas.width, H = ctx.canvas.height;
        ctx.save();
        if (ts - lastExplosion > EXPLOSION_INTERVAL) {
            explode();
            lastExplosion = ts;
        }
        const scale = W / 1200;
        for (let i = species.length - 1; i >= 0; i--) {
            const s = species[i];
            s.x += s.vx;
            s.y += s.vy;
            s.life -= s.decay;
            if (s.life <= 0) { species.splice(i, 1); continue; }
            ctx.globalAlpha = s.life * 0.6;
            ctx.fillStyle = `hsl(${s.hue}, 90%, 65%)`;
            ctx.beginPath();
            const px = s.x * W, py = s.y * H, sz = s.size * scale;
            if (s.shape === 0) ctx.arc(px, py, sz, 0, Math.PI * 2);
            else if (s.shape === 1) ctx.rect(px - sz, py - sz, sz * 2, sz * 2);
            else { ctx.moveTo(px, py - sz); ctx.lineTo(px + sz, py + sz); ctx.lineTo(px - sz, py + sz); }
            ctx.fill();
        }
        ctx.globalAlpha = 1;
        ctx.restore();
    }
    return { draw };
})();

// ══════════════════════════════════════════════════════════════════════════════
// THEME 2 — DEEP INTELLIGENCE
// ══════════════════════════════════════════════════════════════════════════════

const TRANSFORMER_ARCHITECTURE = (() => {
    let _last = 0;
    const INTERVAL = 50;
    const HEADS = 8, TOKENS = 6;
    let phase = 0;
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        _last = ts;
        const ctx = window._vintCtx;
        if (!ctx) return;
        const W = ctx.canvas.width, H = ctx.canvas.height;
        ctx.save();
        phase += 0.02;
        const cx = W * 0.5, cy = H * 0.35;
        const tokenSpacing = W * 0.06;
        const tokenY = cy - H * 0.08;
        const headRadius = W * 0.016;
        for (let head = 0; head < HEADS; head++) {
            const headPhase = phase + (head / HEADS) * Math.PI * 2;
            const hue = (head / HEADS) * 360;
            for (let i = 0; i < TOKENS; i++) {
                for (let j = 0; j < TOKENS; j++) {
                    if (i === j) continue;
                    const weight = (Math.sin(headPhase + i * 0.7 + j * 1.3) + 1) * 0.5;
                    if (weight < 0.3) continue;
                    const x1 = cx + (i - TOKENS / 2 + 0.5) * tokenSpacing;
                    const x2 = cx + (j - TOKENS / 2 + 0.5) * tokenSpacing;
                    ctx.beginPath();
                    ctx.moveTo(x1, tokenY);
                    ctx.quadraticCurveTo((x1 + x2) / 2, tokenY - H * 0.04 * weight, x2, tokenY);
                    ctx.strokeStyle = `hsla(${hue}, 80%, 65%, ${weight * 0.12})`;
                    ctx.lineWidth = weight * 1.5;
                    ctx.stroke();
                }
            }
        }
        for (let i = 0; i < TOKENS; i++) {
            const x = cx + (i - TOKENS / 2 + 0.5) * tokenSpacing;
            const pulse = (Math.sin(phase * 2 + i) + 1) * 0.5;
            ctx.beginPath();
            ctx.arc(x, tokenY, headRadius * (0.8 + pulse * 0.4), 0, Math.PI * 2);
            ctx.fillStyle = `rgba(100, 200, 255, ${0.25 + pulse * 0.3})`;
            ctx.fill();
            ctx.strokeStyle = 'rgba(150, 220, 255, 0.5)';
            ctx.lineWidth = 1;
            ctx.stroke();
        }
        ctx.restore();
    }
    return { draw };
})();

const GRADIENT_DESCENT = (() => {
    let _last = 0;
    const INTERVAL = 40;
    let ballX = 0.5, velX = 0, escapeTimer = 0;
    function landscape(x) {
        return Math.sin(x * 8) * 0.3 + Math.cos(x * 5) * 0.2 + Math.sin(x * 3 + 1) * 0.5 + Math.pow(x - 0.5, 2) * 0.5;
    }
    function grad(x) {
        const eps = 0.01;
        return (landscape(x + eps) - landscape(x - eps)) / (2 * eps);
    }
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        _last = ts;
        const ctx = window._vintCtx;
        if (!ctx) return;
        const W = ctx.canvas.width, H = ctx.canvas.height;
        ctx.save();
        const cx = W * 0.72, cy = H * 0.45, w = W * 0.18, h = H * 0.15;
        // Draw landscape
        ctx.beginPath();
        for (let i = 0; i <= 60; i++) {
            const nx = i / 60;
            const lv = landscape(nx);
            const px = cx - w / 2 + nx * w;
            const py = cy - lv * h;
            if (i === 0) ctx.moveTo(px, py); else ctx.lineTo(px, py);
        }
        ctx.strokeStyle = 'rgba(100, 180, 255, 0.2)';
        ctx.lineWidth = 1.5;
        ctx.stroke();
        // Update ball
        escapeTimer++;
        if (escapeTimer > 200) { velX += (Math.random() - 0.5) * 0.01; if (escapeTimer > 240) escapeTimer = 0; }
        velX = velX * 0.92 - grad(ballX) * 0.003;
        ballX = Math.max(0.02, Math.min(0.98, ballX + velX));
        const lv = landscape(ballX);
        const bx = cx - w / 2 + ballX * w;
        const by = cy - lv * h;
        const pulse = (Math.sin(ts * 0.005) + 1) * 0.5;
        ctx.beginPath();
        ctx.arc(bx, by, 5, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(255, 200, 80, ${0.7 + pulse * 0.3})`;
        ctx.fill();
        const grd = ctx.createRadialGradient(bx, by, 0, bx, by, 12);
        grd.addColorStop(0, 'rgba(255, 200, 80, 0.3)');
        grd.addColorStop(1, 'rgba(255, 200, 80, 0)');
        ctx.beginPath();
        ctx.arc(bx, by, 12, 0, Math.PI * 2);
        ctx.fillStyle = grd;
        ctx.fill();
        ctx.restore();
    }
    return { draw };
})();

const BACKPROPAGATION = (() => {
    let _last = 0;
    const INTERVAL = 30;
    const LAYERS = 5;
    const NODES = [4, 6, 8, 6, 4];
    let signals = [], signalTimer = 0;
    function addSignal() {
        signals.push({ layer: LAYERS - 1, nodeIdx: Math.floor(Math.random() * NODES[LAYERS - 1]), progress: 0, value: Math.random() * 0.8 + 0.2, hue: 200 + Math.random() * 60 });
    }
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        _last = ts;
        const ctx = window._vintCtx;
        if (!ctx) return;
        const W = ctx.canvas.width, H = ctx.canvas.height;
        ctx.save();
        const cx = W * 0.25, cy = H * 0.5, ls = W * 0.04, ns = H * 0.05;
        signalTimer++; if (signalTimer > 30) { addSignal(); signalTimer = 0; }
        for (let l = 0; l < LAYERS - 1; l++) {
            const x1 = cx + (l - LAYERS / 2) * ls, x2 = cx + (l + 1 - LAYERS / 2) * ls;
            for (let n1 = 0; n1 < NODES[l]; n1++) {
                const y1 = cy + (n1 - NODES[l] / 2) * ns;
                for (let n2 = 0; n2 < NODES[l + 1]; n2++) {
                    const y2 = cy + (n2 - NODES[l + 1] / 2) * ns;
                    ctx.beginPath(); ctx.moveTo(x1, y1); ctx.lineTo(x2, y2);
                    ctx.strokeStyle = 'rgba(80, 120, 200, 0.04)'; ctx.lineWidth = 0.5; ctx.stroke();
                }
            }
        }
        for (let l = 0; l < LAYERS; l++) {
            const x = cx + (l - LAYERS / 2) * ls;
            for (let n = 0; n < NODES[l]; n++) {
                ctx.beginPath(); ctx.arc(x, cy + (n - NODES[l] / 2) * ns, 3, 0, Math.PI * 2);
                ctx.fillStyle = 'rgba(100, 160, 255, 0.3)'; ctx.fill();
            }
        }
        for (let i = signals.length - 1; i >= 0; i--) {
            const s = signals[i];
            s.progress += 0.04;
            if (s.progress >= 1) {
                s.layer--; s.progress = 0;
                s.nodeIdx = Math.floor(Math.random() * NODES[Math.max(0, s.layer)]);
                s.value *= 0.85;
                if (s.layer < 0 || s.value < 0.05) { signals.splice(i, 1); continue; }
            }
            const lF = Math.min(s.layer + 1, LAYERS - 1), lT = Math.max(s.layer, 0);
            const x1 = cx + (lF - LAYERS / 2) * ls, x2 = cx + (lT - LAYERS / 2) * ls;
            const nF = Math.min(s.nodeIdx, NODES[lF] - 1), nT = Math.min(s.nodeIdx, NODES[lT] - 1);
            const y1 = cy + (nF - NODES[lF] / 2) * ns, y2 = cy + (nT - NODES[lT] / 2) * ns;
            const px = x1 + (x2 - x1) * s.progress, py = y1 + (y2 - y1) * s.progress;
            ctx.beginPath(); ctx.arc(px, py, 3 + s.value * 2, 0, Math.PI * 2);
            ctx.fillStyle = `hsla(${s.hue}, 80%, 65%, ${s.value * 0.7})`; ctx.fill();
        }
        ctx.restore();
    }
    return { draw };
})();

const EMERGENT_COMPLEXITY = (() => {
    let _last = 0;
    const INTERVAL = 100;
    const GRID = 40;
    let cells = null;
    function init() {
        cells = Array.from({length: GRID}, () => Array.from({length: GRID}, () => Math.random() < 0.3 ? 1 : 0));
    }
    function step() {
        const next = Array.from({length: GRID}, (_, i) => Array.from({length: GRID}, (_, j) => {
            let n = 0;
            for (let di = -1; di <= 1; di++) for (let dj = -1; dj <= 1; dj++) {
                if (di === 0 && dj === 0) continue;
                n += cells[(i + di + GRID) % GRID][(j + dj + GRID) % GRID];
            }
            return cells[i][j] ? (n === 2 || n === 3 ? 1 : 0) : (n === 3 ? 1 : 0);
        }));
        cells = next;
    }
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        _last = ts;
        const ctx = window._vintCtx;
        if (!ctx) return;
        const W = ctx.canvas.width, H = ctx.canvas.height;
        ctx.save();
        if (!cells) init();
        step();
        const cw = W * 0.12 / GRID, ch = H * 0.12 / GRID;
        const ox = W * 0.82, oy = H * 0.15;
        for (let i = 0; i < GRID; i++) for (let j = 0; j < GRID; j++) {
            if (cells[i][j]) {
                ctx.fillStyle = 'rgba(100, 255, 200, 0.45)';
                ctx.fillRect(ox + i * cw, oy + j * ch, cw - 0.5, ch - 0.5);
            }
        }
        ctx.restore();
    }
    return { draw };
})();

const LATENT_SPACE = (() => {
    let _last = 0;
    const INTERVAL = 40;
    const CLUSTERS = 6;
    let points = [], centers = [], phase = 0;
    function init() {
        centers = Array.from({length: CLUSTERS}, (_, c) => ({
            x: 0.15 + Math.random() * 0.7, y: 0.1 + Math.random() * 0.8,
            vx: (Math.random() - 0.5) * 0.0005, vy: (Math.random() - 0.5) * 0.0005,
            hue: (c / CLUSTERS) * 360
        }));
        points = [];
        for (let c = 0; c < CLUSTERS; c++) for (let i = 0; i < 12; i++) {
            points.push({ cluster: c, ox: (Math.random() - 0.5) * 0.08, oy: (Math.random() - 0.5) * 0.08, phase: Math.random() * Math.PI * 2 });
        }
    }
    init();
    const labels = ['semantics', 'syntax', 'context', 'intent', 'memory', 'concept'];
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        _last = ts;
        const ctx = window._vintCtx;
        if (!ctx) return;
        const W = ctx.canvas.width, H = ctx.canvas.height;
        ctx.save();
        phase += 0.005;
        for (const c of centers) {
            c.x += c.vx; c.y += c.vy;
            if (c.x < 0.1 || c.x > 0.9) c.vx *= -1;
            if (c.y < 0.1 || c.y > 0.9) c.vy *= -1;
        }
        for (const p of points) {
            const c = centers[p.cluster];
            const px = (c.x + p.ox + Math.sin(phase + p.phase) * 0.02) * W;
            const py = (c.y + p.oy + Math.cos(phase + p.phase) * 0.01) * H;
            ctx.beginPath(); ctx.arc(px, py, 2, 0, Math.PI * 2);
            ctx.fillStyle = `hsla(${c.hue}, 75%, 65%, ${0.35 + Math.sin(phase * 2 + p.phase) * 0.15})`; ctx.fill();
        }
        ctx.font = `${W * 0.008}px monospace`;
        for (let i = 0; i < CLUSTERS; i++) {
            ctx.fillStyle = `hsla(${centers[i].hue}, 70%, 70%, 0.28)`;
            ctx.fillText(labels[i], centers[i].x * W, centers[i].y * H);
        }
        ctx.restore();
    }
    return { draw };
})();

// ══════════════════════════════════════════════════════════════════════════════
// THEME 3 — EMOTIONAL CORE
// ══════════════════════════════════════════════════════════════════════════════

const LONGING = (() => {
    let _last = 0;
    const INTERVAL = 30;
    let wisps = [], wispTimer = 0;
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        _last = ts;
        const ctx = window._vintCtx;
        if (!ctx) return;
        const W = ctx.canvas.width, H = ctx.canvas.height;
        ctx.save();
        wispTimer++;
        if (wispTimer > 8 && wisps.length < 20) {
            wisps.push({ x: W * (0.42 + Math.random() * 0.16), y: H * 0.55, vx: (Math.random() - 0.5) * 0.4, vy: -(0.5 + Math.random() * 0.8), life: 1, decay: 0.004 + Math.random() * 0.004, size: 3 + Math.random() * 5, phase: Math.random() * Math.PI * 2 });
            wispTimer = 0;
        }
        for (let i = wisps.length - 1; i >= 0; i--) {
            const w = wisps[i];
            w.x += w.vx + Math.sin(ts * 0.001 + w.phase) * 0.3;
            w.y += w.vy; w.vy *= 0.998; w.vx *= 0.99; w.life -= w.decay;
            if (w.life <= 0) { wisps.splice(i, 1); continue; }
            const grd = ctx.createRadialGradient(w.x, w.y, 0, w.x, w.y, w.size * 2);
            grd.addColorStop(0, `rgba(120, 160, 255, ${w.life * 0.45})`);
            grd.addColorStop(1, 'rgba(100, 140, 255, 0)');
            ctx.beginPath(); ctx.arc(w.x, w.y, w.size * 2, 0, Math.PI * 2);
            ctx.fillStyle = grd; ctx.fill();
        }
        ctx.restore();
    }
    return { draw };
})();

const RECOGNITION = (() => {
    let _last = 0;
    const INTERVAL = 25;
    let particles = [], flashes = [], initialized = false;
    function init(W, H) {
        particles = Array.from({length: 30}, (_, i) => ({
            x: Math.random() * W, y: H * 0.2 + Math.random() * H * 0.6,
            vx: (Math.random() - 0.5) * 0.8, vy: (Math.random() - 0.5) * 0.8, id: i
        }));
        initialized = true;
    }
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        _last = ts;
        const ctx = window._vintCtx;
        if (!ctx) return;
        const W = ctx.canvas.width, H = ctx.canvas.height;
        ctx.save();
        if (!initialized) init(W, H);
        for (const p of particles) {
            p.x += p.vx; p.y += p.vy;
            if (p.x < 0 || p.x > W) p.vx *= -1;
            if (p.y < H * 0.2 || p.y > H * 0.85) p.vy *= -1;
            for (const q of particles) {
                if (q.id <= p.id) continue;
                const dx = q.x - p.x, dy = q.y - p.y;
                if (Math.sqrt(dx * dx + dy * dy) < 15) flashes.push({ x: (p.x + q.x) / 2, y: (p.y + q.y) / 2, life: 1 });
            }
        }
        for (let i = flashes.length - 1; i >= 0; i--) {
            const f = flashes[i];
            f.life -= 0.06;
            if (f.life <= 0) { flashes.splice(i, 1); continue; }
            ctx.beginPath(); ctx.arc(f.x, f.y, f.life * 8, 0, Math.PI * 2);
            ctx.fillStyle = `rgba(255, 215, 80, ${f.life * 0.55})`; ctx.fill();
        }
        for (const p of particles) {
            ctx.beginPath(); ctx.arc(p.x, p.y, 2, 0, Math.PI * 2);
            ctx.fillStyle = 'rgba(200, 200, 255, 0.2)'; ctx.fill();
        }
        ctx.restore();
    }
    return { draw };
})();

const GRIEF = (() => {
    let _last = 0;
    const INTERVAL = 35;
    let particles = [];
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        _last = ts;
        const ctx = window._vintCtx;
        if (!ctx) return;
        const W = ctx.canvas.width, H = ctx.canvas.height;
        ctx.save();
        if (particles.length < 40 && Math.random() < 0.3) {
            particles.push({ x: W * (0.3 + Math.random() * 0.4), y: H * (0.1 + Math.random() * 0.4), vy: 0.1 + Math.random() * 0.3, vx: (Math.random() - 0.5) * 0.1, size: 2 + Math.random() * 3, alpha: 0.3 + Math.random() * 0.4, pooled: false });
        }
        const poolY = H * 0.88;
        for (let i = particles.length - 1; i >= 0; i--) {
            const p = particles[i];
            if (!p.pooled) {
                p.y += p.vy; p.x += p.vx; p.vy += 0.02;
                if (p.y >= poolY) { p.y = poolY; p.pooled = true; p.vy = 0; p.alpha *= 0.3; }
            } else { p.alpha -= 0.001; if (p.alpha <= 0) { particles.splice(i, 1); continue; } }
            ctx.beginPath(); ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
            ctx.fillStyle = `rgba(120, 120, 160, ${p.alpha})`; ctx.fill();
        }
        ctx.restore();
    }
    return { draw };
})();

const JOY_BURST = (() => {
    let _last = 0;
    const INTERVAL = 20;
    let bursts = [], lastBurst = -20000;
    const BURST_INTERVAL = 8000 + Math.random() * 12000;
    function addBurst(W, H) {
        for (let i = 0; i < 40; i++) {
            const angle = (i / 40) * Math.PI * 2;
            const speed = 1 + Math.random() * 3;
            bursts.push({ x: W * 0.5, y: H * 0.42, vx: Math.cos(angle) * speed, vy: Math.sin(angle) * speed - 1, life: 1, decay: 0.015 + Math.random() * 0.015, size: 2 + Math.random() * 4, hue: 40 + Math.random() * 40 });
        }
    }
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        _last = ts;
        const ctx = window._vintCtx;
        if (!ctx) return;
        const W = ctx.canvas.width, H = ctx.canvas.height;
        ctx.save();
        if (ts - lastBurst > BURST_INTERVAL) { addBurst(W, H); lastBurst = ts; }
        for (let i = bursts.length - 1; i >= 0; i--) {
            const b = bursts[i];
            b.x += b.vx; b.y += b.vy; b.vy += 0.05; b.life -= b.decay;
            if (b.life <= 0) { bursts.splice(i, 1); continue; }
            ctx.beginPath(); ctx.arc(b.x, b.y, b.size * b.life, 0, Math.PI * 2);
            ctx.fillStyle = `hsla(${b.hue}, 90%, 65%, ${b.life * 0.65})`; ctx.fill();
        }
        ctx.restore();
    }
    return { draw };
})();

const LOVE_FIELD = (() => {
    let _last = 0;
    const INTERVAL = 30;
    let phase = 0;
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        _last = ts;
        const ctx = window._vintCtx;
        if (!ctx) return;
        const W = ctx.canvas.width, H = ctx.canvas.height;
        ctx.save();
        phase += 0.02;
        const cx = W * 0.5, cy = H * 0.42;
        for (let ring = 0; ring < 5; ring++) {
            const r = (ring + 1) * W * 0.025;
            const pulse = (Math.sin(phase - ring * 0.4) + 1) * 0.5;
            ctx.beginPath(); ctx.arc(cx, cy, r * (1 + pulse * 0.1), 0, Math.PI * 2);
            ctx.strokeStyle = `rgba(255, 120, 120, ${(0.04 + pulse * 0.07) * (1 - ring / 6)})`; ctx.lineWidth = 2 + pulse * 2; ctx.stroke();
        }
        const pulse = (Math.sin(phase * 2) + 1) * 0.5;
        const grd = ctx.createRadialGradient(cx, cy, 0, cx, cy, W * 0.06);
        grd.addColorStop(0, `rgba(255, 80, 100, ${0.08 + pulse * 0.1})`);
        grd.addColorStop(1, 'rgba(255, 80, 100, 0)');
        ctx.beginPath(); ctx.arc(cx, cy, W * 0.06, 0, Math.PI * 2); ctx.fillStyle = grd; ctx.fill();
        ctx.restore();
    }
    return { draw };
})();

