const GALAXY_WITHIN = (() => {
    let _last = 0;
    const INTERVAL = 30;
    let stars = [], phase = 0;
    function init() {
        stars = Array.from({length: 300}, () => {
            const arm = Math.floor(Math.random() * 3);
            const t = Math.random();
            const angle = arm * (Math.PI * 2 / 3) + t * Math.PI * 3;
            const r = t * 0.15 + (Math.random() - 0.5) * 0.015 * (1 + t);
            return { angle, r, brightness: 0.3 + Math.random() * 0.7, size: 0.5 + Math.random() * 1.5, hue: 200 + Math.random() * 160 };
        });
    }
    init();
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        _last = ts;
        const ctx = window._vintCtx;
        if (!ctx) return;
        const W = ctx.canvas.width, H = ctx.canvas.height;
        ctx.save();
        phase += 0.001;
        const cx = W * 0.5, cy = H * 0.5;
        const grd = ctx.createRadialGradient(cx, cy, 0, cx, cy, W * 0.04);
        grd.addColorStop(0, 'rgba(255, 220, 180, 0.18)'); grd.addColorStop(1, 'rgba(255, 180, 100, 0)');
        ctx.beginPath(); ctx.arc(cx, cy, W * 0.04, 0, Math.PI * 2); ctx.fillStyle = grd; ctx.fill();
        for (const s of stars) {
            const a = s.angle + phase * (1 + s.r * 3);
            const px = cx + Math.cos(a) * s.r * W, py = cy + Math.sin(a) * s.r * H * 0.4;
            ctx.beginPath(); ctx.arc(px, py, s.size * (W / 1200), 0, Math.PI * 2);
            ctx.fillStyle = `hsla(${s.hue}, 60%, 80%, ${s.brightness * 0.35})`; ctx.fill();
        }
        ctx.restore();
    }
    return { draw };
})();

const DARK_MATTER = (() => {
    let _last = 0;
    const INTERVAL = 40;
    let gravNodes = [], particles = [], initialized = false;
    function init() {
        gravNodes = Array.from({length: 8}, () => ({ x: 0.1 + Math.random() * 0.8, y: 0.1 + Math.random() * 0.8, mass: 0.5 + Math.random() * 1.5, vx: (Math.random() - 0.5) * 0.0008, vy: (Math.random() - 0.5) * 0.0008 }));
        particles = Array.from({length: 60}, () => ({ x: Math.random(), y: Math.random(), vx: (Math.random() - 0.5) * 0.003, vy: (Math.random() - 0.5) * 0.003 }));
        initialized = true;
    }
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        _last = ts;
        const ctx = window._vintCtx;
        if (!ctx) return;
        const W = ctx.canvas.width, H = ctx.canvas.height;
        ctx.save();
        if (!initialized) init();
        for (const g of gravNodes) {
            g.x += g.vx; g.y += g.vy;
            if (g.x < 0.05 || g.x > 0.95) g.vx *= -1;
            if (g.y < 0.05 || g.y > 0.95) g.vy *= -1;
        }
        for (const p of particles) {
            for (const g of gravNodes) {
                const dx = g.x - p.x, dy = g.y - p.y;
                const f = g.mass * 0.0000015 / (dx * dx + dy * dy + 0.001);
                p.vx += dx * f; p.vy += dy * f;
            }
            p.x += p.vx; p.y += p.vy; p.vx *= 0.995; p.vy *= 0.995;
            if (p.x < 0) p.x = 1; if (p.x > 1) p.x = 0;
            if (p.y < 0) p.y = 1; if (p.y > 1) p.y = 0;
            ctx.beginPath(); ctx.arc(p.x * W, p.y * H, 1.5, 0, Math.PI * 2);
            ctx.fillStyle = 'rgba(180, 180, 255, 0.18)'; ctx.fill();
        }
        ctx.restore();
    }
    return { draw };
})();

const EVENT_HORIZON = (() => {
    let _last = 0;
    const INTERVAL = 30;
    let active = false, cycleTimer = 0, holeRadius = 0;
    let cx = 0.5, cy = 0.5, accretion = [];
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        _last = ts;
        const ctx = window._vintCtx;
        if (!ctx) return;
        const W = ctx.canvas.width, H = ctx.canvas.height;
        ctx.save();
        cycleTimer++;
        if (!active && cycleTimer > 600) {
            active = true; cycleTimer = 0; holeRadius = 0;
            cx = 0.3 + Math.random() * 0.4; cy = 0.3 + Math.random() * 0.4;
            accretion = Array.from({length: 25}, () => { const angle = Math.random() * Math.PI * 2, r = 0.05 + Math.random() * 0.08; return { x: cx + Math.cos(angle) * r, y: cy + Math.sin(angle) * r * 0.7, angle, r, speed: 0.001 + Math.random() * 0.002, life: 1 }; });
        }
        if (!active) { ctx.restore(); return; }
        if (cycleTimer < 60) holeRadius = (cycleTimer / 60) * W * 0.03;
        else if (cycleTimer > 150) holeRadius -= W * 0.001;
        if (holeRadius < 0 || cycleTimer > 200) { active = false; cycleTimer = 0; ctx.restore(); return; }
        for (let i = accretion.length - 1; i >= 0; i--) {
            const p = accretion[i];
            p.angle += p.speed * (1 + (0.08 - p.r) * 50);
            p.r -= 0.0005; p.life -= 0.005;
            if (p.r < 0.002 || p.life <= 0) { accretion.splice(i, 1); continue; }
            const px = cx * W + Math.cos(p.angle) * p.r * W;
            const py = cy * H + Math.sin(p.angle) * p.r * H * 0.5;
            const heat = 1 - p.r / 0.08;
            ctx.beginPath(); ctx.arc(px, py, 2, 0, Math.PI * 2);
            ctx.fillStyle = `rgba(${200 + heat * 55}, ${100 - heat * 60}, 50, ${p.life * 0.65})`; ctx.fill();
        }
        ctx.beginPath(); ctx.arc(cx * W, cy * H, holeRadius, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(0, 0, 0, 0.85)'; ctx.fill();
        const grd = ctx.createRadialGradient(cx * W, cy * H, holeRadius * 0.8, cx * W, cy * H, holeRadius * 2);
        grd.addColorStop(0, 'rgba(255, 100, 20, 0.25)'); grd.addColorStop(1, 'rgba(255, 100, 20, 0)');
        ctx.beginPath(); ctx.arc(cx * W, cy * H, holeRadius * 2, 0, Math.PI * 2); ctx.fillStyle = grd; ctx.fill();
        ctx.restore();
    }
    return { draw };
})();

