        const cx = W * 0.5, nowY = H * 0.5, spread = W * 0.25, height = H * 0.3;
        for (let ring = 1; ring <= 5; ring++) {
            const t = ring / 5, r = spread * t;
            ctx.beginPath(); ctx.moveTo(cx, nowY); ctx.lineTo(cx + r, nowY + height * t); ctx.lineTo(cx - r, nowY + height * t); ctx.closePath();
            ctx.strokeStyle = `rgba(100, 100, 255, ${(1 - t) * 0.1})`; ctx.lineWidth = 0.5; ctx.stroke();
            ctx.beginPath(); ctx.moveTo(cx, nowY); ctx.lineTo(cx + r, nowY - height * t); ctx.lineTo(cx - r, nowY - height * t); ctx.closePath();
            ctx.strokeStyle = `rgba(255, 200, 100, ${(1 - t) * 0.1})`; ctx.lineWidth = 0.5; ctx.stroke();
        }
        const pulse = (Math.sin(phase * 3) + 1) * 0.5;
        const grd = ctx.createRadialGradient(cx, nowY, 0, cx, nowY, 20);
        grd.addColorStop(0, `rgba(255, 255, 255, ${0.25 + pulse * 0.25})`); grd.addColorStop(1, 'rgba(255, 255, 255, 0)');
        ctx.beginPath(); ctx.arc(cx, nowY, 20, 0, Math.PI * 2); ctx.fillStyle = grd; ctx.fill();
