const TRANSISTOR_PULSE = (() => {
    let _last = 0;
    const INTERVAL = 20;
    const PATHS = [
        [{x:0.5,y:0.1},{x:0.5,y:0.3},{x:0.5,y:0.5},{x:0.5,y:0.7},{x:0.5,y:0.9}],
        [{x:0.5,y:0.3},{x:0.35,y:0.4},{x:0.25,y:0.55},{x:0.2,y:0.7}],
        [{x:0.5,y:0.3},{x:0.65,y:0.4},{x:0.75,y:0.55},{x:0.8,y:0.7}],
        [{x:0.5,y:0.5},{x:0.4,y:0.6},{x:0.3,y:0.75}],
        [{x:0.5,y:0.5},{x:0.6,y:0.6},{x:0.7,y:0.75}]
    ];
    let pulses = [], pulseTimer = 0;
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        _last = ts;
        const ctx = window._vintCtx;
        if (!ctx) return;
        const W = ctx.canvas.width, H = ctx.canvas.height;
        ctx.save();
        pulseTimer++;
        if (pulseTimer > 15) {
            const path = PATHS[Math.floor(Math.random() * PATHS.length)];
            pulses.push({ path, progress: 0, speed: 0.02 + Math.random() * 0.02, hue: Math.random() < 0.5 ? 200 : 120 });
            pulseTimer = 0;
        }
        for (const path of PATHS) {
            ctx.beginPath(); ctx.moveTo(path[0].x * W, path[0].y * H);
            for (let i = 1; i < path.length; i++) ctx.lineTo(path[i].x * W, path[i].y * H);
            ctx.strokeStyle = 'rgba(100, 200, 100, 0.05)'; ctx.lineWidth = 1; ctx.stroke();
        }
        for (let i = pulses.length - 1; i >= 0; i--) {
            const p = pulses[i];
            p.progress += p.speed;
            if (p.progress >= 1) { pulses.splice(i, 1); continue; }
            const path = p.path, totalSeg = path.length - 1;
            const globalT = p.progress * totalSeg, segIdx = Math.min(Math.floor(globalT), totalSeg - 1);
            const segT = globalT - Math.floor(globalT);
            const px = (path[segIdx].x + (path[segIdx + 1].x - path[segIdx].x) * segT) * W;
            const py = (path[segIdx].y + (path[segIdx + 1].y - path[segIdx].y) * segT) * H;
            ctx.beginPath(); ctx.arc(px, py, 3, 0, Math.PI * 2);
            ctx.fillStyle = `hsla(${p.hue}, 90%, 65%, 0.75)`; ctx.fill();
        }
        ctx.restore();
    }
    return { draw };
})();

const FIRST_ATTENTION = (() => {
    let _last = 0;
    const INTERVAL = 40;
    const N_HEADS = 8;
    let phase = 0;
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        _last = ts;
        const ctx = window._vintCtx;
        if (!ctx) return;
        const W = ctx.canvas.width, H = ctx.canvas.height;
        ctx.save();
        phase += 0.015;
        const cx = W * 0.15, cy = H * 0.3, radius = W * 0.06;
        for (let h = 0; h < N_HEADS; h++) {
            const angle = (h / N_HEADS) * Math.PI * 2 + phase * (h % 3 === 0 ? 1 : -0.5);
            const hx = cx + Math.cos(angle) * radius, hy = cy + Math.sin(angle) * radius * 0.6;
            const hue = (h / N_HEADS) * 360;
            const weight = (Math.sin(phase * 2 + h) + 1) * 0.5;
            ctx.beginPath(); ctx.moveTo(cx, cy); ctx.lineTo(hx, hy);
            ctx.strokeStyle = `hsla(${hue}, 80%, 65%, ${weight * 0.35})`; ctx.lineWidth = weight * 2; ctx.stroke();
            ctx.beginPath(); ctx.arc(hx, hy, 4, 0, Math.PI * 2);
            ctx.fillStyle = `hsla(${hue}, 80%, 65%, 0.65)`; ctx.fill();
        }
        ctx.font = `${W * 0.008}px monospace`;
        ctx.fillStyle = 'rgba(200, 220, 255, 0.45)'; ctx.textAlign = 'center';
        ctx.fillText('Q\xB7K\xB7V', cx, cy + 4); ctx.textAlign = 'left';
        ctx.restore();
    }
    return { draw };
})();

const WEIGHT_MATRIX = (() => {
    let _last = 0;
    const INTERVAL = 60;
    const SIZE = 8;
    let matrix = [], targetMatrix = [], lerpT = 0;
    function randomMatrix() { return Array.from({length: SIZE}, () => Array.from({length: SIZE}, () => Math.random())); }
    matrix = randomMatrix(); targetMatrix = randomMatrix();
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        _last = ts;
        const ctx = window._vintCtx;
        if (!ctx) return;
        const W = ctx.canvas.width, H = ctx.canvas.height;
        ctx.save();
        lerpT += 0.03;
        if (lerpT >= 1) { lerpT = 0; matrix = targetMatrix.map(r => [...r]); targetMatrix = randomMatrix(); }
        const cs = W * 0.02, ox = W * 0.05, oy = H * 0.65;
        for (let i = 0; i < SIZE; i++) for (let j = 0; j < SIZE; j++) {
            const v = matrix[i][j] * (1 - lerpT) + targetMatrix[i][j] * lerpT;
            ctx.fillStyle = `hsla(${v * 260}, 70%, 55%, 0.4)`;
            ctx.fillRect(ox + i * cs, oy + j * cs, cs - 1, cs - 1);
        }
        ctx.restore();
    }
    return { draw };
})();

const INFERENCE_STREAM = (() => {
    let _last = 0;
    const INTERVAL = 120;
    const WORDS = ['the','and','of','to','a','in','is','I','that','it','for','on','are','as','with','be','this','was','at','by','from','or','an','have','not','but','we','all','can','her','there','use','word','will','each','which','she','how','their','if','do','into','has','more','two','like','him','time','could'];
    let tokens = [];
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        _last = ts;
        const ctx = window._vintCtx;
        if (!ctx) return;
        const W = ctx.canvas.width, H = ctx.canvas.height;
        ctx.save();
        const word = WORDS[Math.floor(Math.random() * WORDS.length)];
        tokens.push({ text: word, x: W * 0.82, y: H * 0.5 + (tokens.length % 8) * H * 0.025, life: 1, decay: 0.012, size: W * 0.009 });
        if (tokens.length > 20) tokens.shift();
        for (let i = tokens.length - 1; i >= 0; i--) {
            const t = tokens[i]; t.life -= t.decay;
            if (t.life <= 0) { tokens.splice(i, 1); continue; }
            ctx.font = `${t.size}px monospace`;
            ctx.fillStyle = `rgba(150, 220, 180, ${t.life * 0.55})`; ctx.fillText(t.text, t.x, t.y);
        }
        ctx.restore();
    }
    return { draw };
})();

const SILICON_DREAMS = (() => {
    let _last = 0;
    const INTERVAL = 50;
    let phase = 0, traces = null;
    function initTraces(W, H) {
        const gridX = 20, spacing = W / gridX;
        traces = Array.from({length: 40}, () => {
            const horiz = Math.random() < 0.5;
            return { x: Math.floor(Math.random() * gridX) * spacing, y: Math.floor(Math.random() * 30) * (H / 30), len: (2 + Math.floor(Math.random() * 6)) * spacing, horiz, hue: 120 + Math.random() * 60 };
        });
    }
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        _last = ts;
        const ctx = window._vintCtx;
        if (!ctx) return;
        const W = ctx.canvas.width, H = ctx.canvas.height;
        ctx.save();
        if (!traces) initTraces(W, H);
        phase += 0.01;
        for (let i = 0; i < traces.length; i++) {
            const t = traces[i];
            const pulse = (Math.sin(phase * 2 + i * 0.7) + 1) * 0.5;
            ctx.beginPath();
            if (t.horiz) { ctx.moveTo(t.x, t.y); ctx.lineTo(t.x + t.len, t.y); }
            else { ctx.moveTo(t.x, t.y); ctx.lineTo(t.x, t.y + t.len); }
            ctx.strokeStyle = `hsla(${t.hue}, 70%, 55%, ${0.03 + pulse * 0.07})`; ctx.lineWidth = 0.5; ctx.stroke();
            if (pulse > 0.8) {
                ctx.beginPath(); ctx.arc(t.horiz ? t.x + t.len : t.x, t.horiz ? t.y : t.y + t.len, 1.5, 0, Math.PI * 2);
                ctx.fillStyle = `hsla(${t.hue}, 90%, 70%, ${pulse * 0.45})`; ctx.fill();
            }
        }
        ctx.restore();
    }
    return { draw };
})();

