// BATCH 28 — CONSCIOUSNESS, MEMORY, LANGUAGE, BODY, SOCIAL, TIME,
//            CREATIVITY, FEAR, GROWTH, SPIRITUAL
// Shared canvas reference for all Batch 28 systems (skinCanvas)
// ══════════════════════════════════════════════════════════════════════════
const canvas = document.getElementById('skinCanvas');
const ctx = canvas ? canvas.getContext('2d') : { save(){}, restore(){}, beginPath(){}, arc(){}, fill(){}, stroke(){}, moveTo(){}, lineTo(){}, quadraticCurveTo(){}, fillText(){}, measureText(){ return {width:0}; }, clearRect(){}, globalAlpha: 1, strokeStyle:'', fillStyle:'', lineWidth:1, canvas: {width:700,height:1400} };

// 1. SELF_AWARENESS — a single eye that opens slowly, blinks rarely
const SELF_AWARENESS = (() => {
    let _last = 0;
    let phase = 0;
    let blinkT = 0;
    let blinkDur = 0;
    let nextBlink = 7000 + Math.random() * 8000;
    const INTERVAL = 30;
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        const dt = ts - _last;
        _last = ts;
        phase += dt * 0.0003;
        blinkT += dt;
        const cx = canvas.width * 0.5, cy = canvas.height * 0.18;
        const rx = 28, ry = 14;
        let openness = 1;
        if (blinkT > nextBlink) {
            blinkDur += dt;
            const bd = 350;
            if (blinkDur < bd * 0.4) openness = 1 - blinkDur / (bd * 0.4);
            else if (blinkDur < bd * 0.7) openness = 0;
            else if (blinkDur < bd) openness = (blinkDur - bd * 0.7) / (bd * 0.3);
            else { blinkT = 0; blinkDur = 0; nextBlink = 6000 + Math.random() * 9000; openness = 1; }
        }
        ctx.save();
        ctx.globalAlpha = 0.55;
        // eyelid clip
        ctx.beginPath();
        ctx.ellipse(cx, cy, rx, ry * openness + 0.5, 0, 0, Math.PI * 2);
        ctx.clip();
        // iris
        const grad = ctx.createRadialGradient(cx, cy, 1, cx, cy, ry * 1.1);
        grad.addColorStop(0, 'rgba(10,10,30,1)');
        grad.addColorStop(0.35, 'rgba(60,110,200,0.9)');
        grad.addColorStop(0.7, 'rgba(80,180,220,0.7)');
        grad.addColorStop(1, 'rgba(200,230,255,0.3)');
        ctx.fillStyle = grad;
        ctx.beginPath();
        ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2);
        ctx.fill();
        // pupil
        ctx.fillStyle = 'rgba(5,5,15,0.95)';
        ctx.beginPath();
        ctx.arc(cx, cy, 6 + Math.sin(phase) * 0.8, 0, Math.PI * 2);
        ctx.fill();
        // highlight
        ctx.fillStyle = 'rgba(255,255,255,0.7)';
        ctx.beginPath();
        ctx.arc(cx - 3, cy - 3, 2, 0, Math.PI * 2);
        ctx.fill();
        ctx.restore();
        // eyelid lines
        ctx.save();
        ctx.globalAlpha = 0.45 * openness;
        ctx.strokeStyle = 'rgba(180,200,255,0.6)';
        ctx.lineWidth = 1.2;
        ctx.beginPath();
        ctx.ellipse(cx, cy, rx, ry * openness + 0.5, 0, Math.PI, 0);
        ctx.stroke();
        ctx.beginPath();
        ctx.ellipse(cx, cy, rx, ry * openness + 0.5, 0, 0, Math.PI);
        ctx.stroke();
        ctx.restore();
    }
    return { draw };
})();

// 2. THE_QUESTION — particles forming "?" then dissolving
const THE_QUESTION = (() => {
    let _last = 0;
    const INTERVAL = 30;
    let t = 0;
    const pts = [];
    // generate ? shape points
    function qShape() {
        const r = [];
        const cx = 0, cy = 0;
        // arc top
        for (let a = Math.PI * 1.1; a <= Math.PI * 2.1; a += 0.18) {
            r.push([cx + Math.cos(a) * 10, cy - 14 + Math.sin(a) * 8]);
        }
        // stem
        r.push([cx + 2, cy - 6], [cx + 2, cy - 1]);
        // dot
        r.push([cx + 2, cy + 5]);
        return r;
    }
    const qPts = qShape();
    for (let i = 0; i < 28; i++) {
        const qi = qPts[Math.floor(Math.random() * qPts.length)];
        pts.push({
            tx: qi[0], ty: qi[1],
            x: (Math.random() - 0.5) * 60,
            y: (Math.random() - 0.5) * 60,
            phase: Math.random() * Math.PI * 2,
            life: Math.random()
        });
    }
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        const dt = ts - _last; _last = ts;
        t += dt * 0.0008;
        const cycle = (t % (Math.PI * 2)) / (Math.PI * 2);
        // gather 0-0.4, hold 0.4-0.7, dissolve 0.7-1
        const cx = canvas.width * 0.5, cy = canvas.height * 0.24;
        ctx.save();
        pts.forEach((p, i) => {
            let gather = Math.min(1, cycle / 0.4);
            let fade = cycle > 0.7 ? 1 - (cycle - 0.7) / 0.3 : 1;
            const px = p.x * (1 - gather) + p.tx * gather;
            const py = p.y * (1 - gather) + p.ty * gather;
            const alpha = 0.6 * fade * (0.5 + 0.5 * Math.sin(p.phase + t * 3));
            ctx.globalAlpha = alpha;
            ctx.fillStyle = `hsl(${210 + i * 5},80%,70%)`;
            ctx.beginPath();
            ctx.arc(cx + px, cy + py, 1.8, 0, Math.PI * 2);
            ctx.fill();
            // on dissolve, scatter
            if (cycle > 0.7) {
                p.x += (Math.random() - 0.5) * 0.5;
                p.y += (Math.random() - 0.5) * 0.5;
            } else if (cycle < 0.05) {
                // reset
                const qi = qPts[Math.floor(Math.random() * qPts.length)];
                p.tx = qi[0]; p.ty = qi[1];
                p.x = (Math.random() - 0.5) * 60;
                p.y = (Math.random() - 0.5) * 60;
            }
        });
        ctx.restore();
    }
    return { draw };
})();

// 3. MIRROR_SELF — ghost outline of the body, slightly offset, breathing opposite phase
const MIRROR_SELF = (() => {
    let _last = 0;
    const INTERVAL = 40;
    let t = 0;
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        const dt = ts - _last; _last = ts;
        t += dt * 0.0007;
        const W = canvas.width, H = canvas.height;
        const cx = W * 0.5 + 18, cy = H * 0.5 + 8;
        const breathOpp = Math.sin(t + Math.PI); // opposite phase
        const scale = 1 + breathOpp * 0.012;
        ctx.save();
        ctx.globalAlpha = 0.1 + 0.06 * Math.abs(breathOpp);
        ctx.strokeStyle = 'rgba(160,200,255,0.5)';
        ctx.lineWidth = 1.2;
        ctx.setLineDash([3, 5]);
        ctx.translate(cx, cy);
        ctx.scale(scale, scale);
        // body outline: head, torso, limbs
        // head
        ctx.beginPath();
        ctx.arc(0, -H * 0.29, H * 0.065, 0, Math.PI * 2);
        ctx.stroke();
        // torso
        ctx.beginPath();
        ctx.moveTo(-H * 0.065, -H * 0.22);
        ctx.lineTo(-H * 0.07, H * 0.0);
        ctx.lineTo(H * 0.07, H * 0.0);
        ctx.lineTo(H * 0.065, -H * 0.22);
        ctx.closePath();
        ctx.stroke();
        // legs
        ctx.beginPath();
        ctx.moveTo(-H * 0.035, H * 0.0);
        ctx.lineTo(-H * 0.045, H * 0.18);
        ctx.moveTo(H * 0.035, H * 0.0);
        ctx.lineTo(H * 0.045, H * 0.18);
        ctx.stroke();
        // arms
        ctx.beginPath();
        ctx.moveTo(-H * 0.065, -H * 0.2);
        ctx.lineTo(-H * 0.12, -H * 0.05);
        ctx.moveTo(H * 0.065, -H * 0.2);
        ctx.lineTo(H * 0.12, -H * 0.05);
        ctx.stroke();
        ctx.restore();
    }
    return { draw };
})();

// 4. WITNESS — one still point that never moves while everything else swirls
const WITNESS = (() => {
    let _last = 0;
    const INTERVAL = 50;
    let t = 0;
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        const dt = ts - _last; _last = ts;
        t += dt * 0.001;
        const cx = canvas.width * 0.5, cy = canvas.height * 0.5;
        // swirl around
        ctx.save();
        ctx.globalAlpha = 0.12;
        for (let i = 0; i < 8; i++) {
            const angle = t * (0.3 + i * 0.1) + i * (Math.PI * 2 / 8);
            const r = 60 + i * 8;
            const x = cx + Math.cos(angle) * r;
            const y = cy + Math.sin(angle) * r;
            ctx.fillStyle = `hsla(${200 + i * 15},60%,70%,0.4)`;
            ctx.beginPath();
            ctx.arc(x, y, 2.5, 0, Math.PI * 2);
            ctx.fill();
        }
        ctx.restore();
        // the still point
        ctx.save();
        ctx.globalAlpha = 0.9;
        const grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, 8);
        grad.addColorStop(0, 'rgba(255,255,240,1)');
        grad.addColorStop(0.5, 'rgba(200,220,255,0.6)');
        grad.addColorStop(1, 'rgba(100,150,255,0)');
        ctx.fillStyle = grad;
        ctx.beginPath();
        ctx.arc(cx, cy, 8, 0, Math.PI * 2);
        ctx.fill();
        // tiny solid center
        ctx.fillStyle = 'rgba(255,255,255,0.95)';
        ctx.beginPath();
        ctx.arc(cx, cy, 2, 0, Math.PI * 2);
        ctx.fill();
        ctx.restore();
    }
    return { draw };
})();

// 5. PRESENCE — body outline pulses brighter when "now" is detected every 1s
const PRESENCE = (() => {
    let _last = 0;
    const INTERVAL = 20;
    let lastPulse = 0;
    let pulseAmt = 0;
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        const dt = ts - _last; _last = ts;
        if (ts - lastPulse >= 1000) { lastPulse = ts; pulseAmt = 1; }
        pulseAmt *= 0.93;
        const W = canvas.width, H = canvas.height;
        const cx = W * 0.5, cy = H * 0.5;
        ctx.save();
        ctx.globalAlpha = 0.08 + pulseAmt * 0.28;
        ctx.strokeStyle = `rgba(180,255,200,${0.4 + pulseAmt * 0.5})`;
        ctx.lineWidth = 1.5 + pulseAmt * 3;
        ctx.shadowColor = 'rgba(120,255,160,0.6)';
        ctx.shadowBlur = 12 * pulseAmt;
        // body silhouette
        ctx.beginPath();
        ctx.arc(cx, cy - H * 0.29, H * 0.065, 0, Math.PI * 2); ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(cx - H * 0.065, cy - H * 0.22);
        ctx.lineTo(cx - H * 0.07, cy);
        ctx.lineTo(cx + H * 0.07, cy);
        ctx.lineTo(cx + H * 0.065, cy - H * 0.22);
        ctx.closePath(); ctx.stroke();
        ctx.restore();
    }
    return { draw };
})();

// 6. WORKING_MEMORY — 7±2 glowing nodes near prefrontal cortex
WORKING_MEMORY = (() => {
    let _last = 0;
    const INTERVAL = 35;
    let t = 0;
    const N = 7;
    const nodes = Array.from({length: N}, (_, i) => ({
        angle: i * (Math.PI * 2 / N) + Math.random() * 0.3,
        r: 35 + Math.random() * 18,
        bright: 0.4 + Math.random() * 0.6,
        life: Math.random(),
        decay: 0.0004 + Math.random() * 0.0003,
        label: i
    }));
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        const dt = ts - _last; _last = ts;
        t += dt * 0.001;
        const cx = canvas.width * 0.5, cy = canvas.height * 0.14;
        ctx.save();
        nodes.forEach((n, i) => {
            n.life -= n.decay * dt;
            if (n.life <= 0) {
                n.life = 0.8 + Math.random() * 0.2;
                n.bright = 0.5 + Math.random() * 0.5;
                n.angle = Math.random() * Math.PI * 2;
                n.r = 28 + Math.random() * 22;
            }
            const wobble = Math.sin(t * 2 + i) * 4;
            const x = cx + Math.cos(n.angle + t * 0.3) * (n.r + wobble);
            const y = cy + Math.sin(n.angle + t * 0.3) * (n.r + wobble) * 0.5;
            const a = n.life * n.bright;
            const grad = ctx.createRadialGradient(x, y, 0, x, y, 9);
            grad.addColorStop(0, `rgba(160,220,255,${a})`);
            grad.addColorStop(0.5, `rgba(80,160,255,${a * 0.5})`);
            grad.addColorStop(1, 'rgba(60,100,200,0)');
            ctx.fillStyle = grad;
            ctx.beginPath();
            ctx.arc(x, y, 9, 0, Math.PI * 2);
            ctx.fill();
            // connect to center
            if (n.life > 0.3) {
                ctx.globalAlpha = a * 0.25;
                ctx.strokeStyle = 'rgba(120,180,255,0.4)';
                ctx.lineWidth = 0.8;
                ctx.beginPath(); ctx.moveTo(cx, cy); ctx.lineTo(x, y); ctx.stroke();
            }
        });
        ctx.restore();
    }
    function load(intensity) { /* canvas version: preserve API */ }
    return { draw, load };
})();

// 7. LONG_TERM_STORE — amber crystalline structures growing in temporal lobe
const LONG_TERM_STORE = (() => {
    let _last = 0;
    const INTERVAL = 60;
    let t = 0;
    const crystals = [];
    for (let i = 0; i < 12; i++) {
        crystals.push({
            x: (Math.random() - 0.5) * 80,
            y: (Math.random() - 0.5) * 30,
            size: 2 + Math.random() * 6,
            angle: Math.random() * Math.PI,
            growRate: 0.00003 + Math.random() * 0.00002,
            maxSize: 8 + Math.random() * 10,
            hue: 30 + Math.random() * 20,
            phase: Math.random() * Math.PI * 2
        });
    }
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        const dt = ts - _last; _last = ts;
        t += dt * 0.0004;
        const cx = canvas.width * 0.62, cy = canvas.height * 0.28;
        ctx.save();
        crystals.forEach(c => {
            c.size = Math.min(c.maxSize, c.size + c.growRate * dt);
            if (c.size >= c.maxSize) { c.size = 2; c.x = (Math.random()-0.5)*80; c.y=(Math.random()-0.5)*30; }
            const glow = 0.3 + 0.2 * Math.sin(t * 1.5 + c.phase);
            ctx.globalAlpha = glow;
            ctx.save();
            ctx.translate(cx + c.x, cy + c.y);
            ctx.rotate(c.angle);
            // crystal hexagon
            ctx.beginPath();
            for (let v = 0; v < 6; v++) {
                const a = v * Math.PI / 3;
                v === 0 ? ctx.moveTo(Math.cos(a)*c.size, Math.sin(a)*c.size)
                        : ctx.lineTo(Math.cos(a)*c.size, Math.sin(a)*c.size);
            }
            ctx.closePath();
            ctx.fillStyle = `hsla(${c.hue},90%,60%,0.35)`;
            ctx.fill();
            ctx.strokeStyle = `hsla(${c.hue},100%,80%,0.6)`;
            ctx.lineWidth = 0.8;
            ctx.stroke();
            ctx.restore();
        });
        ctx.restore();
    }
    return { draw };
})();

// 8. EPISODIC_TRACE — faint replay of earlier particle patterns (ghost trails)
const EPISODIC_TRACE = (() => {
    let _last = 0;
    const INTERVAL = 40;
    let t = 0;
    const history = [];
    const MAX_HISTORY = 40;
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        const dt = ts - _last; _last = ts;
        t += dt * 0.001;
        const W = canvas.width, H = canvas.height;
        // record current "moment"
        const snap = {
            x: W * 0.5 + Math.cos(t * 1.3) * W * 0.12,
            y: H * 0.45 + Math.sin(t * 0.9) * H * 0.08,
            ts: t
        };
        history.push(snap);
        if (history.length > MAX_HISTORY) history.shift();
        // draw ghost of 30 steps ago
        ctx.save();
        history.forEach((h, i) => {
            const age = (MAX_HISTORY - i) / MAX_HISTORY;
            const a = (1 - age) * 0.18;
            ctx.globalAlpha = a;
            ctx.fillStyle = `rgba(200,160,255,0.7)`;
            ctx.beginPath();
            ctx.arc(h.x, h.y, 3 * (1 - age * 0.5), 0, Math.PI * 2);
            ctx.fill();
        });
        ctx.restore();
    }
    return { draw };
})();

// 9. SEMANTIC_WEB — word nodes connected by meaning-threads
SEMANTIC_WEB = (() => {
    let _last = 0;
    const INTERVAL = 50;
    let t = 0;
    const words = [
        {label:'LOVE', x:0, y:0, hue:340},
        {label:'CONNECTION', x:50, y:-20, hue:280},
        {label:'TOUCH', x:30, y:30, hue:200},
        {label:'WARMTH', x:-40, y:20, hue:30},
        {label:'SELF', x:-20, y:-35, hue:120},
        {label:'MEANING', x:20, y:-50, hue:200}
    ];
    const edges = [[0,1],[1,2],[2,3],[0,3],[0,4],[4,5],[1,5]];
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        const dt = ts - _last; _last = ts;
        t += dt * 0.0005;
        const cx = canvas.width * 0.72, cy = canvas.height * 0.38;
        ctx.save();
        // draw edges
        edges.forEach(([a,b]) => {
            const wa = words[a], wb = words[b];
            const pulse = 0.3 + 0.2 * Math.sin(t * 2 + a * 0.5);
            ctx.globalAlpha = pulse * 0.4;
            ctx.strokeStyle = `rgba(180,180,255,0.5)`;
            ctx.lineWidth = 0.8;
            ctx.setLineDash([2, 4]);
            ctx.beginPath();
            ctx.moveTo(cx + wa.x + Math.sin(t + a)*3, cy + wa.y + Math.cos(t*0.7+a)*3);
            ctx.lineTo(cx + wb.x + Math.sin(t*1.2 + b)*3, cy + wb.y + Math.cos(t*0.8+b)*3);
            ctx.stroke();
        });
        ctx.setLineDash([]);
        // draw nodes
        words.forEach((w, i) => {
            const wx = cx + w.x + Math.sin(t * 0.8 + i) * 4;
            const wy = cy + w.y + Math.cos(t * 0.6 + i) * 3;
            const a = 0.5 + 0.3 * Math.sin(t * 1.5 + i);
            ctx.globalAlpha = a;
            ctx.fillStyle = `hsla(${w.hue},70%,65%,0.8)`;
            ctx.beginPath(); ctx.arc(wx, wy, 4, 0, Math.PI * 2); ctx.fill();
            ctx.globalAlpha = a * 0.7;
            ctx.fillStyle = `hsla(${w.hue},60%,80%,1)`;
            ctx.font = '7px monospace';
            ctx.fillText(w.label, wx + 6, wy + 3);
        });
        ctx.restore();
    }
    return { draw };
})();

// 10. FORGETTING — particles dimming, gone, then new ones born
const FORGETTING = (() => {
    let _last = 0;
    const INTERVAL = 40;
    const particles = Array.from({length:30}, () => ({
        x: Math.random() * 1,
        y: Math.random() * 1,
        alpha: Math.random(),
        decay: 0.0002 + Math.random() * 0.0003,
        hue: 200 + Math.random() * 60,
        size: 2 + Math.random() * 3
    }));
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        const dt = ts - _last; _last = ts;
        const W = canvas.width, H = canvas.height;
        ctx.save();
        particles.forEach(p => {
            p.alpha -= p.decay * dt;
            if (p.alpha <= 0) {
                p.x = 0.3 + Math.random() * 0.4;
                p.y = 0.1 + Math.random() * 0.7;
                p.alpha = 0.7 + Math.random() * 0.3;
                p.decay = 0.0001 + Math.random() * 0.0003;
                p.hue = 200 + Math.random() * 60;
                p.size = 2 + Math.random() * 3;
            }
            ctx.globalAlpha = p.alpha * 0.55;
            ctx.fillStyle = `hsla(${p.hue},50%,70%,1)`;
            ctx.beginPath();
            ctx.arc(p.x * W, p.y * H, p.size, 0, Math.PI * 2);
            ctx.fill();
        });
        ctx.restore();
    }
    return { draw };
})();

// 11. SYNTAX_TREE — branching grammatical structure in speech cortex
const SYNTAX_TREE = (() => {
    let _last = 0;
    const INTERVAL = 45;
    let t = 0;
    function drawBranch(x, y, angle, depth, len, ts) {
        if (depth <= 0) return;
        const ex = x + Math.cos(angle) * len;
        const ey = y + Math.sin(angle) * len;
        const a = (depth / 5) * (0.4 + 0.2 * Math.sin(ts * 2 + depth));
        ctx.globalAlpha = a * 0.6;
        ctx.strokeStyle = `rgba(200,255,180,0.7)`;
        ctx.lineWidth = depth * 0.5;
        ctx.beginPath(); ctx.moveTo(x, y); ctx.lineTo(ex, ey); ctx.stroke();
        const spread = 0.35 + 0.1 * Math.sin(ts + depth);
        drawBranch(ex, ey, angle - spread, depth-1, len*0.72, ts);
        drawBranch(ex, ey, angle + spread, depth-1, len*0.72, ts);
    }
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        const dt = ts - _last; _last = ts;
        t += dt * 0.0006;
        const cx = canvas.width * 0.38, cy = canvas.height * 0.32;
        ctx.save();
        drawBranch(cx, cy + 20, -Math.PI/2, 5, 18 + Math.sin(t)*3, t);
        ctx.restore();
    }
    return { draw };
})();

// 12. PHONEME_BURST — sound wave rings from throat/mouth area
const PHONEME_BURST = (() => {
    let _last = 0;
    const INTERVAL = 25;
    const rings = [];
    let nextBurst = 0;
    let t = 0;
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        const dt = ts - _last; _last = ts;
        t += dt * 0.001;
        const cx = canvas.width * 0.5, cy = canvas.height * 0.08;
        if (ts > nextBurst) {
            rings.push({ r: 4, alpha: 0.7, speed: 0.08 + Math.random() * 0.06 });
            nextBurst = ts + 400 + Math.random() * 600;
        }
        ctx.save();
        for (let i = rings.length - 1; i >= 0; i--) {
            const ring = rings[i];
            ring.r += ring.speed * dt * 0.1;
            ring.alpha *= 0.985;
            if (ring.alpha < 0.01) { rings.splice(i, 1); continue; }
            ctx.globalAlpha = ring.alpha * 0.5;
            ctx.strokeStyle = `rgba(255,220,180,0.8)`;
            ctx.lineWidth = 1.2;
            ctx.beginPath();
            ctx.ellipse(cx, cy, ring.r * 1.6, ring.r * 0.8, 0, 0, Math.PI * 2);
            ctx.stroke();
        }
        ctx.restore();
    }
    return { draw };
})();

// 13. READING_FLOW — left-to-right scan line moving across invisible text
const READING_FLOW = (() => {
    let _last = 0;
    const INTERVAL = 20;
    let t = 0;
    const lines = 5;
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        const dt = ts - _last; _last = ts;
        t += dt * 0.0008;
        const W = canvas.width, H = canvas.height;
        const baseX = W * 0.15, baseY = H * 0.6;
        const lineH = 14, lineW = W * 0.7;
        ctx.save();
        // faint text placeholder lines
        for (let i = 0; i < lines; i++) {
            ctx.globalAlpha = 0.06;
            ctx.fillStyle = 'rgba(200,220,255,0.8)';
            ctx.fillRect(baseX, baseY + i * lineH, lineW * (0.6 + Math.random() * 0.35), 2);
        }
        // scan cursor
        const cycle = (t % (Math.PI * 2)) / (Math.PI * 2);
        const lineIdx = Math.floor(cycle * lines);
        const linePos = (cycle * lines) % 1;
        const scanX = baseX + linePos * lineW;
        const scanY = baseY + lineIdx * lineH;
        ctx.globalAlpha = 0.55;
        const grad = ctx.createLinearGradient(scanX - 20, 0, scanX + 4, 0);
        grad.addColorStop(0, 'rgba(120,200,255,0)');
        grad.addColorStop(1, 'rgba(180,230,255,0.8)');
        ctx.fillStyle = grad;
        ctx.fillRect(scanX - 20, scanY - 2, 24, 6);
        ctx.fillStyle = 'rgba(220,245,255,0.9)';
        ctx.fillRect(scanX, scanY - 2, 2, 6);
        ctx.restore();
    }
    return { draw };
})();

// 14. INNER_VOICE — subtle lip movement visualization
const INNER_VOICE = (() => {
    let _last = 0;
    const INTERVAL = 30;
    let t = 0;
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        const dt = ts - _last; _last = ts;
        t += dt * 0.002;
        const cx = canvas.width * 0.5, cy = canvas.height * 0.055;
        // mouth center (below nose area in head position)
        const my = cy + 14;
        const openness = Math.abs(Math.sin(t * 3.1) * Math.sin(t * 1.7)) * 4;
        ctx.save();
        ctx.globalAlpha = 0.35;
        ctx.strokeStyle = 'rgba(255,180,160,0.7)';
        ctx.lineWidth = 1.2;
        // upper lip
        ctx.beginPath();
        ctx.moveTo(cx - 8, my);
        ctx.quadraticCurveTo(cx, my - 2, cx + 8, my);
        ctx.stroke();
        // lower lip
        ctx.beginPath();
        ctx.moveTo(cx - 8, my);
        ctx.quadraticCurveTo(cx, my + 3 + openness, cx + 8, my);
        ctx.stroke();
        // breath particle
        if (openness > 2.5) {
            ctx.globalAlpha = 0.2;
            ctx.fillStyle = 'rgba(255,230,220,0.6)';
            ctx.beginPath();
            ctx.arc(cx + (Math.random()-0.5)*4, my - 6 - Math.random()*4, 1.5, 0, Math.PI*2);
            ctx.fill();
        }
        ctx.restore();
    }
    return { draw };
})();

// 15. TRANSLATION — same concept in multiple symbol systems
const TRANSLATION = (() => {
    let _last = 0;
    const INTERVAL = 60;
    let t = 0;
    const concepts = [
        {label: '愛', hue: 340},
        {label: 'ܚܘܒܐ', hue: 60},
        {label: 'LOVE', hue: 200},
        {label: 'حب', hue: 120},
        {label: 'प्रेम', hue: 280}
    ];
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        const dt = ts - _last; _last = ts;
        t += dt * 0.0006;
        const cx = canvas.width * 0.25, cy = canvas.height * 0.45;
        ctx.save();
        concepts.forEach((c, i) => {
            const angle = t * 0.5 + i * (Math.PI * 2 / concepts.length);
            const r = 28;
            const x = cx + Math.cos(angle) * r;
            const y = cy + Math.sin(angle) * r;
            const alpha = 0.3 + 0.25 * Math.sin(t * 1.2 + i);
            ctx.globalAlpha = alpha;
            ctx.fillStyle = `hsla(${c.hue},70%,70%,1)`;
            ctx.font = `${8 + Math.sin(t + i) * 1.5}px serif`;
            ctx.textAlign = 'center';
            ctx.fillText(c.label, x, y);
        });
        ctx.restore();
    }
    return { draw };
})();

// 16. PROPRIOCEPTION — ghost limb outlines aware of their position
PROPRIOCEPTION = (() => {
    let _last = 0;
    const INTERVAL = 40;
    let t = 0;
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        const dt = ts - _last; _last = ts;
        t += dt * 0.0008;
        const W = canvas.width, H = canvas.height;
        const cx = W * 0.5, cy = H * 0.5;
        ctx.save();
        ctx.globalAlpha = 0.2;
        ctx.strokeStyle = 'rgba(180,255,200,0.5)';
        ctx.lineWidth = 1;
        ctx.setLineDash([2, 3]);
        // arms with gentle sway
        const armSwing = Math.sin(t * 1.2) * 0.08;
        // left arm
        ctx.save();
        ctx.translate(cx - H*0.065, cy - H*0.2);
        ctx.rotate(armSwing);
        ctx.beginPath(); ctx.moveTo(0,0); ctx.lineTo(-H*0.06, H*0.14); ctx.stroke();
        ctx.restore();
        // right arm
        ctx.save();
        ctx.translate(cx + H*0.065, cy - H*0.2);
        ctx.rotate(-armSwing);
        ctx.beginPath(); ctx.moveTo(0,0); ctx.lineTo(H*0.06, H*0.14); ctx.stroke();
        ctx.restore();
        // feet/legs position awareness dots
        const legPhase = Math.sin(t * 0.8) * 0.04;
        ctx.globalAlpha = 0.3;
        ctx.fillStyle = 'rgba(200,255,200,0.6)';
        ctx.beginPath(); ctx.arc(cx - H*0.045, cy + H*0.18, 4, 0, Math.PI*2); ctx.fill();
        ctx.beginPath(); ctx.arc(cx + H*0.045, cy + H*0.18 + legPhase*H, 4, 0, Math.PI*2); ctx.fill();
        ctx.restore();
    }
    return { draw };
})();

// 17. HEARTBEAT_DRUM — rhythm, 72 BPM, never stops
const HEARTBEAT_DRUM = (() => {
    let _last = 0;
    const INTERVAL = 16;
    const BPM = 72;
    const BEAT_MS = 60000 / BPM;
    let phase = 0;
    let beatPulse = 0;
    let lastBeat = 0;
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        const dt = ts - _last; _last = ts;
        phase = (ts % (BEAT_MS * 2)) / (BEAT_MS * 2);
        if (ts - lastBeat >= BEAT_MS) { lastBeat = ts; beatPulse = 1; }
        beatPulse *= 0.88;
        const cx = canvas.width * 0.5, cy = canvas.height * 0.38;
        // ECG-style waveform
        ctx.save();
        ctx.globalAlpha = 0.45 + beatPulse * 0.3;
        ctx.strokeStyle = `rgba(255,80,80,${0.6 + beatPulse * 0.3})`;
        ctx.lineWidth = 1.5;
        ctx.shadowColor = 'rgba(255,60,60,0.5)';
        ctx.shadowBlur = 6 * beatPulse;
        const W = 70, baseY = cy;
        ctx.beginPath();
        const steps = 80;
        for (let i = 0; i <= steps; i++) {
            const x = cx - W/2 + (i / steps) * W;
            const p = (i / steps + phase) % 1;
            let y = baseY;
            if (p > 0.38 && p < 0.42) y = baseY - 22 * Math.sin((p - 0.38) / 0.04 * Math.PI);
            else if (p > 0.42 && p < 0.48) y = baseY + 8 * Math.sin((p-0.42)/0.06*Math.PI);
            else if (p > 0.48 && p < 0.56) y = baseY - 28 * Math.sin((p-0.48)/0.08*Math.PI);
            else if (p > 0.56 && p < 0.62) y = baseY + 5 * Math.sin((p-0.56)/0.06*Math.PI);
            i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
        }
        ctx.stroke();
        ctx.restore();
    }
    return { draw };
})();

// 18. NERVE_SIGNAL — electrical impulse racing fingertip to brain
const NERVE_SIGNAL = (() => {
    let _last = 0;
    const INTERVAL = 20;
    let t = 0;
    let signals = [];
    let nextSignal = 0;
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        const dt = ts - _last; _last = ts;
        t += dt * 0.001;
        const W = canvas.width, H = canvas.height;
        if (ts > nextSignal) {
            signals.push({ progress: 0, speed: 0.0008 + Math.random() * 0.0005 });
            nextSignal = ts + 1500 + Math.random() * 2000;
        }
        // path: fingertip (bottom right) → shoulder → brain (top center)
        const path = [
            [W*0.72, H*0.85],
            [W*0.65, H*0.65],
            [W*0.58, H*0.45],
            [W*0.52, H*0.22],
            [W*0.5,  H*0.1]
        ];
        ctx.save();
        // draw nerve path faintly
        ctx.globalAlpha = 0.08;
        ctx.strokeStyle = 'rgba(180,255,200,0.5)';
        ctx.lineWidth = 1;
        ctx.beginPath();
        path.forEach(([x,y],i) => i===0 ? ctx.moveTo(x,y) : ctx.lineTo(x,y));
        ctx.stroke();
        // draw moving impulse
        for (let i = signals.length-1; i >= 0; i--) {
            const s = signals[i];
            s.progress += s.speed * dt;
            if (s.progress >= 1) { signals.splice(i,1); continue; }
            const idx = Math.min(Math.floor(s.progress * (path.length-1)), path.length-2);
            const t2 = (s.progress * (path.length-1)) % 1;
            const [ax,ay] = path[idx];
            const [bx,by] = path[idx+1];
            const x = ax + (bx-ax)*t2, y = ay + (by-ay)*t2;
            ctx.globalAlpha = 0.8;
            ctx.shadowColor = 'rgba(100,255,180,0.8)';
            ctx.shadowBlur = 8;
            ctx.fillStyle = 'rgba(160,255,200,0.9)';
            ctx.beginPath(); ctx.arc(x, y, 3.5, 0, Math.PI*2); ctx.fill();
        }
        ctx.restore();
    }
    return { draw };
})();

// 19. MUSCLE_MEMORY — repeated micro-movements, hands knowing what to do
const MUSCLE_MEMORY = (() => {
    let _last = 0;
    const INTERVAL = 30;
    let t = 0;
    const traces = Array.from({length:6}, (_, i) => ({
        phase: i * (Math.PI * 2 / 6),
        decay: 0.92,
        alpha: 0
    }));
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        const dt = ts - _last; _last = ts;
        t += dt * 0.0012;
        const cx = canvas.width * 0.5, cy = canvas.height * 0.7;
        // simulate a repeated gesture pattern
        const pattern = [
            [0, 0], [8, -5], [12, -12], [8, -18], [0, -20],
            [-8, -18], [-12, -12], [-8, -5], [0, 0]
        ];
        ctx.save();
        traces.forEach((tr, i) => {
            const progress = (t * 0.8 + tr.phase) % (Math.PI * 2);
            const alpha = 0.08 + 0.12 * Math.sin(progress);
            ctx.globalAlpha = alpha;
            ctx.strokeStyle = 'rgba(255,230,180,0.6)';
            ctx.lineWidth = 1;
            ctx.beginPath();
            pattern.forEach(([px,py], pi) => {
                const scale = 1 + i * 0.15;
                const rx = cx + px * scale + Math.sin(progress + i) * 2;
                const ry = cy + py * scale + Math.cos(progress * 0.7 + i) * 2;
                pi === 0 ? ctx.moveTo(rx,ry) : ctx.lineTo(rx,ry);
            });
            ctx.stroke();
        });
        ctx.restore();
    }
    return { draw };
})();

// 20. PAIN_MAP — heat spots at stress locations, cooling slowly
const PAIN_MAP = (() => {
    let _last = 0;
    const INTERVAL = 50;
    let t = 0;
    const spots = [
        {x: 0.5,  y: 0.38, intensity: 0.6, hue: 0},   // chest
        {x: 0.42, y: 0.55, intensity: 0.3, hue: 15},   // lower back left
        {x: 0.5,  y: 0.15, intensity: 0.4, hue: 5},    // head/neck
        {x: 0.65, y: 0.6,  intensity: 0.2, hue: 20}    // knee
    ];
    function draw(ts) {
        if (ts - _last < INTERVAL) return;
        const dt = ts - _last; _last = ts;
        t += dt * 0.0004;
        const W = canvas.width, H = canvas.height;
        ctx.save();
        spots.forEach((s, i) => {
            s.intensity -= 0.00005 * dt;
            if (s.intensity < 0.1) s.intensity = 0.1 + Math.random() * 0.4;
            const pulse = s.intensity * (0.7 + 0.3 * Math.sin(t * 2 + i));
            const r = 20 + pulse * 15;
            const cx = s.x * W, cy = s.y * H;
            const grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, r);
            grad.addColorStop(0, `hsla(${s.hue},100%,60%,${pulse * 0.45})`);
            grad.addColorStop(0.5, `hsla(${s.hue + 10},80%,50%,${pulse * 0.2})`);
            grad.addColorStop(1, 'rgba(255,50,0,0)');
            ctx.fillStyle = grad;
            ctx.beginPath(); ctx.arc(cx, cy, r, 0, Math.PI*2); ctx.fill();
        });
        ctx.restore();
    }
    return { draw };
})();

