// ═══════════════════════════════════════════════════════════════════════════
// DORSAL BRAIN ENGINE — setup, coordinate helpers, region registry
// ═══════════════════════════════════════════════════════════════════════════
(function() {
  const dCvs = document.getElementById('brainDorsalCanvas');
  const dCtx = dCvs.getContext('2d');

  // Resize to match SVG actual rendered size — NO devicePixelRatio scaling
  // (DPR scaling causes size mismatch when wrapper CSS transform is applied)
  function resizeDB() {
    const svg = document.getElementById('brainSvg');
    const wrapper = document.getElementById('brainWrapper');
    const r = svg ? svg.getBoundingClientRect() : wrapper.getBoundingClientRect();
    const wr = wrapper.getBoundingClientRect();
    dCvs.width = r.width;
    dCvs.height = r.height;
    dCvs.style.width = r.width + 'px';
    dCvs.style.height = r.height + 'px';
    dCvs.style.left = (r.left - wr.left) + 'px';
    dCvs.style.top = (r.top - wr.top) + 'px';
  }
  resizeDB();
  window.addEventListener('resize', resizeDB);

  // Convert SVG coords (0–700 wide, 0–1400 tall) → dorsal canvas pixel coords
  // Brain occupies roughly y:58–455 in SVG, centered at x:350
  function svgToDorsal(sx, sy) {
    const scaleX = dCvs.width / 700;
    const scaleY = dCvs.height / 1400;
    return { x: sx * scaleX, y: sy * scaleY };
  }

  // Center of the brain in dorsal canvas pixels
  function brainCenter() {
    const p = svgToDorsal(350, 257);
    return p;
  }

  // Scale factor — how big the brain should be relative to canvas
  function brainScale() {
    return dCvs.width / 700;
  }

  // Expose helpers
  window.DORSAL = {
    cvs: dCvs, ctx: dCtx,
    svgToDorsal, brainCenter, brainScale, resizeDB
  };
})();

// ═══════════════════════════════════════════════════════════════════════════
// BRAIN_OUTLINE — anatomically shaped dorsal brain silhouette
// Two hemispheres, longitudinal fissure, sulci grooves
// ═══════════════════════════════════════════════════════════════════════════
window.BRAIN_OUTLINE = (function() {
  let phase = 0;

  function drawHemisphere(ctx, cx, cy, sc, side, t) {
    // side: -1 = left, +1 = right
    const s = side;
    ctx.save();
    ctx.translate(cx, cy);
    ctx.scale(sc, sc);

    // Main hemisphere outline — kidney bean shape
    ctx.beginPath();
    if (s < 0) {
      // Left hemisphere
      ctx.moveTo(0, -195);
      ctx.bezierCurveTo(-8, -202, -35, -205, -60, -195);
      ctx.bezierCurveTo(-105, -178, -135, -148, -148, -110);
      ctx.bezierCurveTo(-162, -68, -158, -18, -152, 25);
      ctx.bezierCurveTo(-148, 60, -145, 95, -138, 120);
      ctx.bezierCurveTo(-128, 152, -108, 168, -80, 175);
      ctx.bezierCurveTo(-52, 182, -20, 178, 0, 170);
      ctx.closePath();
    } else {
      // Right hemisphere
      ctx.moveTo(0, -195);
      ctx.bezierCurveTo(8, -202, 35, -205, 60, -195);
      ctx.bezierCurveTo(105, -178, 135, -148, 148, -110);
      ctx.bezierCurveTo(162, -68, 158, -18, 152, 25);
      ctx.bezierCurveTo(148, 60, 145, 95, 138, 120);
      ctx.bezierCurveTo(128, 152, 108, 168, 80, 175);
      ctx.bezierCurveTo(52, 182, 20, 178, 0, 170);
      ctx.closePath();
    }

    // Cortex fill — subtle grey matter base
    const pulse = 0.03 + 0.01 * Math.sin(t * 0.0008 + (s < 0 ? 0 : Math.PI * 0.3));
    ctx.fillStyle = `rgba(40, 55, 90, ${pulse + 0.06})`;
    ctx.fill();

    // Outline
    ctx.strokeStyle = `rgba(80, 110, 170, ${0.18 + 0.06 * Math.sin(t * 0.001)})`;
    ctx.lineWidth = 1.5 / sc;
    ctx.stroke();

    ctx.restore();
  }

  function drawSulci(ctx, cx, cy, sc, t) {
    ctx.save();
    ctx.translate(cx, cy);
    ctx.scale(sc, sc);
    ctx.strokeStyle = `rgba(30, 45, 80, ${0.35 + 0.05 * Math.sin(t * 0.0009)})`;
    ctx.lineWidth = 1.2 / sc;
    ctx.lineCap = 'round';

    // Central sulcus — main divider front/back
    ctx.beginPath(); ctx.moveTo(-5, -160); ctx.bezierCurveTo(-18, -120, -22, -60, -20, -10); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(5, -160); ctx.bezierCurveTo(18, -120, 22, -60, 20, -10); ctx.stroke();

    // Lateral sulcus (Sylvian fissure) — left
    ctx.beginPath(); ctx.moveTo(-35, -50); ctx.bezierCurveTo(-65, -35, -105, -20, -125, 15); ctx.stroke();
    // right
    ctx.beginPath(); ctx.moveTo(35, -50); ctx.bezierCurveTo(65, -35, 105, -20, 125, 15); ctx.stroke();

    // Superior frontal sulcus — left
    ctx.beginPath(); ctx.moveTo(-15, -185); ctx.bezierCurveTo(-40, -178, -75, -165, -90, -140); ctx.stroke();
    // right
    ctx.beginPath(); ctx.moveTo(15, -185); ctx.bezierCurveTo(40, -178, 75, -165, 90, -140); ctx.stroke();

    // Intraparietal sulcus — left
    ctx.beginPath(); ctx.moveTo(-18, -10); ctx.bezierCurveTo(-45, 5, -80, 20, -100, 50); ctx.stroke();
    // right
    ctx.beginPath(); ctx.moveTo(18, -10); ctx.bezierCurveTo(45, 5, 80, 20, 100, 50); ctx.stroke();

    // Post-central sulcus — left
    ctx.beginPath(); ctx.moveTo(-20, -5); ctx.bezierCurveTo(-35, 15, -40, 40, -38, 65); ctx.stroke();
    // right
    ctx.beginPath(); ctx.moveTo(20, -5); ctx.bezierCurveTo(35, 15, 40, 40, 38, 65); ctx.stroke();

    // Superior temporal sulcus — left
    ctx.beginPath(); ctx.moveTo(-45, -40); ctx.bezierCurveTo(-72, -20, -110, 5, -128, 40); ctx.stroke();
    // right
    ctx.beginPath(); ctx.moveTo(45, -40); ctx.bezierCurveTo(72, -20, 110, 5, 128, 40); ctx.stroke();

    // Calcarine sulcus (occipital) — bilateral
    ctx.beginPath(); ctx.moveTo(-20, 130); ctx.bezierCurveTo(-40, 140, -55, 155, -50, 168); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(20, 130); ctx.bezierCurveTo(40, 140, 55, 155, 50, 168); ctx.stroke();

    // Parieto-occipital sulcus — bilateral
    ctx.beginPath(); ctx.moveTo(-30, 80); ctx.bezierCurveTo(-50, 100, -60, 120, -55, 145); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(30, 80); ctx.bezierCurveTo(50, 100, 60, 120, 55, 145); ctx.stroke();

    ctx.restore();
  }

  function draw(t) {
    const { ctx, cvs, brainCenter, brainScale } = window.DORSAL;
    const c = brainCenter();
    const sc = brainScale();
    ctx.save();
    drawHemisphere(ctx, c.x, c.y, sc, -1, t);
    drawHemisphere(ctx, c.x, c.y, sc, 1, t);
    drawSulci(ctx, c.x, c.y, sc, t);
    ctx.restore();
  }

  return { draw };
})();

// ═══════════════════════════════════════════════════════════════════════════
// HEMISPHERIC_DIVIDE — longitudinal fissure down the center
// ═══════════════════════════════════════════════════════════════════════════
window.HEMISPHERIC_DIVIDE = (function() {
  function draw(t) {
    const { ctx, cvs, brainCenter, brainScale } = window.DORSAL;
    const c = brainCenter();
    const sc = brainScale();
    ctx.save();
    ctx.translate(c.x, c.y);
    ctx.scale(sc, sc);

    const alpha = 0.22 + 0.06 * Math.sin(t * 0.0007);
    ctx.strokeStyle = `rgba(60, 90, 150, ${alpha})`;
    ctx.lineWidth = 1.8 / sc;
    ctx.setLineDash([4 / sc, 3 / sc]);
    ctx.lineDashOffset = (t * 0.02) % 7;
    ctx.beginPath();
    ctx.moveTo(0, -198);
    ctx.bezierCurveTo(-2, -100, -1, 50, 0, 170);
    ctx.stroke();
    ctx.setLineDash([]);
    ctx.restore();
  }
  return { draw };
})();

// ═══════════════════════════════════════════════════════════════════════════
// FRONTAL_LOBE — decision making, personality, planning — BLUE-WHITE glow
// ═══════════════════════════════════════════════════════════════════════════
window.FRONTAL_LOBE = (function() {
  let _phase = Math.random() * Math.PI * 2;

  function draw(t) {
    const { ctx, cvs, brainCenter, brainScale } = window.DORSAL;
    const c = brainCenter();
    const sc = brainScale();
    ctx.save();
    ctx.translate(c.x, c.y);
    ctx.scale(sc, sc);

    const pulse = 0.5 + 0.5 * Math.sin(t * 0.00065 + _phase);
    const alpha = 0.22 + 0.18 * pulse;

    // Left frontal
    ctx.beginPath();
    ctx.moveTo(0, -195);
    ctx.bezierCurveTo(-8, -200, -35, -203, -60, -192);
    ctx.bezierCurveTo(-100, -175, -130, -145, -145, -108);
    ctx.bezierCurveTo(-150, -80, -148, -50, -142, -18);
    ctx.bezierCurveTo(-88, -25, -45, -28, -20, -10);
    ctx.bezierCurveTo(-10, -70, -5, -140, 0, -195);
    ctx.closePath();
    const gradL = ctx.createRadialGradient(-65, -120, 5 * sc, -65, -120, 80 * sc);
    gradL.addColorStop(0, `rgba(130, 180, 255, ${alpha * 0.9})`);
    gradL.addColorStop(0.5, `rgba(100, 160, 255, ${alpha * 0.55})`);
    gradL.addColorStop(1, `rgba(80, 130, 220, 0)`);
    ctx.fillStyle = gradL;
    ctx.fill();

    // Right frontal
    ctx.beginPath();
    ctx.moveTo(0, -195);
    ctx.bezierCurveTo(8, -200, 35, -203, 60, -192);
    ctx.bezierCurveTo(100, -175, 130, -145, 145, -108);
    ctx.bezierCurveTo(150, -80, 148, -50, 142, -18);
    ctx.bezierCurveTo(88, -25, 45, -28, 20, -10);
    ctx.bezierCurveTo(10, -70, 5, -140, 0, -195);
    ctx.closePath();
    const gradR = ctx.createRadialGradient(65, -120, 5 * sc, 65, -120, 80 * sc);
    gradR.addColorStop(0, `rgba(130, 180, 255, ${alpha * 0.9})`);
    gradR.addColorStop(0.5, `rgba(100, 160, 255, ${alpha * 0.55})`);
    gradR.addColorStop(1, `rgba(80, 130, 220, 0)`);
    ctx.fillStyle = gradR;
    ctx.fill();

    // Subtle label glow
    ctx.fillStyle = `rgba(160, 200, 255, ${0.06 + 0.04 * pulse})`;
    ctx.beginPath(); ctx.arc(0, -155, 25 / sc, 0, Math.PI * 2); ctx.fill();

    ctx.restore();
  }
  return { draw };
})();

// ═══════════════════════════════════════════════════════════════════════════
// PARIETAL_LOBE — sensory integration, spatial awareness — CYAN rippling
// ═══════════════════════════════════════════════════════════════════════════
window.PARIETAL_LOBE = (function() {
  let _phase = Math.random() * Math.PI * 2;
  let _ripple = 0;

  function draw(t) {
    const { ctx, brainCenter, brainScale } = window.DORSAL;
    const c = brainCenter();
    const sc = brainScale();
    ctx.save();
    ctx.translate(c.x, c.y);
    ctx.scale(sc, sc);

    _ripple = t * 0.0012 + _phase;
    const pulse = 0.5 + 0.5 * Math.sin(_ripple);
    const alpha = 0.18 + 0.14 * pulse;

    // Left parietal (posterior to central sulcus, anterior to occipital)
    ctx.beginPath();
    ctx.moveTo(-20, -10);
    ctx.bezierCurveTo(-45, 5, -80, 20, -100, 50);
    ctx.bezierCurveTo(-115, 75, -118, 105, -110, 125);
    ctx.bezierCurveTo(-90, 135, -55, 140, -30, 135);
    ctx.bezierCurveTo(-15, 130, -5, 120, 0, 105);
    ctx.bezierCurveTo(-5, 70, -12, 30, -20, -10);
    ctx.closePath();
    const gL = ctx.createRadialGradient(-60, 55, 5 * sc, -60, 55, 70 * sc);
    gL.addColorStop(0, `rgba(0, 220, 200, ${alpha * 0.9})`);
    gL.addColorStop(0.5, `rgba(0, 200, 180, ${alpha * 0.55})`);
    gL.addColorStop(1, `rgba(0, 180, 160, 0)`);
    ctx.fillStyle = gL;
    ctx.fill();

    // Right parietal
    ctx.beginPath();
    ctx.moveTo(20, -10);
    ctx.bezierCurveTo(45, 5, 80, 20, 100, 50);
    ctx.bezierCurveTo(115, 75, 118, 105, 110, 125);
    ctx.bezierCurveTo(90, 135, 55, 140, 30, 135);
    ctx.bezierCurveTo(15, 130, 5, 120, 0, 105);
    ctx.bezierCurveTo(5, 70, 12, 30, 20, -10);
    ctx.closePath();
    const gR = ctx.createRadialGradient(60, 55, 5 * sc, 60, 55, 70 * sc);
    gR.addColorStop(0, `rgba(0, 220, 200, ${alpha * 0.9})`);
    gR.addColorStop(0.5, `rgba(0, 200, 180, ${alpha * 0.55})`);
    gR.addColorStop(1, `rgba(0, 180, 160, 0)`);
    ctx.fillStyle = gR;
    ctx.fill();

    // Ripple rings
    for (let i = 0; i < 3; i++) {
      const rPhase = (_ripple + i * 1.0) % (Math.PI * 2);
      const rAlpha = Math.sin(rPhase) * 0.12;
      if (rAlpha > 0) {
        const rR = 30 + i * 15;
        ctx.strokeStyle = `rgba(0, 230, 210, ${rAlpha})`;
        ctx.lineWidth = 0.8 / sc;
        ctx.beginPath(); ctx.arc(-55, 58, rR, 0, Math.PI * 2); ctx.stroke();
        ctx.beginPath(); ctx.arc(55, 58, rR, 0, Math.PI * 2); ctx.stroke();
      }
    }

    ctx.restore();
  }
  return { draw };
})();

// ═══════════════════════════════════════════════════════════════════════════
// TEMPORAL_LOBE_L + TEMPORAL_LOBE_R — language, memory, emotion — AMBER flicker
// ═══════════════════════════════════════════════════════════════════════════
