// ═══════════════════════════════════════════════════════════════════════════
// OCCIPITAL_LOBE — vision processing — VIOLET rapid firing
// ═══════════════════════════════════════════════════════════════════════════
window.OCCIPITAL_LOBE = (function() {
  let _firePhase = 0;
  let _nextFire = 600;
  function draw(t) {
    const { ctx, brainCenter, brainScale } = window.DORSAL;
    const c = brainCenter();
    const sc = brainScale();
    ctx.save();
    ctx.translate(c.x, c.y);
    ctx.scale(sc, sc);

    const fast = 0.5 + 0.5 * Math.sin(t * 0.0035);
    const alpha = 0.2 + 0.2 * fast;

    ctx.beginPath();
    ctx.moveTo(0, 105);
    ctx.bezierCurveTo(-15, 112, -35, 125, -50, 140);
    ctx.bezierCurveTo(-65, 155, -60, 168, -45, 174);
    ctx.bezierCurveTo(-25, 180, 0, 178, 25, 174);
    ctx.bezierCurveTo(48, 168, 65, 155, 50, 140);
    ctx.bezierCurveTo(35, 125, 15, 112, 0, 105);
    ctx.closePath();
    const g = ctx.createRadialGradient(0, 148, 3 * sc, 0, 148, 55 * sc);
    g.addColorStop(0, `rgba(200, 120, 255, ${alpha + 0.15})`);
    g.addColorStop(0.4, `rgba(170, 90, 240, ${alpha * 0.75})`);
    g.addColorStop(1, `rgba(140, 60, 210, 0)`);
    ctx.fillStyle = g;
    ctx.fill();

    // Rapid visual cortex firing sparks
    if (t > _nextFire) {
      _firePhase = t;
      _nextFire = t + 280 + Math.random() * 400;
    }
    const age = t - _firePhase;
    if (age < 350) {
      const n = 5;
      for (let i = 0; i < n; i++) {
        const ang = (i / n) * Math.PI * 2 + age * 0.01;
        const r = 12 + 22 * (age / 350);
        const px = Math.cos(ang) * r;
        const py = 148 + Math.sin(ang) * r * 0.5;
        const fa = (1 - age / 350) * 0.6;
        ctx.fillStyle = `rgba(220, 160, 255, ${fa})`;
        ctx.beginPath(); ctx.arc(px, py, 1.5, 0, Math.PI * 2); ctx.fill();
      }
    }

    ctx.restore();
  }
  return { draw };
})();

// ═══════════════════════════════════════════════════════════════════════════
// PREFRONTAL_FOCUS — spotlight on PFC during "thinking" — brighter blue-white
// ═══════════════════════════════════════════════════════════════════════════
window.PREFRONTAL_FOCUS = (function() {
  let _state = 0;
  let _nextTrigger = 3000 + Math.random() * 5000;
  let _activeUntil = 0;

  function draw(t) {
    const { ctx, brainCenter, brainScale } = window.DORSAL;
    const c = brainCenter();
    const sc = brainScale();

    if (t > _nextTrigger) {
      _activeUntil = t + 1800 + Math.random() * 2200;
      _nextTrigger = _activeUntil + 4000 + Math.random() * 6000;
    }

    if (t < _activeUntil) {
      const age = (_activeUntil - t) / 1800;
      const alpha = Math.min(1, age) * (0.12 + 0.1 * Math.sin(t * 0.003));
      ctx.save();
      ctx.translate(c.x, c.y);
      ctx.scale(sc, sc);
      const g = ctx.createRadialGradient(0, -175, 2, 0, -175, 65);
      g.addColorStop(0, `rgba(200, 230, 255, ${alpha + 0.08})`);
      g.addColorStop(0.4, `rgba(150, 200, 255, ${alpha * 0.7})`);
      g.addColorStop(1, `rgba(100, 160, 255, 0)`);
      ctx.fillStyle = g;
      ctx.beginPath(); ctx.arc(0, -165, 62, 0, Math.PI * 2); ctx.fill();
      ctx.restore();
    }
  }
  return { draw };
})();

// ═══════════════════════════════════════════════════════════════════════════
// CORPUS_CALLOSUM — white data stream connecting hemispheres
// ═══════════════════════════════════════════════════════════════════════════
window.CORPUS_CALLOSUM = (function() {
  let _packets = [];
  let _lastSpawn = 0;

  function spawnPacket(t) {
    const dir = Math.random() > 0.5 ? 1 : -1;
    _packets.push({ start: t, dir, yOff: (Math.random() - 0.5) * 18 });
  }

  function draw(t) {
    const { ctx, brainCenter, brainScale } = window.DORSAL;
    const c = brainCenter();
    const sc = brainScale();
    ctx.save();
    ctx.translate(c.x, c.y);
    ctx.scale(sc, sc);

    // Draw the corpus callosum band
    const alpha = 0.22 + 0.08 * Math.sin(t * 0.0011);
    ctx.strokeStyle = `rgba(220, 235, 255, ${alpha})`;
    ctx.lineWidth = 6 / sc;
    ctx.lineCap = 'round';
    ctx.beginPath();
    ctx.moveTo(-70, 22);
    ctx.bezierCurveTo(-40, 12, 40, 12, 70, 22);
    ctx.stroke();

    ctx.lineWidth = 3 / sc;
    ctx.strokeStyle = `rgba(255, 255, 255, ${alpha * 0.7})`;
    ctx.beginPath();
    ctx.moveTo(-65, 18);
    ctx.bezierCurveTo(-38, 8, 38, 8, 65, 18);
    ctx.stroke();

    // Spawn data packets
    if (t - _lastSpawn > 180 + Math.random() * 220) {
      spawnPacket(t);
      _lastSpawn = t;
    }

    // Draw packets flowing L↔R
    _packets = _packets.filter(p => t - p.start < 900);
    _packets.forEach(p => {
      const prog = (t - p.start) / 900;
      const x = p.dir * (-70 + 140 * prog);
      const y = 15 + p.yOff + Math.sin(prog * Math.PI) * -5;
      const alpha2 = Math.sin(prog * Math.PI) * 0.85;
      const g = ctx.createRadialGradient(x, y, 0, x, y, 5 / sc);
      g.addColorStop(0, `rgba(255, 255, 255, ${alpha2})`);
      g.addColorStop(1, `rgba(200, 220, 255, 0)`);
      ctx.fillStyle = g;
      ctx.beginPath(); ctx.arc(x, y, 3, 0, Math.PI * 2); ctx.fill();
    });

    ctx.restore();
  }
  return { draw };
})();

// ═══════════════════════════════════════════════════════════════════════════
// THALAMUS_GATE — sensory relay, consciousness gate — BRIGHT WHITE central pulse
// ═══════════════════════════════════════════════════════════════════════════
window.THALAMUS_GATE = (function() {
  let _pulsePhase = 0;

  function draw(t) {
    const { ctx, brainCenter, brainScale } = window.DORSAL;
    const c = brainCenter();
    const sc = brainScale();
    ctx.save();
    ctx.translate(c.x, c.y);
    ctx.scale(sc, sc);

    const pulse = 0.5 + 0.5 * Math.sin(t * 0.0025);
    const alpha = 0.55 + 0.35 * pulse;

    // Thalamus body — egg-shaped bilateral pair
    for (let s of [-1, 1]) {
      const tx = s * 14;
      const ty = 22;
      const g = ctx.createRadialGradient(tx, ty, 2, tx, ty, 18);
      g.addColorStop(0, `rgba(255, 255, 220, ${alpha})`);
      g.addColorStop(0.35, `rgba(240, 245, 200, ${alpha * 0.7})`);
      g.addColorStop(1, `rgba(200, 220, 180, 0)`);
      ctx.fillStyle = g;
      ctx.beginPath();
      ctx.ellipse(tx, ty, 15, 20, 0, 0, Math.PI * 2);
      ctx.fill();
    }

    // Pulse ring
    const ringR = 28 + 18 * pulse;
    const ringA = (1 - pulse) * 0.3;
    ctx.strokeStyle = `rgba(255, 255, 200, ${ringA})`;
    ctx.lineWidth = 1.5 / sc;
    ctx.beginPath(); ctx.arc(0, 22, ringR, 0, Math.PI * 2); ctx.stroke();

    ctx.restore();
  }
  return { draw };
})();

// ═══════════════════════════════════════════════════════════════════════════
// BASAL_GANGLIA — habit, reward, movement — PURPLE rings around thalamus
// ═══════════════════════════════════════════════════════════════════════════
window.BASAL_GANGLIA = (function() {
  function draw(t) {
    const { ctx, brainCenter, brainScale } = window.DORSAL;
    const c = brainCenter();
    const sc = brainScale();
    ctx.save();
    ctx.translate(c.x, c.y);
    ctx.scale(sc, sc);

    const spin = t * 0.0005;
    for (let ring = 0; ring < 3; ring++) {
      const r = 30 + ring * 12;
      const alpha = (0.12 + 0.08 * Math.sin(t * 0.0009 + ring * 1.2)) * (1 - ring * 0.2);
      ctx.strokeStyle = `rgba(190, 130, 255, ${alpha})`;
      ctx.lineWidth = (2.5 - ring * 0.5) / sc;
      ctx.beginPath();
      // Slightly offset ellipse for putamen/caudate shape
      ctx.ellipse(0, 22, r * 1.35, r, spin + ring * 0.5, 0, Math.PI * 2);
      ctx.stroke();
    }

    // Putamen highlights — bilateral
    for (let s of [-1, 1]) {
      const px = s * 38;
      const py = 28;
      const alpha = 0.18 + 0.12 * Math.sin(t * 0.0013 + s);
      const g = ctx.createRadialGradient(px, py, 0, px, py, 16);
      g.addColorStop(0, `rgba(180, 100, 255, ${alpha})`);
      g.addColorStop(1, `rgba(160, 80, 240, 0)`);
      ctx.fillStyle = g;
      ctx.beginPath(); ctx.ellipse(px, py, 13, 18, 0, 0, Math.PI * 2); ctx.fill();
    }

    ctx.restore();
  }
  return { draw };
})();

// ═══════════════════════════════════════════════════════════════════════════
// HIPPOCAMPUS_L + HIPPOCAMPUS_R — memory formation — TEAL seahorse wave
// ═══════════════════════════════════════════════════════════════════════════
window.HIPPOCAMPUS_L = (function() {
  let _wave = 0;
  function draw(t) {
    const { ctx, brainCenter, brainScale } = window.DORSAL;
    const c = brainCenter();
    const sc = brainScale();
    ctx.save();
    ctx.translate(c.x, c.y);
    ctx.scale(sc, sc);

    _wave = t * 0.0008;
    const pulse = 0.5 + 0.5 * Math.sin(_wave);
    const alpha = 0.45 + 0.3 * pulse;

    // Seahorse/curved shape — medial temporal lobe
    ctx.beginPath();
    ctx.moveTo(-40, 35);
    ctx.bezierCurveTo(-52, 45, -60, 58, -62, 72);
    ctx.bezierCurveTo(-64, 88, -58, 102, -48, 108);
    ctx.bezierCurveTo(-38, 114, -28, 110, -22, 100);
    ctx.bezierCurveTo(-16, 90, -16, 75, -22, 62);
    ctx.bezierCurveTo(-28, 50, -34, 40, -40, 35);
    ctx.closePath();
    const g = ctx.createRadialGradient(-42, 72, 2, -42, 72, 38);
    g.addColorStop(0, `rgba(0, 230, 190, ${alpha})`);
    g.addColorStop(0.5, `rgba(0, 210, 170, ${alpha * 0.65})`);
    g.addColorStop(1, `rgba(0, 190, 150, 0)`);
    ctx.fillStyle = g;
    ctx.fill();

    // Wave ripple
    const wAlpha = 0.25 * Math.sin(_wave * 2);
    if (wAlpha > 0) {
      ctx.strokeStyle = `rgba(0, 240, 200, ${wAlpha})`;
      ctx.lineWidth = 1 / sc;
      ctx.beginPath(); ctx.arc(-42, 72, 20 + 12 * pulse, 0, Math.PI * 2); ctx.stroke();
    }

    ctx.restore();
  }
  return { draw };
})();

